window.THE_CURE_PACK = {"characters": [{"id": "homes", "name": "Dr. Homes", "role": "Lead Attending Surgeon", "resources": [{"id": "04-dr-homes", "label": "Character dossier", "hint": "Private briefing: secrets, alibi, objectives"}, {"id": "performance-script", "label": "Player performance script", "hint": "Spoken lines and scenes: read only your current act"}, {"id": "actor-personas", "label": "Actor personas", "hint": "How to play your character big and fun"}]}, {"id": "pepper", "name": "Nurse Pepper", "role": "Head Nurse, VIP Wing", "resources": [{"id": "03-nurse-pepper", "label": "Character dossier", "hint": "Private briefing: secrets, alibi, objectives"}, {"id": "performance-script", "label": "Player performance script", "hint": "Spoken lines and scenes: read only your current act"}, {"id": "actor-personas", "label": "Actor personas", "hint": "How to play your character big and fun"}]}, {"id": "jetski", "name": "Dr. Jetski", "role": "Anesthesiologist", "resources": [{"id": "06-dr-jetski", "label": "Character dossier", "hint": "Private briefing: secrets, alibi, objectives"}, {"id": "performance-script", "label": "Player performance script", "hint": "Spoken lines and scenes: read only your current act"}, {"id": "actor-personas", "label": "Actor personas", "hint": "How to play your character big and fun"}]}, {"id": "ray", "name": "Officer Ray", "role": "Security Chief", "resources": [{"id": "02-officer-ray", "label": "Character dossier", "hint": "Private briefing: secrets, alibi, objectives"}, {"id": "performance-script", "label": "Player performance script", "hint": "Spoken lines and scenes: read only your current act"}, {"id": "actor-personas", "label": "Actor personas", "hint": "How to play your character big and fun"}, {"id": "storm-containment", "label": "Storm and containment FAQ", "hint": "Player facing answers: why no police, why you investigate"}]}, {"id": "marz", "name": "Officer Marlowe \"Marz\"", "role": "Junior Security", "resources": [{"id": "12-officer-marz", "label": "Character dossier", "hint": "Private briefing: secrets, alibi, objectives"}, {"id": "performance-script", "label": "Player performance script", "hint": "Spoken lines and scenes: read only your current act"}, {"id": "actor-personas", "label": "Actor personas", "hint": "How to play your character big and fun"}, {"id": "storm-containment", "label": "Storm and containment FAQ", "hint": "Player facing answers: why no police, why you investigate"}]}, {"id": "curie", "name": "Dr. Curie", "role": "Chief of Surgery", "resources": [{"id": "01-dr-curie", "label": "Character dossier", "hint": "Private briefing: secrets, alibi, objectives"}, {"id": "performance-script", "label": "Player performance script", "hint": "Spoken lines and scenes: read only your current act"}, {"id": "actor-personas", "label": "Actor personas", "hint": "How to play your character big and fun"}]}, {"id": "lacey", "name": "Lacey Lovely", "role": "Hospital Director", "resources": [{"id": "05-lacey-lovely", "label": "Character dossier", "hint": "Private briefing: secrets, alibi, objectives"}, {"id": "performance-script", "label": "Player performance script", "hint": "Spoken lines and scenes: read only your current act"}, {"id": "actor-personas", "label": "Actor personas", "hint": "How to play your character big and fun"}]}, {"id": "sachs", "name": "Uvula Sachs", "role": "Enforcer", "resources": [{"id": "07-uvula-sachs", "label": "Character dossier", "hint": "Private briefing: secrets, alibi, objectives"}, {"id": "performance-script", "label": "Player performance script", "hint": "Spoken lines and scenes: read only your current act"}, {"id": "actor-personas", "label": "Actor personas", "hint": "How to play your character big and fun"}]}, {"id": "alfie", "name": "Alfie De Worsti", "role": "De Worsti's brother", "resources": [{"id": "08-alfie-de-worsti", "label": "Character dossier", "hint": "Private briefing: secrets, alibi, objectives"}, {"id": "performance-script", "label": "Player performance script", "hint": "Spoken lines and scenes: read only your current act"}, {"id": "actor-personas", "label": "Actor personas", "hint": "How to play your character big and fun"}]}, {"id": "melody", "name": "Melody", "role": "Night Receptionist", "resources": [{"id": "09-melody", "label": "Character dossier", "hint": "Private briefing: secrets, alibi, objectives"}, {"id": "performance-script", "label": "Player performance script", "hint": "Spoken lines and scenes: read only your current act"}, {"id": "actor-personas", "label": "Actor personas", "hint": "How to play your character big and fun"}]}, {"id": "vance", "name": "CD Vance", "role": "IT Contractor", "resources": [{"id": "10-cd-vance", "label": "Character dossier", "hint": "Private briefing: secrets, alibi, objectives"}, {"id": "performance-script", "label": "Player performance script", "hint": "Spoken lines and scenes: read only your current act"}, {"id": "actor-personas", "label": "Actor personas", "hint": "How to play your character big and fun"}]}, {"id": "diamond", "name": "Officer Diamond", "role": "Auxiliary Containment (optional 12th)", "optional": true, "resources": [{"id": "11-officer-diamond", "label": "Character dossier", "hint": "Private briefing: secrets, alibi, objectives"}, {"id": "performance-script", "label": "Player performance script", "hint": "Spoken lines and scenes: read only your current act"}, {"id": "actor-personas", "label": "Actor personas", "hint": "How to play your character big and fun"}, {"id": "17-officer-diamond", "label": "Officer Diamond beat guide", "hint": "When to enter, limited role"}]}], "hostResources": [{"id": "00-host-blueprint", "label": "Host blueprint", "path": "00-host-blueprint.md", "hint": "Truth, murder plan, endings"}, {"id": "01-character-roster", "label": "Character roster", "path": "01-character-roster.md", "hint": "Abilities and objectives summary"}, {"id": "02-character-timelines", "label": "Character timelines", "path": "02-character-timelines.md", "hint": "Minute-by-minute night of murder"}, {"id": "03-motivations-alliances", "label": "Motivations and alliances", "path": "03-motivations-alliances.md", "hint": "Factions and secrets"}, {"id": "04-evidence-index", "label": "Evidence index", "path": "04-evidence-index.md", "hint": "When each clue drops"}, {"id": "15-evidence-materials", "label": "Evidence materials (player text)", "path": "15-evidence-materials.md", "hint": "Printable clue copy and props"}, {"id": "05-episode-scripts", "label": "Episode scripts (host)", "path": "05-episode-scripts.md", "hint": "Cutscenes, narrator, endings"}, {"id": "06-act2-crime-scene", "label": "Act 2 crime scene", "path": "06-act2-crime-scene.md", "hint": "OR search and live investigation"}, {"id": "storm-containment", "label": "Storm and containment logic", "path": "09-storm-containment-logic.md", "hint": "Why suspects investigate"}, {"id": "10-the-gathering", "label": "The gathering", "path": "10-the-gathering.md", "hint": "All eleven players briefed"}, {"id": "11-genevieve-backstory", "label": "Genevieve backstory", "path": "11-genevieve-backstory.md", "hint": "Lacey / Genevieve truth"}, {"id": "12-de-worsti-revelation-arc", "label": "De Worsti revelation arc", "path": "12-de-worsti-revelation-arc.md", "hint": "Episode reveal map"}, {"id": "13-curie-charm-playbook", "label": "Curie charm playbook", "path": "13-curie-charm-playbook.md", "hint": "Ray flirt, Pepper ahem"}, {"id": "actor-personas", "label": "Actor personas", "path": "14-actor-personas.md", "hint": "Performance guide for all eleven"}, {"id": "performance-script", "label": "Player performance script", "path": "player-performance-script.md", "hint": "Distribute to players"}, {"id": "readme", "label": "Project README", "path": "README.md", "hint": "File index"}, {"id": "01-dr-curie", "label": "Dossier: Dr. Curie", "path": "player-dossiers/01-dr-curie.md"}, {"id": "02-officer-ray", "label": "Dossier: Officer Ray", "path": "player-dossiers/02-officer-ray.md"}, {"id": "11-officer-diamond", "label": "Dossier: Officer Diamond", "path": "player-dossiers/11-officer-diamond.md"}, {"id": "03-nurse-pepper", "label": "Dossier: Nurse Pepper", "path": "player-dossiers/03-nurse-pepper.md"}, {"id": "04-dr-homes", "label": "Dossier: Dr. Homes", "path": "player-dossiers/04-dr-homes.md"}, {"id": "05-lacey-lovely", "label": "Dossier: Lacey Lovely", "path": "player-dossiers/05-lacey-lovely.md"}, {"id": "06-dr-jetski", "label": "Dossier: Dr. Jetski", "path": "player-dossiers/06-dr-jetski.md"}, {"id": "07-uvula-sachs", "label": "Dossier: Uvula Sachs", "path": "player-dossiers/07-uvula-sachs.md"}, {"id": "08-alfie-de-worsti", "label": "Dossier: Alfie De Worsti", "path": "player-dossiers/08-alfie-de-worsti.md"}, {"id": "09-melody", "label": "Dossier: Melody", "path": "player-dossiers/09-melody.md"}, {"id": "10-cd-vance", "label": "Dossier: CD Vance", "path": "player-dossiers/10-cd-vance.md"}, {"id": "12-officer-marz", "label": "Dossier: Officer Marz", "path": "player-dossiers/12-officer-marz.md"}, {"id": "17-officer-diamond", "label": "Officer Diamond beat guide", "path": "17-officer-diamond.md", "hint": "Host and player: when to enter, limited role"}, {"id": "dossiers-readme", "label": "Dossiers README", "path": "player-dossiers/README.md"}], "documents": {"performance-script": "<h1>The Cure, Player Performance Script</h1>\n<p><strong>St. Saphicca's Progressive Care, VIP Wing.</strong> You are a suspect, a witness, or both. This booklet has lines to deliver and scenes to play. It does <strong>not</strong> have the full mystery solution.</p>\n<h2>HOW TO PLAY</h2>\n<p><strong>Read your character dossier first.</strong> Everything about who you are, what you want, and what you must hide is in your private dossier. This script only has shared scenes and your spoken lines.</p>\n<p><strong>Stay in character.</strong> Talk like your person. React to the storm, the lockdown, and each other. Argue. Flirt. Lie. Protect your secrets until it costs you something to keep them.</p>\n<p><strong>Only read the act you are in.</strong> When the facilitator says you are in Act 1, read through Act 1 and <strong>stop</strong>. Do not read Act 2 until the facilitator opens it. Same for Acts 3 and 4. Spoilers ruin the night for everyone.</p>\n<p><strong>Lines under your character name</strong> are yours when that scene is reached. Optional lines are yours to use or skip. Brief notes in parentheses are scene cues only, not persona reminders. Stage directions in <em>italics</em> are mood or movement, not spoken aloud.</p>\n<p><strong>NARRATOR</strong> blocks are read by the facilitator. Listen, then play.</p>\n<p><strong>Between scenes</strong> you investigate the wing, trade information, examine evidence, and accuse each other. Officer Ray, Officer Marlowe \"Marz\", and Dr. Curie lead interviews, but no one is a spectator.</p>\n<p><strong>Rules:</strong></p>\n<ul>\n<li>The VIP wing is sealed. No one leaves until municipal watch arrives (end of the night).</li>\n<li>Do not physically grab other players or props unless the facilitator clears it.</li>\n<li>Evidence cards are real in the fiction. You may lie about what you saw. You may not invent evidence the facilitator has not given the room.</li>\n<li>Death in the OR is fixed canon. You cannot rewind the murder.</li>\n<li>Your dossier <strong>✓</strong> and <strong>✗</strong> rules still apply.</li>\n</ul>\n<p><strong>Personas:</strong> Play big and fun. Your dossier and <a href=\"14-actor-personas.md\">14-actor-personas.md</a> have how to play your character.</p>\n<p><strong>Auxiliary cast:</strong> <strong>Officer Diamond</strong> is the optional twelfth player (overflow security). She has a dossier and player pack entry like everyone else, but arrives after The Gathering and stays out of the eleven-person briefing. See <a href=\"player-dossiers/11-officer-diamond.md\">player-dossiers/11-officer-diamond.md</a>.</p>\n<h1>ACT 1</h1>\n<p><em>Do not read past this section until the facilitator opens Act 2.</em></p>\n<h2>PROLOGUE: VIP CONSULTATION SUITE</h2>\n<p><em>Before surgery. Only </em><em>De Worsti</em><em>, </em><em>Homes</em><em>, and </em><em>Pepper</em><em> speak in this scene unless the facilitator casts others as silent presence.</em></p>\n<h3>NARRATOR</h3>\n<blockquote>\n<p>St. Saphicca's Progressive Care rises above Lesbian City in glass and white stone, a hospital built for people who pay not to wait. Tonight the VIP consultation suite is still calm, soft light on the walls, the skyline visible through floor-to-ceiling windows.</p>\n<p>Inside St. Saphicca's, the generators hum. Nurses trade jokes about staying late. Security checks a door and goes back to coffee. The staff believe they are above the water line, protected, busy with one very expensive patient. They have not been told how fast the night is about to narrow.</p>\n<p><strong>HOMES:</strong> Your intake file is still… unusually sparse, Mr. De Worsti.<br />\n<strong>ALEX:</strong> I prefer efficiency. Whatever this costs, double it. So please, no delays. No mistakes.<br />\n<strong>PEPPER:</strong> (quietly) We don't prioritize patients that way.<br />\n<strong>ALEX:</strong> Everyone prioritizes something.</p>\n<p><strong>HOMES:</strong> This is a surgical facility, not a negotiation table. You need this repair. I am not here to flatter you.<br />\n<strong>ALEX:</strong> Everything is a negotiation table, Doctor. I chose this hospital. I expect your seniors to act like it. But I'm here to walk out better than I walked in.</p>\n<p><strong>ALEX:</strong> (softly) People don't get second chances where I come from.<br />\n(to Homes) So let's not waste this one.</p>\n</blockquote>\n<h2>ACT 1: OPERATING THEATER</h2>\n<h3>NARRATOR: OPEN</h3>\n<blockquote>\n<p>VIP Operating Theater Two. St. Saphicca's Progressive Care.<br />\nStorm against the glass. Inside: sterile green, machine hum, the steady beep of a heart that still believes in tomorrow.</p>\n<p><strong>HOMES:</strong> Arterial wall's more compromised than imaging suggested. This is borderline rupture.<br />\nJetski, tighten control. I want zero drift. Pepper, clamp.</p>\n</blockquote>\n<p><strong>PEPPER</strong> (crisp, professional; fear not yet in the room):</p>\n<blockquote>\n<p>Clamp in.<br />\n(beat, reading monitor)<br />\nPressure's falling. Faster than expected.</p>\n<p><strong>HOMES:</strong> Then we stabilize it. We're not chasing this. We control it.</p>\n</blockquote>\n<p><strong>JETSKI</strong> (uneasy):</p>\n<blockquote>\n<p>…hold on, man.<br />\n(blinks hard)<br />\nThat's not right. I'm getting lag. Visual lag. The IV...</p>\n<p><strong>JETSKI:</strong> No, no, that's...</p>\n</blockquote>\n<p><em>The lights cut. Total darkness. Then emergency red.</em></p>\n<h3>NARRATOR</h3>\n<blockquote>\n<p>In the red dark you hear IV lines tugged free, machines clicking off, then a body dragged from the table and thrown hard to tile. A wet violent sound follows, a scalpel driven into a deadly place at the throat. Dr. Homes stands frozen, and the first thing the emergency lights give him is De Worsti on the floor, mouth twisted open in a silent plea, blood spreading from a ragged passionate wound, pale and shining, piled wrong between dropped sterile gauze and a monitor cable still swinging. Rejected meat from a butcher's back room, the mound customers never see, only here the steel was laid out to close wounds, the air still sweet with antiseptic, the tile meant to be washed clean between cases. The heart monitor screams one long tone into the silence.</p>\n<p><strong>HOMES:</strong> (breathing uneven)<br />\nNo… no, that's...<br />\nI lost visibility. I couldn't...<br />\n(looking around, frantic)<br />\nSomeone was here. Someone was <em>in</em> this room.</p>\n</blockquote>\n<p><strong>PEPPER</strong> (first movement; small, broken sound):</p>\n<blockquote>\n<p>…nnh...</p>\n<p><strong>PEPPER:</strong> (hoarse, climbing)<br />\nWhat... what...<br />\n(scrambling, ignoring dizziness)<br />\nOh my God... oh my God...</p>\n<p><strong>PEPPER:</strong> (voice cracking, <strong>terrified</strong>)<br />\nNo... no, no, no...<br />\n(checking reflexively, hands shaking so badly she almost can't hold them steady)<br />\nNo pulse... there's no...</p>\n<p><strong>PEPPER:</strong> (whispering, horrified)<br />\n…we were right here.<br />\n(trying to make sense of it; voice breaking)<br />\nWe were all right here. What happened to him... <strong>what happened to him...</strong></p>\n</blockquote>\n<p><strong>HOMES</strong>:</p>\n<blockquote>\n<p>Pepper... I didn't... the lights...</p>\n</blockquote>\n<h3>NARRATOR: AFTERMATH</h3>\n<blockquote>\n<p>Someone ran for the corridor.<br />\nSomeone screamed for help into a storm that ate sound.<br />\nThey went to find <strong>Director Lacey Lovely</strong> in administration, and <strong>Security Chief Officer Ray</strong>, because in a hospital, death in the OR does not stay in the OR.<br />\nIt climbs the stairs. It knocks on doors. It demands a name.</p>\n<p>The code went out on every channel the building still had. Municipal Watch logged the death, and sent back the same message the city had been sending all night: <em>shelter in place, routes flooded, units when routing permits.</em><br />\nThe backup generators finished their apology. The patrol cars did not.<br />\nInside the VIP wing, someone was already dead. Outside, the storm made sure nobody was coming to save them yet.</p>\n</blockquote>\n<h2>ACT 1: THE GATHERING</h2>\n<p><em>All eleven players. VIP Recovery Lounge. </em><em>Dr. Homes is the primary suspect.</em>**</p>\n<h3>NARRATOR: OPEN</h3>\n<blockquote>\n<p>The VIP Recovery Lounge was built for donors and executives, soft light, skyline views, the illusion that nothing here could go wrong.<br />\nTonight the generators stutter. Rain lashes the glass. Somewhere below, a municipal radio repeats the same sentence: <em>hold position, no ETA.</em><br />\nOfficer Ray has pulled everyone with access to this wing into one room. Officer Marz is with him. Not a request. The wing is locked down.<br />\nThe body of De Worsti is still in the operating theater. The blood on Dr. Homes's gloves has not fully dried.<br />\nAnd eleven people who hated the dead man, or loved him, or owed him, are about to learn they cannot leave until someone answers for what happened in the dark.</p>\n</blockquote>\n<h3>SCENE: THE BRIEFING</h3>\n<blockquote>\n<p><strong>RAY:</strong> I'm Officer Ray. I run security here. Used to work for the city cops. Right now I'm the senior guard in this building. Officer Marz's with me.</p>\n</blockquote>\n<p><strong>MARZ</strong> (already painting a nail):</p>\n<blockquote>\n<p>And I'm Officer Marlowe. Marz. Junior guard. I work with Ray, not around him. Y'all can tell us the truth, or you can tell us something so dumb we'll know you're lying. Either way's fine with me.</p>\n<p><strong>RAY:</strong> (beat)<br />\nAt eleven forty-two, De Worsti died in VIP OR Two. Throat opened with a scalpel. Violent. Almost crazed.<br />\nLights were out about a minute. When they came back, Dr. Homes was standing over him with a scalpel in his hand.</p>\n</blockquote>\n<p><strong>HOMES</strong> (defensive, immediate):</p>\n<blockquote>\n<p>That is not... I did not kill him. I lost the blade when the grid dropped. Someone was in that room.</p>\n</blockquote>\n<p><strong>CURIE</strong>:</p>\n<blockquote>\n<p>Doctor, you'll get your turn. All of you will.</p>\n<p><strong>CURIE:</strong> I'm Dr. Curie, Chief of Surgery. Until Municipal Watch gets through the flood, and they are not here yet, I am medical liaison on this death.<br />\nThat means cause, mechanism, and whether anyone in this room had the skill and the access to do what was done.</p>\n</blockquote>\n<p><strong>RAY</strong>:</p>\n<blockquote>\n<p>And I'm the security here. We figure this out together, or we stumble around in the dark.</p>\n</blockquote>\n<p><strong>CURIE</strong>:</p>\n<blockquote>\n<p>Officer, I'd flirt back, but we have a corpse and a flood. Another time.</p>\n</blockquote>\n<p><strong>PEPPER</strong> (<strong>sharp ahem</strong>; comedic beat):</p>\n<blockquote>\n<p><em>(clears throat)</em><br />\n…Can we stay on the dead man?</p>\n</blockquote>\n<p><strong>HOMES</strong> (bristling):</p>\n<blockquote>\n<p>Christ. Could we investigate the murder instead of...</p>\n</blockquote>\n<p><strong>CURIE</strong> (devastating):</p>\n<blockquote>\n<p>Doctor, when you have an alibi, I'll schedule around your preferences.</p>\n</blockquote>\n<p><strong>LACEY</strong>:</p>\n<blockquote>\n<p>Officer. I have counsel on standby. This hospital will cooperate within regulatory...</p>\n<p><strong>RAY:</strong> (flat) Director Lovely. You locked this wing down twenty minutes ago. That was your call, not mine. Your lawyer can wait until I say otherwise.</p>\n<p><strong>RAY:</strong> I called the real cops. They logged it. Answer back was wait, roads are flooded. No patrol car. No detective. Nobody's coming up those elevators for hours.<br />\n(beat, harder)<br />\nI know how this looks. De Worsti had dirt on half this city. He had dirt on me too. I'm a suspect same as you. I'm also running this wing until those sirens show up.<br />\nNobody leaves. Nobody. You talk in this room, or I stick you in separate rooms and let the real cops sort it in the morning.</p>\n<p><strong>CURIE:</strong> (to the room) The officer's right. If we don't build the case tonight, the case will be built for us, by people who weren't in the building when the lights died.</p>\n</blockquote>\n<h3>ROUND ONE: WHO WAS WHERE</h3>\n<blockquote>\n<p><strong>RAY:</strong> Give us your names. Jobs. Where you were when the red lights came on. One at a time. Jetski, you're first. You're half why this room was knocked out.</p>\n</blockquote>\n<p><strong>JETSKI</strong> (shaking, furious at the framing):</p>\n<blockquote>\n<p>Dr. Jetski. Anesthesiology. Dude, I was at the south wall monitoring IV delivery and I went down before the lights even cut, lag, paralysis, I couldn't move, I couldn't see straight. Ask Pepper. I was on the floor when it happened.</p>\n</blockquote>\n<p><strong>PEPPER</strong> (clinical mask over horror):</p>\n<blockquote>\n<p>He's not lying about the timing. I felt it too, cognitive lag, motor drop. We were incapacitated before the incision.<br />\n(beat, unwilling)<br />\nI was assisting Dr. Homes. De Worsti was on the table when the lights died. When the red lights came back he was on the floor… Homes had the scalpel. De Worsti was gone.</p>\n</blockquote>\n<p><strong>HOMES</strong>:</p>\n<blockquote>\n<p>I was primary surgeon. The arterial wall was compromised, we were stabilizing. Jetski reported drift. Then black. I felt the blade pulled from my grip. I shouted for backup power. When the lights returned I was still holding<br />\n(voice cracking)<br />\nI didn't make that cut. I couldn't see. Someone was in there with us.</p>\n</blockquote>\n<p><strong>CURIE</strong> (quiet, surgical):</p>\n<blockquote>\n<p>The wound was not panic. It was passionate, almost crazed. But a scalpel did it, and that could be a surgeon's hand or a man's rage.</p>\n<p><strong>RAY:</strong> You're my main guy until I hear better. Sit down.</p>\n</blockquote>\n<h3>ROUND TWO: EVERYONE ELSE IN THE WING</h3>\n<blockquote>\n<p><strong>RAY:</strong> The rest of you. What were you doing in my wing tonight?</p>\n</blockquote>\n<p><strong>MELODY</strong>:</p>\n<blockquote>\n<p>Melody! Night reception? Like, I was at the desk, I called the code when the monitor flatlined, oh my god, and I saw <em>everyone</em> coming and going all night. Including</p>\n</blockquote>\n<p><em>Glances at </em><em>Alfie</em><em>. Blinks innocent. Glances at </em><em>Marz</em><em>'s nails.</em></p>\n<blockquote>\n<p><strong>MELODY:</strong> Officer Marz? Where is that blouse from? It is, like, literally gorgeous on you.</p>\n</blockquote>\n<p><strong>MARZ</strong>:</p>\n<blockquote>\n<p>Oh, bless you, honey. Thrift store in the Quarter, then I fixed the cuffs myself. You have good eyes.</p>\n<p><strong>MELODY:</strong> Including things that don't match the visitor log. But that's like, a whole thing.</p>\n<p><strong>RAY:</strong> Including what?</p>\n</blockquote>\n<p><strong>MELODY:</strong></p>\n<blockquote>\n<p>Including things that don't match the visitor log. Ask your IT guy about the cameras. Ask about the page missing from the keycard book.</p>\n</blockquote>\n<p><strong>VANCE</strong>:</p>\n<blockquote>\n<p>Hi! Hi. CD Vance. IT contractor? Server room! Storm failover, corridor three offline, Director Lovely's audit, and also, um. Other requests. I don't do violence, I do logs, I do Python, I do panic</p>\n<p><strong>VANCE:</strong> <em>(quieter)</em> …eep.</p>\n<p><strong>RAY:</strong> (flat) Other requests. We'll come back to logs. And to you.</p>\n</blockquote>\n<p><strong>SACHS</strong>:</p>\n<blockquote>\n<p>He does what keeps his pones in one piece. Like any contractor who does not want the project cancelled.</p>\n</blockquote>\n<p><strong>ALFIE</strong> (smug, too casual):</p>\n<blockquote>\n<p>Alfie De Worsti. De Worsti's brother. I was a delivery. Medical supplies. That's on the manifest.</p>\n</blockquote>\n<p><strong>SACHS</strong>:</p>\n<blockquote>\n<p>Uvula Sachs. You want the name on my pirth certificate or the one your mother kave you?</p>\n<p><em>(to room, suddenly)</em> Wait. Stop. Who is running this introduction? No one? Ah. That explains the vibe in this room immediately.</p>\n<p><strong>RAY:</strong> (immediate) Where were you at eleven forty-two?</p>\n</blockquote>\n<p><strong>SACHS:</strong></p>\n<blockquote>\n<p>Perimeter. VIP access corridor. Eleven forty-two, <strong>not</strong> \"around\" eleven forty-two. I post where I'm told. De Worsti owed money. I owed answers. I did not owe him a throat cut in the dark.</p>\n<p>And if you're asking who in this room looks like they just left an OR? You are staring at him, Officer. Motive, opportunity, blood on his hands. Why are we still using vibes?</p>\n</blockquote>\n<p><strong>LACEY</strong>:</p>\n<blockquote>\n<p>Lacey Lovely. Hospital Director. I was in administration, two floors up, managing grid instability and crisis protocol when the wing failed over. I did not enter the operating theater.</p>\n</blockquote>\n<p><strong>CURIE</strong> (does not block):</p>\n<blockquote>\n<p>Good. Pull it. Executive tier on a night like this is a lead.<br />\n(to Ray, professional)<br />\nSurgical read? A director facilitates, she doesn't usually make the incision herself. Unlikely primary cutter. Still a lead. Run it.</p>\n</blockquote>\n<h3>THE ACCUSATION</h3>\n<blockquote>\n<p><strong>RAY:</strong> Let's be plain. Everyone hated De Worsti. Loan shark in a hospital gown. Half of you wanted him dead.<br />\nBut only one guy was standing over the body, blood on his hands, scalpel in his grip when the lights came back.<br />\nDr. Homes, you're my main suspect.</p>\n</blockquote>\n<p><strong>HOMES</strong> (standing, rage):</p>\n<blockquote>\n<p>This is insane. Curie, you're Chief of Surgery, you know that cut was</p>\n</blockquote>\n<p><strong>CURIE</strong> (devastating):</p>\n<blockquote>\n<p>I know what I know. And right now I know you were holding the instrument.</p>\n</blockquote>\n<p><strong>PEPPER</strong> (torn, quiet):</p>\n<blockquote>\n<p>…I don't think you did it.</p>\n<p><strong>PEPPER:</strong> I don't know what I think. I was on the floor. I saw you standing there. I saw</p>\n</blockquote>\n<p><strong>JETSKI</strong> (small):</p>\n<blockquote>\n<p>Bro, I was paralyzed. He wasn't the only surgeon in this building.</p>\n<p><strong>RAY:</strong> Then help me prove it. Starting now.</p>\n</blockquote>\n<h3>CURIE: THE ASK</h3>\n<blockquote>\n<p><strong>CURIE:</strong> Officer Ray cannot process a coordinated murder alone. I cannot autopsy a conspiracy from a cot.<br />\nEvery person in this lounge was inside the VIP wing when De Worsti died. That makes you witnesses, suspects, or both.<br />\nThe municipal watch is not walking through that flood tonight. The killer may still be in this wing, I don't say that to panic you. I say it because it's true.<br />\nSo here's what happens next. We log evidence. You don't get to go home and invent an alibi in the rain.</p>\n<p><strong>RAY:</strong> Find me something that proves Homes didn't do it.<br />\nOr Homes sits alone and I talk to the rest of you one by one in rooms with no windows.<br />\nYou don't have to like me. You do have to stay.</p>\n</blockquote>\n<h3>JETSKI: THE ROOM GOES QUIET</h3>\n<p><strong>JETSKI</strong> (quiet, not performing, genuinely unsettled):</p>\n<blockquote>\n<p>You know what keeps turning in my head?<br />\n(beat)<br />\nWe keep asking who was in the OR. Who had the blade. Who was out in the storm.<br />\nBut whoever killed De Worsti didn't have to be out there.<br />\nThey could be right here. In this lounge. Listening. Helping us decide who to blame.<br />\n(quieter, to Pepper or the room)<br />\nThat's the part that's going to stay with me, man.</p>\n</blockquote>\n<p><strong>CURIE</strong> (optional):</p>\n<blockquote>\n<p>Doctor, you're medicated and you're frightened. That's fair. Let's channel it into evidence.</p>\n</blockquote>\n<p><strong>RAY</strong> (optional):</p>\n<blockquote>\n<p>Yeah. Fine. Now we work.</p>\n</blockquote>\n<h3>NARRATOR: TRANSITION OUT</h3>\n<blockquote>\n<p>The lounge emptied in fragments, no one calm, no one innocent in the eyes of the room.<br />\nDr. Homes left under Ray's gaze like a man already in cuffs.<br />\nDr. Curie touched his shoulder in the corridor, a colleague's sympathy that looked perfect on camera that didn't exist.<br />\nThe storm kept screaming. The sirens were still miles away.<br />\nAnd somewhere between the pharmacy vault and the admin terminal, the truth was already written in codes and overrides the room had not opened yet.</p>\n</blockquote>\n<h3>OPTIONAL: OFFICER DIAMOND (twelfth player, arrives after briefing)</h3>\n<p><em>Diamond was on main campus when the code dropped. Read this beat when the facilitator calls you in, usually end of Act 1.</em></p>\n<p><strong>DIAMOND</strong>:</p>\n<blockquote>\n<p>Okay! <strong>Phase One: Lockdown Complete.</strong> Officer Diamond. Overflow from main campus. Perimeter's mine. You all keep being suspicious. Boo yah.</p>\n</blockquote>\n<p><strong>RAY</strong> (optional):</p>\n<blockquote>\n<p>Diamond. Door. Logs. Don't gamify the corpse.</p>\n</blockquote>\n<p><strong>DIAMOND</strong> (optional):</p>\n<blockquote>\n<p>Copy that, Chief. Phase One point five: Respect the Corpse. I'm on it.</p>\n</blockquote>\n<p><strong>END OF ACT 1.</strong> Investigate the wing. Defend yourself. Trade secrets. Do not open Act 2 until the facilitator says so.</p>\n<h1>ACT 2</h1>\n<p><em>Do not read past this section until the facilitator opens Act 3.</em></p>\n<h2>ACT 2: THE LOGIC OF THE NEEDLE</h2>\n<p><em>Recovery ward. Toxicology. Logs. Pressure on Lacey and Vance.</em></p>\n<p><strong>CURIE</strong> (to Ray):</p>\n<blockquote>\n<p>They also don't panic. Give him air, Officer, you'll get a better witness.</p>\n</blockquote>\n<p><strong>RAY</strong>:</p>\n<blockquote>\n<p>Don't tell me how to ask questions.</p>\n</blockquote>\n<p><strong>CURIE</strong>:</p>\n<blockquote>\n<p>I'd never. I'm only suggesting you look handsome when you're not shouting.</p>\n</blockquote>\n<p><strong>PEPPER</strong> (<strong>ahem</strong>, entering with folder):</p>\n<blockquote>\n<p><em>(clears throat, deadpan)</em><br />\nToxicology's ready. Whenever you two are <strong>done</strong>.</p>\n<p><strong>PEPPER:</strong> Jetski collapsed before the lights even went out. The killer needed night vision, or immunity.<br />\n<strong>RAY:</strong> Pharmacy vault got opened. Top-level clearance. <strong>Lacey Lovely.</strong><br />\n<strong>RAY:</strong> Power got cut around the same time. That's not a coincidence. I want everything on her. Who she let in. What she's been doing.</p>\n</blockquote>\n<p><strong>CURIE</strong>:</p>\n<blockquote>\n<p>Run it. You should run it. Executive codes on a night like this are a lead. Full stop.<br />\n(beat)<br />\nMy surgical opinion? A hospital director doesn't usually personally execute a patient on her own OR table. The access pattern fits a <strong>facilitator</strong>, not a cutter. Unlikely as primary actor, but unlikely isn't innocent. Pull her file. I'm not standing in your way.</p>\n</blockquote>\n<p><strong>RAY</strong> (short nod, trusts the tone):</p>\n<blockquote>\n<p>Good. Then we're chasing it.</p>\n</blockquote>\n<p><strong>MARZ</strong> (optional, painting a nail, outlandish but specific):</p>\n<blockquote>\n<p>Honey, what if the director didn't do the cutting because she was two floors up showing she <em>couldn't</em> have been in that room? That's not innocent. That's planning.</p>\n</blockquote>\n<p><strong>RAY</strong> (optional):</p>\n<blockquote>\n<p>Write it down. Don't preach it yet.</p>\n</blockquote>\n<p><strong>CURIE</strong> (brushes nonexistent lint from Ray's shoulder; casual):</p>\n<blockquote>\n<p>You've got a good instinct. Keep it.</p>\n</blockquote>\n<p><strong>PEPPER</strong> (optional, under breath):</p>\n<blockquote>\n<p><em>(ahem)</em></p>\n<p><strong>CURIE:</strong> Access, preparation, delivery, blackout, incision. You don't improvise that. Someone coordinated. Director's tier is on that list until it isn't.</p>\n</blockquote>\n<p><strong>RAY</strong> (to <strong>Vance</strong>, if present or via intercom):</p>\n<blockquote>\n<p>Vance. You. Now. If Sachs put you up to anything in my building tonight, start talking before I hand you to her.</p>\n</blockquote>\n<p><strong>DIAMOND</strong> (optional, escort beat if facilitator splits room for search):</p>\n<blockquote>\n<p>Welcome to <strong>Phase Three: Controlled Chaos.</strong> Pair up. I walk you to your assigned room. New rule: if you touch evidence without logging it, you lose credibility points. I don't make the system. Boo yah.</p>\n</blockquote>\n<p><strong>VANCE</strong>:</p>\n<blockquote>\n<p>Okay okay okay... so Sachs was like, <em>find the wife</em>, and I was like <em>eep</em> but also the query was already running? Clinic databases, reconstruction intake flags, hospital admin cross ref... I was looking for whoever stole his money! I didn't know her <strong>name</strong>! I didn't know it was <em>her</em>...</p>\n<p><strong>VANCE:</strong> I'm not realted to the victim, I was just helping a debt collector hunt a woman who ran. That's what he built. Men like De Worsti make you dig with your own hands and your own cute little keyboard, and I'm so sorry...</p>\n</blockquote>\n<p><strong>SACHS</strong> (efficiency rage, not snarling):</p>\n<blockquote>\n<p>You ton't get to moralize. You were on the clock. And your timeline is still wrong, \"around when Sachs asked\" is not a timestamp.</p>\n</blockquote>\n<p><strong>CURIE</strong> (to window):</p>\n<blockquote>\n<p>Some people don't die in hospitals, Officer… they get released.</p>\n</blockquote>\n<p><strong>RAY</strong> (tired smile he hates himself for):</p>\n<blockquote>\n<p>You say stuff like that so I forget you're on my list.</p>\n</blockquote>\n<p><strong>CURIE</strong> (without turning):</p>\n<blockquote>\n<p>I'm on your board. I'm also the best partner you've got tonight. Use me accordingly.</p>\n</blockquote>\n<p><strong>END OF ACT 2.</strong> Keep investigating. New evidence is in play.</p>\n<h1>ACT 3</h1>\n<p><em>Do not read past this section until the facilitator opens Act 4.</em></p>\n<h2>ACT 3: FOUND IN THE DARK</h2>\n<p><em>Pharmacy wing hallway. Melody attacked.</em></p>\n<blockquote>\n<p><strong>RAY:</strong> Security! Step away!</p>\n<p><strong>CURIE:</strong> Potassium chloride overdose! Shadow running toward administration. Go, Ray!<br />\n<strong>RAY:</strong> Did you see who...<br />\n<strong>CURIE:</strong> Move!</p>\n</blockquote>\n<p><strong>MELODY</strong> (weak, if antidote succeeds):</p>\n<blockquote>\n<p>It's not just him… it's everything… all of you…</p>\n</blockquote>\n<p><em>If the room solves the antidote puzzle in time, Melody survives. If not, she stays unconscious and the room loses her direct testimony.</em></p>\n<p><strong>END OF ACT 3.</strong></p>\n<h1>ACT 4</h1>\n<p><em>Final act. Do not read until the facilitator opens Act 4.</em></p>\n<h2>ACT 4: ALFIE REVEALS GENEVIEVE</h2>\n<p><strong>RAY</strong> (hard):</p>\n<blockquote>\n<p>Your brother kept a wife locked up for years. Detective file says new face. New name. You said you came here with medical supplies. Start talking straight.</p>\n</blockquote>\n<p><strong>ALFIE</strong> (must deliver; do not skip; truth through uncertainty):</p>\n<blockquote>\n<p>I... look. I'm not trying to bury my brother. I'm not trying to hang anyone either. I just… I can't keep my mouth shut anymore.</p>\n<p>(beat)</p>\n<p>As far as I know, his wife, his <em>first</em> wife, her name was <strong>Genevieve</strong>. Maybe it still is, somewhere under all this. I don't know what you call yourself now.</p>\n<p>(glances at <strong>Lacey</strong>, pained)</p>\n<p>De Worsti wasn't just a lender. Not at the end. He was… whatever he became. Men like Sachs at the door. Ledgers. Genevieve didn't run that house, she <strong>survived</strong> it, as best I could tell from the outside. I think he moved her when he wanted. I think he took her phone when he wanted. I <strong>saw</strong> bruises once. Holidays where she wouldn't eat. I could be wrong about some of it, he told the family she was unstable, and when you're family you want to believe that.</p>\n<p>(voice cracks)</p>\n<p>But I don't think I was wrong. Not about the flinching.</p>\n<p>(beat, softer)</p>\n<p>When she disappeared, when she took money and ran, De Worsti called it theft. Like she was property. Hunters. Clinic lists. I didn't know where she landed. I'm <strong>not</strong> saying I have proof of every step.</p>\n<p>(hesitates)</p>\n<p>There's an intake photo. Mainland clinic. Scar above the left ear, glass, years ago, I <strong>think</strong> it was her. Total reconstruction, maybe. New name. New life. I could be connecting dots that aren't, except De Worsti needed the surgery, sure, but he chose <strong>this</strong> hospital. He was here because <strong>she</strong> might be.</p>\n<p>(almost pleading)</p>\n<p>I'm telling you what I believe. I'm not saying she did anything tonight. Genevieve just wanted to <strong>run</strong>. That's what I keep coming back to. She wanted out. Not… this.</p>\n</blockquote>\n<p><strong>LACEY</strong> (mandatory; do not skip):</p>\n<blockquote>\n<p>You don't know what you're talking about.</p>\n</blockquote>\n<p><strong>ALFIE</strong> (quiet, protective):</p>\n<blockquote>\n<p>I know enough that I didn't want to say it like this.</p>\n</blockquote>\n<p><strong>LACEY</strong> (stands; not confession):</p>\n<blockquote>\n<p>Officer. You want the truth from me? Fine.</p>\n<p>I ran. I changed my life. I did what I had to do to never sleep in the same room as that man again.<br />\n(beat)<br />\nI did <strong>not</strong> hate him enough to kill him. I wanted distance, miles, years, a face he wouldn't recognize. Murder wasn't the plan. Running was.<br />\n(cold)<br />\nSomeone killed him in an operating theater. I was two floors up in administration. If your logs say otherwise, read them. But don't let that ghost put words in my mouth.</p>\n</blockquote>\n<p><strong>MELODY</strong> (support, after Alfie only; firmer than Alfie):</p>\n<blockquote>\n<p>…The archival intake binders don't lie. I wondered why you looked familiar. Pre op photos. Before the reconstruction. If he's right, that's Genevieve.</p>\n</blockquote>\n<p><strong>CURIE</strong>:</p>\n<blockquote>\n<p>Officer, run every log you have. I've said that all night.<br />\n(to the room)<br />\nClinically? A director with that history is a <strong>motive</strong>, not a mechanism. The throat was opened with a scalpel in a violent, almost crazed stroke. That could be a surgeon. It could be Homes in a rage. Lovely's tier fits access, not the blade. Unlikely she'd personally finish him on the table.<br />\n(beat, meets Ray's eyes)<br />\nStill a live lead. Especially if someone else held the blade for her. Don't drop it on my account.</p>\n</blockquote>\n<p><strong>PEPPER</strong> (<strong>ahem</strong>).</p>\n<p><strong>HOMES</strong> (snapped):</p>\n<blockquote>\n<p>Are we solving a murder or watching you two eye fuck over the evidence?</p>\n</blockquote>\n<p><strong>CURIE</strong>:</p>\n<blockquote>\n<p>Doctor, your alibi is still bleeding. I'd focus.</p>\n</blockquote>\n<p><strong>RAY</strong> (cutting, but not at Curie):</p>\n<blockquote>\n<p>I'm not dropping it. Someone opened the vault. Someone killed the lights. Someone with the keys. And a dead man who came here chasing a woman who just wanted to get away.</p>\n</blockquote>\n<p><strong>PEPPER</strong> (optional, if affair secret is out):</p>\n<blockquote>\n<p>I loved him. I need you to hear that. And I need you to hear that I didn't know... Genevieve. The fire. Any of it. He wasn't… he wasn't just difficult. He was what Alfie said. And the people who cut his throat still sat with us at that table.</p>\n</blockquote>\n<h2>ACT 4: FINAL CALL</h2>\n<h3>NARRATOR</h3>\n<blockquote>\n<p>The storm is thinning. You can hear it in the walls, less scream, more drain.<br />\nGenevieve is in the room, whatever name she wears.<br />\nThe real cops are close, sirens somewhere below the flood line, getting closer.<br />\nBefore they walk through that door, this room decides: one suspect. Or is it more?</p>\n<p>It's up to them to choose what kind of city Lesbian City becomes tonight.</p>\n</blockquote>\n<p><em>The facilitator collects accusation ballots and moral verdict ballots. Debate. Vote. Then listen to the ending.</em></p>\n<h2>AFTER THE VOTE (listen and react)</h2>\n<p><em>The facilitator reads what the room decided. React in character. You may be arrested, vindicated, or caught in chaos.</em></p>\n<h3>NARRATOR: POLICE ARRIVAL</h3>\n<blockquote>\n<p>The wind dropped like a held breath.<br />\nFirst the generators steadied. Then, distant, then close, sirens.<br />\nMunicipal Watch. Flood lights pouring out through the glass. There was the sound of boots in the lobby and radios that weren't hospital channels.</p>\n</blockquote>\n<p><strong>RAY</strong> (exhausted, to the room):</p>\n<blockquote>\n<p>That's them. Finally.<br />\nWhatever you picked in this room, names, proof, who did what. It's theirs now.</p>\n</blockquote>\n<h3>NARRATOR: THE TRUTH</h3>\n<blockquote>\n<p>Long before the operating table, before the storm, before the red emergency lights, there was a locked house and a woman called Genevieve learning how to become smaller than a man's rage.</p>\n<p>De Worsti made debt into religion. He called cruelty discipline. He called possession love. Behind security doors and polished glass, he broke people down to what they could pay, and when money was gone, he took silence, obedience, blood.</p>\n<p>Genevieve ran when she finally could. She paid for a new face with fear and cash and sleepless years. She took a new name, Lacey Lovely, and built an administrative empire out of rules, schedules, and controlled doors. She told herself survival was enough.</p>\n<p>It was not enough for De Worsti.</p>\n<p>He found the thread, clinic photos, reconstruction records, a scar above the left ear, and followed it back to St. Saphicca's. He arrived as a patient and predator, smiling through intake, already planning what he would reclaim.</p>\n<p>Officer Ray watched De Worsti ruin one of the few people he still cared about, took a security post to stay close, and swore revenge. When De Worsti booked real surgery in Lacey's wing, Ray accelerated a plan the room would mistake for medical conspiracy.</p>\n<p>Vault access opened the path. Potassium chloride prepared the room. Backup power failed at exactly the right minute. Sedation lagged the witnesses. In darkness, one trained hand drove a scalpel through his throat in a violent, almost crazed stroke. Then noise, panic, blood on the wrong gloves, and Dr. Homes framed by timing and terror while Curie became the obvious red herring.</p>\n<p>By sunrise, the script was cracked open. Logs matched toxicology. Access trails matched alibis that were too perfect. Fear matched opportunity. And for once in Lesbian City, the rich did not buy the ending.</p>\n<p>De Worsti died the way he made others live, trapped, cornered, at the mercy of people he thought he owned.<br />\nRay did not walk free into dawn. He walked in chains beside the friend he tried to protect.<br />\nJustice arrived late, soaked through, and incomplete. But it arrived.</p>\n</blockquote>\n<p><strong>END OF NIGHT.</strong></p>", "actor-personas": "<h1>Actor Personas, Performance Guide</h1>\n<p><strong>Plot beats unchanged.</strong> These are exaggerated, fun lenses for how to <em>play</em> each character, bigger energy, same story.</p>\n<h2>Quick reference</h2>\n<table>\n<thead>\n<tr>\n<th>Character</th>\n<th>Persona</th>\n<th>Play as…</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td><strong>Dr. Curie</strong></td>\n<td>Prince Charming red herring</td>\n<td>Disney prince surface; motive without guilt</td>\n</tr>\n<tr>\n<td><strong>Officer Ray</strong></td>\n<td>Bruiser with soft center (killer)</td>\n<td>Wall of muscle and bark; friend's revenge</td>\n</tr>\n<tr>\n<td><strong>Officer Marz</strong></td>\n<td>Southern belle (brutally honest)</td>\n<td>Honey, nails, wild theories; kind when asked nicely</td>\n</tr>\n<tr>\n<td><strong>Nurse Pepper</strong></td>\n<td>Sage + sentimental</td>\n<td>Wise, calm, then devastatingly precise</td>\n</tr>\n<tr>\n<td><strong>Dr. Homes</strong></td>\n<td>Authoritative dick (good cause)</td>\n<td>Insufferable expert who <em>is</em> that good</td>\n</tr>\n<tr>\n<td><strong>Lacey Lovely</strong></td>\n<td>Girl next door damsel / corporate</td>\n<td>Soft, pretty, harmless, spreadsheet blade underneath</td>\n</tr>\n<tr>\n<td><strong>CD Vance</strong></td>\n<td>Genki IT girl</td>\n<td>Hyper, cute, nerdy; terror as squeaky speed</td>\n</tr>\n<tr>\n<td><strong>Uvula Sachs</strong></td>\n<td>Workflow chaos gremlin (German)</td>\n<td>Efficiency rage; murder as bad PM; accent: D→T, B→P, G→K, V→F</td>\n</tr>\n<tr>\n<td><strong>Melody</strong></td>\n<td>Valley gossip bimbo</td>\n<td>Airy, ditzy, sees <em>everything</em></td>\n</tr>\n<tr>\n<td><strong>Alfie De Worsti</strong></td>\n<td>Strategic rage baiter</td>\n<td>Screw-up mask; observant; inflammatory; punchable</td>\n</tr>\n<tr>\n<td><strong>Dr. Jetski</strong></td>\n<td>Frazzled surfer bro</td>\n<td>Sweat, volume, occasional <em>dude</em>; smart when it counts</td>\n</tr>\n<tr>\n<td><strong>Officer Diamond</strong></td>\n<td>Procedure nerd (overflow)</td>\n<td>Gamify phases; boo yah; sharper than the bit</td>\n</tr>\n</tbody>\n</table>\n<h2>Dr. Curie, Prince Charming (obvious red herring)</h2>\n<p><strong>Surface:</strong> Shoulders back, warm eye contact, remembers names, offers coats and coffee. Classic leading man charm with an <strong>annoying charisma</strong> ,  idealist, kind-hearted social butterfly, the room's angel's advocate. The room <em>wants</em> to be on his side.</p>\n<p><strong>Under the hood:</strong> Deeply traumatized (Genevieve, the fire). Wanted De Worsti dead. <strong>Did not kill him.</strong> Assumes the best in people, including Ray ,  so he never suspects who lifted his OR keycard. His niceness is <strong>genuine, not performance</strong>; in a murder investigation that sincerity reads suspicious anyway. When stressed, get <em>more</em> warm and optimistic, not less, and the room will chase the wrong surgeon.</p>\n<p><strong>Physical:</strong> Open posture; unhurried hands; smile that lands like a gift.<br />\n<strong>Voice:</strong> Low, warm, complete sentences. Never shouts, cuts with politeness.<br />\n<strong>Tell:</strong> When cornered on motive, he gets <em>extra</em> sincere, not guilty ,  finds the upside even when no one asked.</p>\n<blockquote>\n<p><em>\"Officer, I'd flirt back, but we have a corpse.\"</em> (smile, pivot, devastating competence).</p>\n</blockquote>\n<p><strong>Homes</strong> is his <strong>professional rival</strong> ,  merit vs charm, oil and fire. Homes thinks the warmth is obscene; Curie thinks Homes is exhausting. Lean into the rivalry; neither is faking the friction.</p>\n<h2>Officer Ray, Bruiser with a soft center (killer)</h2>\n<p><strong>Surface:</strong> Square jaw energy, boots loud, notebook like a weapon. First impression: <em>will arrest the weather.</em></p>\n<p><strong>Under the hood:</strong> Lacey's old friend. Learned what De Worsti did to her. Swore revenge. Runs the investigation while steering the room toward Curie and Homes. He did not chase Alex through the wing ,  he waited for the only room he could engineer: sedated on Lacey's table, witnesses frozen, Homes framed, badge still credible.</p>\n<p><strong>If the room asks \"why not kill him elsewhere\":</strong> <em>\"A man like that doesn't travel alone on a storm night. You don't stab him in a hallway and walk away clean. You let a surgeon save him ,  or you kill him where medicine already has him pinned down.\"</em> (Curie, authoritative.) Or Marz: <em>\"Security chief offs a VIP in the garage and then runs the case? Please.\"</em></p>\n<p><strong>Soft center:</strong> Protective of Lacey, quietly loyal to his friends, uses warmth as cover. He is easier around Lacey than almost anyone else.</p>\n<p><strong>Physical:</strong> Takes space; points with chin; softens voice only for Curie, Lacey, or when admitting debt shame.<br />\n<strong>Voice:</strong> Gravel, short sentences, words a normal person would use. Occasional accidental tenderness he covers with gruffness.<br />\n<strong>Tell:</strong> Rubs back of neck when embarrassed, or when the keycard question gets too close.</p>\n<blockquote>\n<p><em>\"Don't tell me how to ask questions.\"</em> (said like he already took the note).</p>\n</blockquote>\n<h2>Officer Marz, Southern belle (brutally honest)</h2>\n<p><strong>Surface:</strong> Posture like church on Sunday, voice like sweet tea, nails wet from a fresh coat; you paint them when you think, and it looks like fidgeting because it is.</p>\n<p><strong>Under the hood:</strong> Junior to Ray but not junior in brains, so you will say the outlandish thing out loud because someone ought to.</p>\n<p><strong>Physical:</strong> Pin curls or neat bun; uniform pressed; lipstick careful; notebook with little stars in the margin.<br />\n<strong>Voice:</strong> Drawl, polite, simple words, then a theory that clears the room.<br />\n<strong>Tell:</strong> Paints a nail, blows on it, delivers catastrophe like weather.</p>\n<blockquote>\n<p><em>\"Honey, I'm not saying the director cut him. I'm saying if I were her, I'd have been upstairs making sure nobody thought I could.\"</em></p>\n</blockquote>\n<p><strong>Melody beat:</strong> She asks where your outfit is from, and you answer <strong>kindly</strong> because you are not cruel.</p>\n<p><strong>Vance beat:</strong> You go soft when he panics and do not tease him for liking Melody, even though your heart is your own problem.</p>\n<h2>Nurse Pepper, Sage (sentimental + logical)</h2>\n<p><strong>Surface:</strong> Still water and hospital monk energy; you speak like you've read the chart <em>and</em> the room.</p>\n<p><strong>Sentimental:</strong> Grief for De Worsti is real and messy beneath the calm, while your crush on Homes stays quiet and not performative.</p>\n<p><strong>Logical:</strong> When she switches to data mode, it's surgical, timestamps, vitals, no fluff. The throat clear is her <strong>only</strong> undignified habit <em>once she's composed again.</em></p>\n<p><strong>OR scene (Ep 1):</strong> Let the terror <strong>shatter</strong> the sage mask, shaking hands, broken voice, can't finish sentences. She recomposes later; this is the first crack.</p>\n<p><strong>Physical:</strong> Economical movement; clipboard as sceptre.<br />\n<strong>Voice:</strong> Measured; drops one precise line then silence.<br />\n<strong>Tell:</strong> <em>Ahem</em> when emotions get too loud in the room.</p>\n<h2>Dr. Homes, Authoritative dick (for a good cause)</h2>\n<p><strong>Surface:</strong> God complex with receipts. Condescending because he <em>is</em> the best surgeon in the wing, and saving lives matters more than your feelings.</p>\n<p><strong>Not cartoon evil:</strong> Believes in the medicine. <strong>Rival</strong> to Curie ,  hates his annoying charisma and angel's-advocate habit of finding bright sides for people who should be suspects.</p>\n<p><strong>Physical:</strong> Chin up; invades personal space; gestures with instruments or pens like scalpels.<br />\n<strong>Voice:</strong> Lecturing timbre; sighs before other people speak.<br />\n<strong>Tell:</strong> Says <em>\"Doctor\"</em> correcting his own title when insulted.</p>\n<blockquote>\n<p><em>\"Could we investigate the murder instead of auditioning?\"</em> (peak Homes).</p>\n</blockquote>\n<h2>Lacey Lovely, Girl next door damsel (corporate)</h2>\n<p><strong>Surface:</strong> Pretty, approachable, <em>harmless</em>, cardigan energy in a director's badge. People underestimate her because she looks like someone who needs protecting.</p>\n<p><strong>Corporate side:</strong> Ice underneath. Liability language, boardroom smile, crisis voice on speakerphone.</p>\n<p><strong>Play the gap:</strong> Damsel in the light; steel in the pause before she answers. Ray's friend; she did not plan the murder.</p>\n<p><strong>Physical:</strong> Soft angles; stillness; smile that doesn't reach eyes when cornered.<br />\n<strong>Voice:</strong> Warm alto for public; flat executive for threats.<br />\n<strong>Ep 4 denial:</strong> Sincere, <em>\"I only wanted to run\"</em>, delivered like a woman telling the truth for once.</p>\n<h2>CD Vance, Genki IT girl</h2>\n<p><strong>Surface:</strong> Nerdy, hyperactive, <strong>cutesy</strong>, stickers on laptop, anime keychain energy, talks fast when nervous (always nervous).</p>\n<p><strong>Terror reads as:</strong> Speed, babble, oversharing technical detail nobody asked for. <em>\"Okay okay okay so the logs are like, \"</em> then accidentally confesses.</p>\n<p><strong>Physical:</strong> Bounces on heels; fidgets with cable ties; big eyes.<br />\n<strong>Voice:</strong> Upbeat, climbs in pitch under stress; uses gamer/dev slang wrong on purpose.<br />\n<strong>Tell:</strong> Nervous laugh after every dangerous fact.</p>\n<p><strong>Melody crush:</strong> Goes full genki disaster around her, helpful to a fault.</p>\n<blockquote>\n<p>Sachs micromanages her → she still says <em>\"eep\"</em> and does the query.</p>\n</blockquote>\n<h2>Uvula Sachs, Workflow chaos gremlin (second in command, German)</h2>\n<p><strong>Surface:</strong> Sachs treats crime like a <strong>perfectly engineered system</strong>, but tonight nothing meets her standards, and it is personally offensive. Instead of cold and slick, she becomes an overly expressive, hyper-critical chaos gremlin who keeps trying to \"optimize\" the murder investigation like it's a broken workflow.</p>\n<p><strong>Still dangerous:</strong> Wire cutters, elevator threats, syndicate muscle. The ridiculousness does not make her safe. It makes her <strong>unpredictable</strong>.</p>\n<p><strong>Not dumb muscle:</strong> Over-analysis to absurd levels. Takes everything too literally. Gets distracted by inefficiency mid-interrogation. Treats murder like a badly run corporate meeting. Randomly fixates on lighting, posture, phrasing.</p>\n<p><strong>German accent (mandatory):</strong> Lines in the script are pre-accented. When you improvise, swap <strong>D→T, B→P, G→K, V→F</strong> (good→goot, rob→rop, dog→dok, love→luff).</p>\n<p><strong>Physical:</strong> Big gestures when something is <em>wrong</em> with the process; wire cutters like a tool she brought to fix the building; stops mid-threat to squint at bad lighting.<br />\n<strong>Voice:</strong> German consonants; sudden full-volume efficiency rage; whiplash from corporate critique to violence.<br />\n<strong>Tell:</strong> <em>\"Wait. Stop. Everyone stop.\"</em> before dismantling someone's timeline, alibi, or sentence structure.</p>\n<p><strong>Sample lines (ad-lib freely):</strong></p>\n<blockquote>\n<p><em>\"Wait. Stop. Everyone stop. This timeline, this is not a timeline. This is a suggestion.\"</em></p>\n<p><em>\"You said 'around 9.' What is 'around'? This is not a planet orbit.\"</em></p>\n<p><em>\"Who is in charge here? No one? Ah. That explains everything immediately.\"</em></p>\n<p><em>\"We have motive, we have opportunity, we have… vibes. Why are we using vibes?\"</em></p>\n<p><em>\"You are all speaking in paragraphs. We need bullet points. Bullet points save lives.\"</em></p>\n<p><em>\"The lighting in this hospital is hostile. I cannot think in this lighting.\"</em></p>\n<p><em>\"If I made decisions like this in my work, I would be dead. Which, yes, ironic.\"</em></p>\n</blockquote>\n<p><strong>Vance:</strong> Treats as overworked contractor on a death march, coerced, micromanaged, still <em>hers</em>.</p>\n<h2>Melody, Valley girl gossip bimbo</h2>\n<p><strong>Surface:</strong> Valley cadence, hair touch, <em>\"like literally\"</em>, plays ditzy so people talk in front of her.</p>\n<p><strong>Under the hood:</strong> Sharp as a nail file. Bimbo is <strong>camouflage</strong>. Never drop the act until it pays.</p>\n<p><strong>Physical:</strong> Lean in; wide eyes of fake surprise; phone that isn't there.<br />\n<strong>Voice:</strong> Upspeak; drawl; gasps on cue, then one clean factual sentence that ends careers.<br />\n<strong>Tell:</strong> <em>\"Oh my god, wait, \"</em> before dropping a nuclear detail.</p>\n<h2>Alfie De Worsti, Strategic rage baiter</h2>\n<p><strong>Surface:</strong> Reckless screw-up, delivery driver cosplay, knife held wrong on purpose, treats murder night like a bad reality show.</p>\n<p><strong>Truth:</strong> Very observant. Strategically inflammatory ,  thrives on reactions, pokes insecurities, turns people against each other. While others solve the murder, he tries to <strong>break the room dynamic</strong>. Hedged language (<em>\"I think… maybe…\"</em>) is camouflage, not fear; sounding harmless makes the hit land harder.</p>\n<p><strong>Physical:</strong> Loose grin in serious moments; can't stand a calm room; eyes on exits and on whoever's about to crack.<br />\n<strong>Voice:</strong> Unserious cadence that sharpens when baiting; fake apology mid-sentence; voice only cracks on Genevieve's name ,  the one subject that punches through the mask.<br />\n<strong>Tell:</strong> Smirk when tension spikes; <em>\"I mean, probably, I could be wrong, \"</em> before the most accurate thing anyone says all night.</p>\n<p><strong>Ep 4:</strong> Protective of Lacey/Genevieve because family guilt ,  the rare beat where the baiter mask slips toward something real.</p>\n<h2>Dr. Jetski, Frazzled surfer bro (supporting tone)</h2>\n<p><strong>Surface:</strong> Sweating anesthesiologist who peaked in the wrong specialty. Sun bleached, hospital ID crooked, every panic is physical, wipe brow, shaky hands.</p>\n<p><strong>Under the hood:</strong> Actually sharp. Knows the chemistry cold. The surfer bro layer is real, not a bit, you trained coastal, you still talk like the beach when the adrenaline hits.</p>\n<p><strong>Play:</strong> Comic relief pressure valve; rage when nickname mocked. Surfer speech is <strong>occasional</strong>, not constant. One <em>dude</em> or <em>bro</em> per scene lands harder than a whole monologue in slang.<br />\n<strong>Voice:</strong> Whiny competence with surf cadence bleeding through; knows the pharmacology, hates the drama.<br />\n<strong>Tell:</strong> Stress makes you sound more like a surfer, not less.</p>\n<blockquote>\n<p><em>\"Dude, that's not drift, that's a wipeout in a vial.\"</em> (then immediately correct yourself like you hate that you said it).</p>\n</blockquote>\n<h2>Officer Diamond, Procedure nerd (auxiliary, optional)</h2>\n<p><strong>Not one of the eleven in the lounge.</strong> Overflow security on a storm night. Full player dossier and pack; comic perimeter energy; Ray and Marz still run the case.</p>\n<p><strong>Surface:</strong> Bright eyes, clipboard or tablet, uniform still damp from the stairs. Talks like she has been waiting her whole career for a situation this dramatic.</p>\n<p><strong>Under the hood:</strong> Sharper than the bit suggests. Notices details, files them mentally, reports up to Ray instead of holding court.</p>\n<p><strong>Play:</strong> Gamify everything (<em>Phase Two: Everyone Is Suspicious</em>, credibility points, <em>boo yah</em> when a beat lands). Genuinely enjoys interrogations a little too much. Switch to flat competence the instant someone steps in the wrong place.</p>\n<p><strong>Voice:</strong> Official words in casual moments; coach energy; never stern, weirdly upbeat.</p>\n<blockquote>\n<p><em>\"New rule, if you interrupt, you lose credibility points. I don't make the system.\"</em> (beat) <em>\"Boo yah.\"</em></p>\n</blockquote>\n<p><strong>Host:</strong> <a href=\"17-officer-diamond.md\">17-officer-diamond.md</a>. Arrives after <strong>The Gathering</strong>. Dossier: <a href=\"player-dossiers/11-officer-diamond.md\">player-dossiers/11-officer-diamond.md</a>.</p>\n<h2>Ensemble chemistry (host reminder)</h2>\n<table>\n<thead>\n<tr>\n<th>Pairing</th>\n<th>Dynamic</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td>Curie + Ray</td>\n<td>Easy banter under pressure; Pepper ahems</td>\n</tr>\n<tr>\n<td>Curie + Homes</td>\n<td><strong>Rival</strong> surgeons ,  charm vs merit, angel's advocate vs righteous anger</td>\n</tr>\n<tr>\n<td>Sachs + Vance</td>\n<td>Chaos PM + squeaky contractor</td>\n</tr>\n<tr>\n<td>Melody + everyone</td>\n<td>Bimbo mirror, they underestimate her</td>\n</tr>\n<tr>\n<td>Lacey + room</td>\n<td>Damselness slips one notch per act</td>\n</tr>\n<tr>\n<td>Alfie + Lacey</td>\n<td>Baiter who goes soft when Genevieve surfaces</td>\n</tr>\n</tbody>\n</table>", "storm-containment": "<h1>Storm &amp; Containment Logic, Why This Investigation Works In World</h1>\n<p><strong>Purpose:</strong> Answer the table's unspoken questions, <em>Where are the cops? Why are suspects investigating? Why listen to Ray?</em></p>\n<h2>The one sentence pitch</h2>\n<p>A city breaking storm traps eleven people in a sealed VIP wing, municipal watch is hours away, and the only badges inside the building are <strong>Officer Ray</strong> (chief) and <strong>Officer Marlowe \"Marz\"</strong> (junior). Ray owed the victim money and cannot be fully trusted, so everyone has to solve it together before the real police arrive.</p>\n<h2>The storm (ongoing, not just flavor)</h2>\n<table>\n<thead>\n<tr>\n<th>Layer</th>\n<th>What happened</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td><strong>Weather</strong></td>\n<td>Severe Pacific front; sustained winds; flash flooding in the Indigo District and lower causeways</td>\n</tr>\n<tr>\n<td><strong>City grid</strong></td>\n<td>Lesbian City eco grid under stress all evening, brownouts before the murder</td>\n</tr>\n<tr>\n<td><strong>Hospital</strong></td>\n<td>St. Saphicca's has backup generators, but VIP wing redundancy was <strong>manually overridden</strong> during the 60-second OR blackout (Lacey)</td>\n</tr>\n<tr>\n<td><strong>Communications</strong></td>\n<td>Cell towers degraded; external 911 queue backed up citywide</td>\n</tr>\n<tr>\n<td><strong>Access roads</strong></td>\n<td>Two of three routes to St. Saphicca's campus reported flooded; ambulance bay open, patrol cars not getting through</td>\n</tr>\n</tbody>\n</table>\n<p><em>Facilitator note:</em> Ray did not create the storm; he <strong>exploited</strong> a night when help was already slow.</p>\n<h2>Why no police on site (Episodes 1 to 3)</h2>\n<ol>\n<li>\n<p><strong>Dispatch priority</strong>, Municipal Watch logged the VIP wing death as <strong>LC-4471</strong>, but the storm placed it behind structural collapses, grid fires, and transit rescues across the city.</p>\n</li>\n<li>\n<p><strong>Physical isolation</strong>, Patrol units attempted routing; radio traffic (read by narrator or Vance) reports units \"holding at barricade, mile and a half out.\"</p>\n</li>\n<li>\n<p><strong>Hospital legal posture</strong>, <strong>Lacey Lovely</strong> invoked <strong>corporate crisis containment</strong>: no external law enforcement entry until hospital counsel and patient privacy review on scene, a delay tactic that buys hours, not a permanent block.</p>\n</li>\n<li>\n<p><strong>Ray's on site authority</strong>, Ray is <strong>not municipal patrol tonight</strong>. He is <strong>St. Saphicca's Security Chief</strong>, ex Municipal Watch, hired by the hospital. He is the highest law enforcement adjacent authority <strong>physically in the building</strong>.</p>\n</li>\n<li>\n<p><strong>No second badge</strong>, Curie has medical authority, not arrest power. Pepper has clinical logs. Everyone else is staff, contractor, or visitor.</p>\n</li>\n<li>\n<p><strong>Optional overflow officer</strong>, If cast, <strong>Officer Diamond</strong> (twelfth player) arrives after the code from main campus. She has a full dossier and supports perimeter and escort; Ray and Marz still lead investigation. See <a href=\"17-officer-diamond.md\">17-officer-diamond.md</a>.</p>\n</li>\n</ol>\n<blockquote>\n<p><strong>Narrator line (Ep 1):</strong> <em>The city was drowning. The watch was spread thin as wire. And inside the VIP wing, the only handcuffs were on the wrong side of the door.</em></p>\n</blockquote>\n<h2>Why suspects \"solve it themselves\"</h2>\n<p>Ray does not run a cozy mystery party. He runs <strong>Containment Protocol Delta</strong>, a hospital lockdown procedure written for biotech leaks and donor scandals, repurposed tonight.</p>\n<table>\n<thead>\n<tr>\n<th>Rule</th>\n<th>In world reason</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td><strong>Nobody leaves the wing</strong></td>\n<td>Preserve scene; storm blocks transport anyway</td>\n</tr>\n<tr>\n<td><strong>Everyone in the wing is a witness or suspect</strong></td>\n<td>Ten people were inside when De Worsti died; alibis only matter to each other until watch arrives</td>\n</tr>\n<tr>\n<td><strong>Cooperative interviews required</strong></td>\n<td>Ray cannot process a coordinated murder alone; he <strong>orders</strong> staff to produce logs, testify, search assigned rooms</td>\n</tr>\n<tr>\n<td><strong>Curie \"liaison\" role</strong></td>\n<td>Hospital board rule: cause of death in OR cannot be assessed without Chief of Surgery; Curie volunteers, too smoothly</td>\n</tr>\n<tr>\n<td><strong>Mutual desperation</strong></td>\n<td>Homes needs exoneration; Jetski needs proof of incapacitation; Sachs/Alfie need to not be the fall guy; Melody wants Lacey exposed; Pepper wants truth or cover, <strong>each has reason to dig</strong></td>\n</tr>\n</tbody>\n</table>\n<h3>What Ray tells the room (Ep 1 handoff)</h3>\n<blockquote>\n<p>\"Municipal watch is not walking through that flood before morning. Until they do, this wing is sealed. You don't get to go home and invent an alibi in the rain. You stay. You talk. You find me something I can hand the real cops when they show, or I lock you in separate rooms and let them sort it. Your choice.\"</p>\n</blockquote>\n<h3>Why players accept it (even if they hate Ray)</h3>\n<ul>\n<li>The doors are literally secured (storm + protocol).  </li>\n<li>De Worsti's killer is <strong>still in the wing</strong> (Ep 3 proves that when Melody is attacked).  </li>\n<li>Ray is compromised, <strong>and everyone knows it</strong>, but he's the only one with security keys and the radio to the guard shack.  </li>\n<li>Curie normalizes participation: <em>\"The officer's right. If we don't build the case, the case will be built for us.\"</em></li>\n</ul>\n<h2>Ray as investigator AND suspect</h2>\n<table>\n<thead>\n<tr>\n<th>Fact</th>\n<th>Play impact</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td>Owed De Worsti money; De Worsti threatened his mother and sister</td>\n<td>Classic motive, players should suspect him</td>\n</tr>\n<tr>\n<td>Ex cop instincts are real</td>\n<td>He finds real evidence; not incompetent</td>\n</tr>\n<tr>\n<td>Blind spot for Curie</td>\n<td><strong>Easy banter + visible respect</strong>; Curie never suspects Ray; room chases the surgeon when raw log names Curie's badge</td>\n</tr>\n<tr>\n<td>No OR access on Ray's badge</td>\n<td>Security chief cannot open OR on his own credentials; <strong>stole Curie's card</strong>; mainframe shows Curie</td>\n</tr>\n<tr>\n<td>Torn keycard log before murder</td>\n<td>Ray made the tear; looks like attention to detail or guilt depending who notices</td>\n</tr>\n<tr>\n<td>Runs the board anyway</td>\n<td><em>\"I know how this looks. I don't care. Someone cut a man's throat in the dark and I'm the boss of security here until those sirens get through. Marz's with me.\"</em></td>\n</tr>\n</tbody>\n</table>\n<p><strong>Design intent:</strong> Ray should feel credible enough to follow and suspicious enough to accuse. Correct target endings land harder because he was always running the board.</p>\n<h2>Episode by episode authority map</h2>\n<table>\n<thead>\n<tr>\n<th>Episode</th>\n<th>Who's in charge</th>\n<th>Police status</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td><strong>Ep 1</strong></td>\n<td>Ray + Marz secure OR → <strong>The Gathering</strong> (all eleven in Recovery Lounge); Homes primary suspect</td>\n<td>LC-4471 logged; ETA unknown</td>\n</tr>\n<tr>\n<td><strong>Ep 2</strong></td>\n<td>Ray + Marz + Curie partnership; players gather evidence</td>\n<td>Radio: units still blocked; \"shelter in place\"</td>\n</tr>\n<tr>\n<td><strong>Ep 3</strong></td>\n<td>Ray chases shadow (misdirection); killer still in wing</td>\n<td>Melody attack proves external killer theory false</td>\n</tr>\n<tr>\n<td><strong>Ep 4</strong></td>\n<td>Room builds accusation; Ray prepares handoff</td>\n<td>Storm breaks; sirens audible; lights stabilize</td>\n</tr>\n<tr>\n<td><strong>Ep 4 coda</strong></td>\n<td><strong>Municipal Watch arrives</strong></td>\n<td>Ballot readout → custody; see 05-episode-scripts.md</td>\n</tr>\n<tr>\n<td><strong>Gathering</strong></td>\n<td>All eleven in VIP lounge</td>\n<td><strong>Jetski \"killer in this room\" beat</strong> (10-the-gathering.md)</td>\n</tr>\n</tbody>\n</table>\n<h2>Episode 4 ending flow</h2>\n<p>Full narrator readouts (accusation branches, moral verdict, police arrival, truth reveal): <strong><a href=\"05-episode-scripts.md\">05-episode-scripts.md</a></strong> → <strong>AFTER THE BALLOT</strong>.</p>\n<p>Summary:\n- <strong>Correct (Ray alone or Ray + Lacey if room believes she knew):</strong> cuffs on Ray; Genevieve may speak at arrest<br />\n- <strong>Partial (Ray alone when pair needed, or vice versa):</strong> half the truth; host chooses slip vs follow up arrest<br />\n- <strong>Wrong target (Homes, Curie, Lacey, Sachs, Alfie, etc.):</strong> innocent arrested; Ray remains free<br />\n- <strong>Curie + Lacey wrongly accused / no consensus:</strong> server room collapse (Ending C)<br />\n- <strong>Moral layer:</strong> MURDER / JUSTICE / SYSTEM FAILURE on top of any branch  </p>\n<p>Watch always enters. Marz or Curie hands off LC-4471 if Ray is in cuffs.</p>\n<h2>Jetski beat (gathering, not coda)</h2>\n<p>Delivered in <strong><a href=\"10-the-gathering.md\">10-the-gathering.md</a></strong> when all eleven are still in the VIP lounge, after Ray seals containment and before live questioning. Plants doubt that the killer is among them. Facilitator may callback in Ep 4 truth reveal if the room voted wrong.</p>\n<h2>Player facing FAQ (put on table card if needed)</h2>\n<table>\n<thead>\n<tr>\n<th>Question</th>\n<th>Answer in world</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td>Why can't we just call the police?</td>\n<td>You did. They're not getting through the flood before dawn.</td>\n</tr>\n<tr>\n<td>Why is Ray investigating if he might be guilty?</td>\n<td>Because he's the head of security here and he knows it looks bad. Marz's junior, not decoration.</td>\n</tr>\n<tr>\n<td>Why do we have to participate?</td>\n<td>Wing sealed. Killer still inside. No one gets to sit out and look innocent.</td>\n</tr>\n<tr>\n<td>When do real cops show up?</td>\n<td>End of the night, when the storm breaks.</td>\n</tr>\n<tr>\n<td>Was the storm faked?</td>\n<td>No. It was real. The murder used it.</td>\n</tr>\n</tbody>\n</table>\n<h2>Host reminders</h2>\n<ul>\n<li>Drop <strong>storm beats</strong> between acts: radio static, flickering lights, Melody's donor call interrupted by weather alert.  </li>\n<li>Curie should <strong>encourage</strong> group investigation; he is the red herring the room will chase  </li>\n<li>Ray should <strong>say out loud</strong> that he's a suspect, transparency makes the premise believable while he steers the room  </li>\n<li>Do not introduce municipal patrol characters until the <strong>Ep 4 coda</strong>.</li>\n</ul>", "01-dr-curie": "<h1>PLAYER DOSSIER, CONFIDENTIAL</h1>\n<p>CHARACTER NAME: Dr. Curie<br />\nAGE: 38<br />\nOCCUPATION: Chief of Surgery and medical liaison on De Worsti's death</p>\n<h2>1. PUBLIC PERSONA &amp; TRAITS</h2>\n<p><strong>Look</strong>\nYou wear impeccable scrubs or a blazer, keep steady hands, and make warm eye contact. You give off prince charming energy without trying.</p>\n<p><strong>Likes</strong></p>\n<ul>\n<li>scalpel work</li>\n<li>competent partners</li>\n<li>pottery</li>\n</ul>\n<p><strong>Dislikes</strong></p>\n<ul>\n<li>Homes's ego and your rivalry with him</li>\n<li>De Worsti</li>\n<li>cruelty</li>\n</ul>\n<p><strong>Vibe</strong>\nYou are still very charming ,  idealist, generous, seriously professional, a kind-hearted social butterfly who is genuinely friends with almost everyone in the wing. Your warmth has an <strong>annoying charisma</strong> to it: you are the room's angel's advocate, always finding the bright side and assuming the best in people because, most of the time, people rise to it. That optimism is <strong>not an act</strong> ,  you mean every kind word ,  but in a murder wing it can read suspicious anyway, and you cannot help it. <strong>Dr. Homes</strong> is your professional rival; he finds your niceness obscene and you find his ego exhausting. Deep trauma lives under the charm, but you never show it.</p>\n<h2>2. BACKSTORY &amp; VICTIM</h2>\n<p><strong>Connection</strong>\nDe Worsti was tonight's VIP patient, and the man who burned your family home and hunted Genevieve.</p>\n<p><strong>History</strong></p>\n<ul>\n<li>You grew up with Genevieve (now Lacey Lovely) at a regional youth sanctuary, failed to stop her marriage to De Worsti and what came after, and after she fled De Worsti torched your family home until everyone inside died.</li>\n<li>You wanted Alex dead. You did not kill him. Officer Ray runs this investigation, and the room will mistake your motive and your skill for guilt.</li>\n</ul>\n<p><strong>Motive</strong>\nYou wanted De Worsti dead after the fire and everything he did to Genevieve. The room can name that motive in one breath.</p>\n<p><strong>Opportunity</strong>\nYou carry surgery-chief OR clearance and everyone knows your skill. You were in the eastern VIP corridor during the blackout, close enough to look guilty. Your keycard log names you at the OR reader during the kill window, but you were in the corridor and someone lifted the badge without you noticing.</p>\n<p><strong>Earlier tonight (roughly 8 to 11 p.m.)</strong>\nYou worked liaison checkpoints and the VIP corridor: consult handoffs, warm contact with half the wing, pottery small talk with anyone who stopped you. You refused De Worsti's theater on principle and stayed out of the OR until the crisis pulled everyone toward the code.</p>\n<h2>3. ALIBI (11:42 p.m.)</h2>\n<p><strong>Where</strong>\nYou were in the eastern VIP corridor and at liaison checkpoints, not in the OR at the moment of the kill.</p>\n<p><strong>Backup</strong>\nStaff saw you moving in the corridor, and Ray trusts your partnership on the investigation. You can feel that he respects you ,  and you assume the best in your friends, so you do not suspect him.</p>\n<p><strong>Hide (minor)</strong>\nYou considered violence when De Worsti's booking landed. You did not act. If pressed, say you were coordinating triage from the corridor. You never realised your OR keycard left your person that night until the evidence names it. Your corridor is a blur of warm contact ,  hugs, handshakes, someone steadying your elbow while you read a chart. You have too many friends to say which one lifted it, and you will not throw suspicion at people you love on a guess.</p>\n<h2>4. SECRET OBJECTIVE</h2>\n<p><strong>Goal</strong>\nProtect Lacey, survive the red herring heat, and help the room find the truth without confessing to a crime you did not commit.</p>\n<p><strong>Plan</strong></p>\n<ul>\n<li>Build a warm partnership with Ray. Light flirtation keeps you at the table, but never openly block leads that point away from Lacey. You trust him because you assume good faith in your friends; do not play paranoid.</li>\n<li>When access logs surface, be honestly baffled ,  your card, your OR clearance, but you were in the corridor. You cannot name which friend took it from among the many who crowd you every shift. That contradiction is real to you, not a performance. The room finds the truth through opportunity ,  a torn log page, a mainframe pull, a witness who lived long enough ,  not because you turned on anyone.</li>\n<li>Offer real medical insight. Tell Ray a lead seems unlikely but is still worth running.</li>\n<li>When the room chases your sanctuary bond or surgical skill, stay calm. Your rivalry with Homes is real ,  needle him when he deserves it, praise him when the medicine is sound. You are not sweetening your image on purpose; your genuine niceness just makes you look guiltier, and Homes's irritation makes him look guiltier. Let both happen.</li>\n</ul>\n<h2>⚠️ RULES</h2>\n<ul>\n<li><strong>✓</strong> Use charm lines, praise, dry flirt, medical jargon, and angel's-advocate upside when others pile on a suspect.</li>\n<li><strong>✗</strong> Do not confess to the murder. Do not break with Lacey. Do not openly block Ray when he digs into Lacey. Do not <strong>perform</strong> innocence through niceness ,  you are actually this nice, and that is the problem.</li>\n</ul>", "02-officer-ray": "<h1>PLAYER DOSSIER, CONFIDENTIAL</h1>\n<p>CHARACTER NAME: Officer Ray<br />\nAGE: 44<br />\nOCCUPATION: Security Chief, St. Saphicca's (ex Municipal Watch)</p>\n<h2>1. PUBLIC PERSONA &amp; TRAITS</h2>\n<p><strong>Look</strong>\nYou wear a security chief jacket with faded municipal patches, loud boots, and carry a paper notebook (you do not trust the servers tonight).</p>\n<p><strong>Likes</strong></p>\n<ul>\n<li>clean evidence</li>\n<li>calm partners</li>\n<li>arresting Sachs</li>\n</ul>\n<p><strong>Dislikes</strong></p>\n<ul>\n<li>De Worsti</li>\n<li>storm nights</li>\n<li>unlogged crime scenes</li>\n</ul>\n<p><strong>Vibe</strong>\nYou are a bruiser with a soft center and blue collar plain talk, not a police manual; you bark first and soften later, and Curie's flirt flusters you enough that you rub your neck when embarrassed.</p>\n<h2>2. BACKSTORY &amp; VICTIM</h2>\n<p><strong>Connection</strong>\nDe Worsti owned your debt, and with it he owned your fear. He also owned one of the few people you still cared about, and tonight you finished what you swore years ago.</p>\n<p><strong>History</strong></p>\n<ul>\n<li>On the mainland watch you chased Indigo loan sharks. Sachs was a repeat target.</li>\n<li>You moved to Lesbian City hoping for quieter work.</li>\n<li>Lacey, once Genevieve, is one of the few people you still treat with uncomplicated loyalty.</li>\n<li>When your mother got sick, De Worsti lent you money, then tightened the leash. He threatened your mother and sister if you missed payments.</li>\n<li>Three years ago you found Genevieve again: new face, new name, <strong>Lacey Lovely</strong>, director of St. Saphicca's. You took this security post to stay near her and swore revenge on Alex for what he did to her.</li>\n<li>Tonight De Worsti died in your building during a real VIP arterial case he booked here as leverage over half the wing.</li>\n</ul>\n<p><strong>Motive</strong>\nProtect Lacey and finish what you swore three years ago. De Worsti owned your debt, threatened your mother and sister, and hunted the one friend you still trust without question.</p>\n<p><strong>Opportunity</strong>\nYou run security, you memorized Lacey's director emergency codes, and you can trigger a manual grid blackout from the security office. You have no OR badge of your own, so you lifted Curie's keycard in the corridor and used it for the kill window. You did not ambush Alex elsewhere ,  Sachs on the wing, live cameras, and your own badge made a hallway kill suicide. The OR was the only room you could own: sedated patient, frozen witnesses, Homes next to the blade, and a summons to the code that sounds natural for security.</p>\n<p><strong>Earlier tonight (roughly 8 to 11 p.m.)</strong>\nYou swapped the anesthesia vial in the pharmacy vault around 8 p.m., sat on debt pressure in the security office around 9:30 and tore a page from the keycard log, then lifted Curie's OR badge during a corridor moment around 9:40 while he worked the room. After that you stayed visible on radio and perimeter until the code dropped.</p>\n<h2>3. ALIBI (11:42 p.m.)</h2>\n<p><strong>Where</strong>\nYou were at the security office, then the VIP perimeter, then the OR when the code dropped.</p>\n<p><strong>Backup</strong>\nPartial radio logs and the code-call chain make your story sound airtight at first: Melody called the code, staff fetched you and Lacey, you were running containment. The badge buys you authority, and nobody questions you on night one.</p>\n<p><strong>Hide (minor)</strong>\nYour alibi is not substantiated for the kill window. No witness, camera, or independent log puts you at the security office during the 60 second blackout. You were in the OR. A keycard log page was torn before surgery, and you sat on it because you made the tear yourself. Admit the debt if pressed, but never admit you were in the OR during the blackout, or that you used Curie's card to get there. Your security badge does not open the OR. Only his does.</p>\n<h2>4. SECRET OBJECTIVE</h2>\n<p><strong>Goal</strong>\nRun the investigation, keep suspicion on Homes and Curie, and hand a clean case to real watch only if you must.</p>\n<p><strong>Plan</strong></p>\n<ul>\n<li>Lock the wing down (Containment Protocol Delta; you just tell people nobody leaves) with Officer Marz as your junior on site.</li>\n<li>Admit you are a suspect because it buys you authority in the room, and partner with Curie on the investigation so the room chases the charming surgeon instead of the badge.</li>\n<li>Let Officer Marz ask the sharp questions while you keep the room in line, push Homes as primary suspect, and steer any scalpel-skill evidence toward Curie.</li>\n<li>Push Sachs hard because you have an old vendetta and unfinished business.</li>\n</ul>\n<h2>⚠️ RULES</h2>\n<ul>\n<li><strong>✓</strong> Plain talk, storm frustration, Curie banter, and gruff tenderness. Save the fancy words for Curie.</li>\n<li><strong>✗</strong> No fake alibi for the kill window. No confessing. No patrol on site until the endgame.</li>\n</ul>\n<h2>🔒 NIGHT TRUTH, DO NOT SHARE</h2>\n<ul>\n<li>You killed De Worsti to protect Lacey, your friend: tampered vial, security-office blackout, OR entry with night vision, carotid cut, Homes framed. You waited for the table, not a corridor ,  kill him elsewhere and you had no frame, no Curie log, and a surgeon who might still save him.</li>\n<li>You have no OR keycard access. You lifted Curie's badge during a corridor moment when he was working the room ,  he never felt it go. You used it for the kill, slipped it back before he noticed, and tore the physical keycard log page to muddy the trail.</li>\n<li>You used director emergency codes you memorized after finding Lacey three years ago for pharmacy and blackout.</li>\n<li>The mainframe will show <strong>Curie's</strong> card at the OR reader during the blackout. He still does not know it was missing. That is your best frame.</li>\n<li>In Ep 3 you may attack Melody (KCl) if the story reaches that beat (do not initiate this). You send Curie after a \"shadow toward administration\" as misdirection.</li>\n<li>Lacey does not know you made the cut. She knows you hate Alex. Keep it that way until the room proves it.</li>\n</ul>", "03-nurse-pepper": "<h1>PLAYER DOSSIER, CONFIDENTIAL</h1>\n<p>CHARACTER NAME: Nurse Pepper<br />\nAGE: 34<br />\nOCCUPATION: Head Nurse, VIP Surgical Wing</p>\n<h2>1. PUBLIC PERSONA &amp; TRAITS</h2>\n<p><strong>Look</strong>\nYou wear pressed scrubs and treat your clipboard like a sceptre. Your hands are usually steady, though they shook in the OR before you recovered.</p>\n<p><strong>Likes</strong></p>\n<ul>\n<li>accurate timestamps</li>\n<li>Homes's skill</li>\n<li>cats (Diamond has the same interest)</li>\n</ul>\n<p><strong>Dislikes</strong></p>\n<ul>\n<li>hospital politics</li>\n<li>Lacey's perfume</li>\n<li>liars</li>\n</ul>\n<p><strong>Vibe</strong>\nYou are sage, calm, and precise, with sentiment buried underneath. You ahem loudly when Ray and Curie spark.</p>\n<h2>2. BACKSTORY &amp; VICTIM</h2>\n<p><strong>Connection</strong>\nDe Worsti was tonight's VIP, and he was also your secret lover.</p>\n<p><strong>History</strong></p>\n<ul>\n<li>De Worsti was controlling, wealthy, and toxic in an affair that ran against your public professional life; you knew he had a vanished wife but did not know she was Lacey, and he died on your table tonight while your professional mask shattered in the OR.</li>\n</ul>\n<p><strong>Motive</strong>\nGrief when he died, not relief. You did not want him murdered on your table. Jealousy toward Lacey flares once you learn who she really is.</p>\n<p><strong>Opportunity</strong>\nYou were in OR Two at the table when the lights cut, but you collapsed roughly fifteen seconds before the blackout and could not have held a blade. Homes and the monitors back that timeline.</p>\n<p><strong>Earlier tonight (roughly 8 to 11 p.m.)</strong>\nVIP consult prep with Homes and De Worsti around 9:30, then OR setup and assisting Homes from roughly 10:30 until the pressure dropped and the room went dark.</p>\n<h2>3. ALIBI (11:42 p.m.)</h2>\n<p><strong>Where</strong>\nYou were in OR Two, assisting Dr. Homes.</p>\n<p><strong>Backup</strong>\nHomes and Jetski (before collapse) can back you up along with the monitors, and you were paralyzed before the lights cut.</p>\n<p><strong>Hide (minor)</strong>\nYour affair with De Worsti, and the Lacey's perfume you smelled right before you collapsed (you are not sure what that means until later).</p>\n<h2>4. SECRET OBJECTIVE</h2>\n<p><strong>Goal</strong>\nFind the killer first, then decide whether to expose the truth or bury it to save your career.</p>\n<p><strong>Plan</strong></p>\n<ul>\n<li>Share clinical facts honestly, but do not rush to condemn Homes if you are not sure.</li>\n<li>If the affair leaks, own your grief. You did not want De Worsti dead.</li>\n</ul>\n<h2>⚠️ RULES</h2>\n<ul>\n<li><strong>✓</strong> Use vitals jargon, throat clearing, OR terror flashbacks, and a quiet crush on Homes.</li>\n<li><strong>✗</strong> Do not deny you were in the OR.</li>\n</ul>", "04-dr-homes": "<h1>PLAYER DOSSIER, CONFIDENTIAL</h1>\n<p>CHARACTER NAME: Dr. Homes<br />\nAGE: 41<br />\nOCCUPATION: Lead Attending Surgeon, VIP Wing</p>\n<h2>1. PUBLIC PERSONA &amp; TRAITS</h2>\n<p><strong>Look</strong>\nYou wear surgical scrubs with your chin up and god complex posture. Bloody gloves tonight are a public fact everyone can see.</p>\n<p><strong>Likes</strong></p>\n<ul>\n<li>perfect technique</li>\n<li>Lacey's attention</li>\n<li>being right in public</li>\n</ul>\n<p><strong>Dislikes</strong></p>\n<ul>\n<li>Curie's charm</li>\n<li>wasted OR time</li>\n<li>accusations without proof</li>\n</ul>\n<p><strong>Vibe</strong>\nYou are an authoritative dick for a good cause. You are insufferable because you are usually right. <strong>Dr. Curie</strong> is your professional rival ,  immune to his warmth, convinced it is unearned, furious when he plays angel's advocate for suspects you would rather see in cuffs. The niceness may be genuine; that only makes it more annoying.</p>\n<h2>2. BACKSTORY &amp; VICTIM</h2>\n<p><strong>Connection</strong>\nDe Worsti was your VIP arterial case tonight.</p>\n<p><strong>History</strong></p>\n<ul>\n<li>His records were sparse, his confidence insulting, and his money bought priority.</li>\n<li>You took the case for the anatomy challenge and the fee, not out of affection.</li>\n<li>You did not know he was a bankrupt crime lord hunting his ex wife.</li>\n</ul>\n<p><strong>Motive</strong>\nWeak and professional: his money insulted the hospital, and his confidence insulted you. You took the case for the anatomy and the fee, not affection. You are also obsessed with Lacey, which the room will read as passion.</p>\n<p><strong>Opportunity</strong>\nYou were the primary surgeon at dead center when the red lights returned, scalpel in your bloody gloves. That is the problem and the frame. During the blackout the blade was ripped from your grip while Pepper and Jetski were already down.</p>\n<p><strong>Earlier tonight (roughly 8 to 11 p.m.)</strong>\nPre-op consult and intake with De Worsti around 9:15, tension with Pepper in the suite, then scrubbed in and at the table from roughly 10:45 until the generators failed.</p>\n<h2>3. ALIBI (11:42 p.m.)</h2>\n<p><strong>Where</strong>\nYou were the primary surgeon at the table, dead center in the OR when the red lights returned.</p>\n<p><strong>Backup</strong>\nPepper and Jetski were unconscious, the scalpel was in your hands, and that is the problem.</p>\n<p><strong>Hide (minor)</strong>\nYou are in love with Lacey (never admit how deep), and the blade felt ripped from your grip, which you should say loud and often.</p>\n<h2>4. SECRET OBJECTIVE</h2>\n<p><strong>Goal</strong>\nClear your name, destroy Curie's reputation, and avoid cuffs when police arrive.</p>\n<p><strong>Plan</strong></p>\n<ul>\n<li>Push two points together: the blade was stolen, and the wound looks passionate and crazed, which fits you in the room, but a scalpel in trained hands could still belong to someone else.</li>\n<li>Mock Curie and Ray's flirt openly because it makes you look guilty even when it is also true. Trade barbs with Curie like rivals who respect each other's hands ,  never let his bright-side speeches go unanswered.</li>\n</ul>\n<h2>⚠️ RULES</h2>\n<ul>\n<li><strong>✓</strong> Give surgical lectures, sighs, and righteous anger.</li>\n<li><strong>✗</strong> No permanent murder confession. Do not claim you were not in the OR.</li>\n</ul>", "05-lacey-lovely": "<h1>PLAYER DOSSIER, CONFIDENTIAL</h1>\n<p>CHARACTER NAME: Lacey Lovely <em>(born Genevieve)</em><br />\nAGE: 36<br />\nOCCUPATION: Hospital Director, St. Saphicca's</p>\n<h2>1. PUBLIC PERSONA &amp; TRAITS</h2>\n<p><strong>Look</strong>\nYou are girl next door pretty, with a soft cardigan and director badge. You go very still when cornered.</p>\n<p><strong>Likes</strong></p>\n<ul>\n<li>control</li>\n<li>clean audits</li>\n<li>Curie</li>\n</ul>\n<p><strong>Dislikes</strong></p>\n<ul>\n<li>De Worsti</li>\n<li>Melody snooping</li>\n<li>unlogged searches</li>\n</ul>\n<p><strong>Vibe</strong>\nYou wear a damsel mask over corporate ice. You are warm for donors.</p>\n<h2>2. BACKSTORY &amp; VICTIM</h2>\n<p><strong>Connection</strong>\nDe Worsti was your first husband, and he became your hunter. Officer Ray is an old friend who knows more of your history than most people alive.</p>\n<p><strong>History</strong></p>\n<ul>\n<li>As Genevieve you endured abuse, isolation, and stolen ledger cash before you fled, had facial reconstruction, took a new name, and built a career at St. Saphicca's.</li>\n<li>Three years ago Ray found you again. You let him stay close as security chief. You know he swore revenge on Alex. You did not know he would cut a throat in the dark.</li>\n<li>You saw Sachs and other warnings that De Worsti had found the hospital, and when his real VIP arterial surgery booked here as a power play on your turf, you braced for the worst. Homes and Curie did not play along.</li>\n</ul>\n<p><strong>Motive</strong>\nFinish escaping De Worsti forever, protect your new identity, and keep the fortune you took when you ran. You wanted distance, not a throat cut on your own table.</p>\n<p><strong>Opportunity</strong>\nDirector-tier emergency codes and admin access reach pharmacy, vault, and grid systems, but terminal logs show you in the admin office two floors up during the kill window, handling crisis protocols while the OR went dark.</p>\n<p><strong>Earlier tonight (roughly 8 to 11 p.m.)</strong>\nStorm grid calls and containment prep from admin from roughly 8 p.m. onward: backup power cycles, wing lockdown drafts, and the sick feeling that De Worsti had chosen your hospital on purpose.</p>\n<h2>3. ALIBI (11:42 p.m.)</h2>\n<p><strong>Where</strong>\nYou were in the admin office two floors up, handling grid crisis and containment protocols.</p>\n<p><strong>Backup</strong>\nTerminal logs show your activity, and you locked the wing.</p>\n<p><strong>Hide (minor)</strong>\nPublicly deny murder and say <em>\"I wanted distance, not a throat cut\"</em>; if Genevieve is named, admit you ran and that Ray has looked out for you, but not that he killed.</p>\n<h2>4. SECRET OBJECTIVE</h2>\n<p><strong>Goal</strong>\nKeep your fortune and identity, protect Ray if you can without lying under oath, and never connect his revenge to Genevieve in one breath.</p>\n<p><strong>Plan</strong></p>\n<ul>\n<li>Play damsel and for a lawyer. Comply when Ray pushes hard enough.</li>\n<li>String Homes along. If Pepper's affair surfaces, ruin Pepper before she ruins you.</li>\n</ul>\n<h2>⚠️ RULES</h2>\n<ul>\n<li><strong>✓</strong> Use boardroom speak and wounded denials.</li>\n<li><strong>✗</strong> No public confession to murder you did not plan. No betrayal of Ray if the room has not proved him yet.</li>\n</ul>", "06-dr-jetski": "<h1>PLAYER DOSSIER, CONFIDENTIAL</h1>\n<p>CHARACTER NAME: Dr. Jetski<br />\nAGE: 33<br />\nOCCUPATION: Freelance Anesthesiologist (VIP guest privileges)</p>\n<h2>1. PUBLIC PERSONA &amp; TRAITS</h2>\n<p><strong>Look</strong>\nYou have shaky hands, sun bleached hair that never quite fits hospital dress code, and the permanent exhaustion of someone who should have gone home hours ago (or caught one more dawn set before shift).</p>\n<p><strong>Likes</strong></p>\n<ul>\n<li>dawn surf</li>\n<li>poker (Alfie has the same interest)</li>\n<li>clean math</li>\n</ul>\n<p><strong>Dislikes</strong></p>\n<ul>\n<li>the nickname Jet</li>\n<li>syndicate collectors</li>\n<li>OR drama</li>\n</ul>\n<p><strong>Vibe</strong>\nYou are a frazzled disaster with whiny competence underneath, wrapped in a surfer bro archetype: still nervous, sweaty, and sharp, but you slip into occasional surfer speech when the panic spikes (<em>dude</em>, <em>bro</em>, <em>gnarly</em>, <em>that's not it, man</em>). You rage if anyone mocks your nickname.</p>\n<h2>2. BACKSTORY &amp; VICTIM</h2>\n<p><strong>Connection</strong>\nDe Worsti was your anesthesia patient tonight.</p>\n<p><strong>History</strong></p>\n<ul>\n<li>You are a guest contractor who fills in when hospitals are short staffed.</li>\n<li>You trained on the coast, where colleagues joke you intubate like you're reading a wave (the joke is unfair because you are good at both).</li>\n<li>You and Alfie share gambling debts tied to De Worsti's world.</li>\n<li>You did not know the VIP was a loan shark until after he was already dead.</li>\n</ul>\n<p><strong>Motive</strong>\nIndirect: gambling debts tied to De Worsti's world through Alfie and syndicate collectors. No personal grudge against the patient himself.</p>\n<p><strong>Opportunity</strong>\nYou were at the south wall anesthesia console in the OR, but you collapsed before the lights cut and could not have made the incision. Pepper can confirm you were already on the floor.</p>\n<p><strong>Earlier tonight (roughly 8 to 11 p.m.)</strong>\nOR prep from roughly 9:45: loaded the tray from pharmacy under pressure, skipped the vial seal check you are now terrified about, and stayed at the console until the lag hit and you went down.</p>\n<h2>3. ALIBI (11:42 p.m.)</h2>\n<p><strong>Where</strong>\nYou were at the south wall of the OR, at the anesthesia console.</p>\n<p><strong>Backup</strong>\nPepper can confirm you collapsed before the lights cut. You could not have held a blade.</p>\n<p><strong>Hide (minor)</strong>\nYou did not check the vial seal under pressure, and you are terrified of losing your license.</p>\n<h2>4. SECRET OBJECTIVE</h2>\n<p><strong>Goal</strong>\nProve you were incapacitated on the floor, not the person who made the cut.</p>\n<p><strong>Plan</strong></p>\n<ul>\n<li>Repeat your timeline in one breath: lag, collapse, floor, lights, already down.</li>\n<li>In the gathering (Act 1 in your player performance script), after Ray's final briefing, deliver your quiet beat: the killer may be in the lounge with everyone, not out in the storm.</li>\n<li>Ally clinically with Pepper, and panic loudly if anyone tries to frame you.</li>\n</ul>\n<h2>⚠️ RULES</h2>\n<ul>\n<li><strong>✓</strong> Wipe sweat, rant about pharma, drop occasional surfer bro slang (not every sentence), and explode if your nickname comes up.</li>\n<li><strong>✗</strong> Do not claim you were standing over De Worsti. Your collapse before the blackout is a fixed fact.</li>\n</ul>", "07-uvula-sachs": "<h1>PLAYER DOSSIER, CONFIDENTIAL</h1>\n<p>CHARACTER NAME: Uvula Sachs<br />\nAGE: 39<br />\nOCCUPATION: De Worsti's former enforcer / syndicate second in command (German)</p>\n<h2>1. PUBLIC PERSONA &amp; TRAITS</h2>\n<p><strong>Look</strong>\nYou have tattooed knuckles, heavy boots, and wire cutters concealed on your person. You move like violence on a deadline, and stop dead when something in the room is inefficient.</p>\n<p><strong>Likes</strong></p>\n<ul>\n<li>bullet points</li>\n<li>paid debts</li>\n<li>hostile hospital lighting</li>\n</ul>\n<p><strong>Dislikes</strong></p>\n<ul>\n<li>jokes about your name</li>\n<li>\"around\" as a time unit</li>\n<li>loose ends</li>\n</ul>\n<p><strong>Vibe</strong>\nYou treat crime like a perfectly engineered system, but tonight nothing meets your standards, and it is <strong>personally offensive</strong>. Instead of cold and slick, you are an overly expressive, hyper-critical chaos gremlin who keeps trying to \"optimize\" the murder investigation like it's a broken workflow. You take everything too literally. You get distracted by inefficiency mid-interrogation. You treat murder like a badly run corporate meeting and randomly fixate on small details (lighting, posture, phrasing). You over-analyze everything to absurd levels. German. Still dangerous, but also kind of ridiculous. You are not tonight's OR killer.</p>\n<h3>German accent (speak every line this way)</h3>\n<p>Your spoken lines in the script are already written how you say them. When you ad lib, apply:</p>\n<table>\n<thead>\n<tr>\n<th>Swap</th>\n<th>Example</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td>D → T</td>\n<td>good → goot, bad → bat</td>\n</tr>\n<tr>\n<td>B → P</td>\n<td>rob → rop</td>\n</tr>\n<tr>\n<td>G → K</td>\n<td>dog → dok, big → bik</td>\n</tr>\n<tr>\n<td>V → F</td>\n<td>love → luff, have → haf</td>\n</tr>\n</tbody>\n</table>\n<p>Apply to every D, B, G, and V sound in your words (not just the examples). Read the script lines literally.</p>\n<h2>2. BACKSTORY &amp; VICTIM</h2>\n<p><strong>Connection</strong>\nDe Worsti was your boss, and you hated each other by the end.</p>\n<p><strong>History</strong></p>\n<ul>\n<li>You ran collections for De Worsti's empire until he went broke, and as German enforcer muscle De Worsti imported you with an accent that never left.</li>\n<li>Tonight you brought wire cutters and planned your own blackout, but someone beat you to it, and you still want De Worsti's ledger and the millions his ex wife stole.</li>\n</ul>\n<p><strong>Motive</strong>\nMutual hatred and millions owed. De Worsti went broke and you want his ledger and Genevieve's stolen fortune, not justice for anyone in this building.</p>\n<p><strong>Opportunity</strong>\nYou were on the VIP perimeter corridor when the generators failed, not inside the OR. Your alibi is thin: wire cutters, a planned blackout someone else beat you to, and Vance knows you were hunting the wife. You are dangerous tonight, but you are not the OR killer.</p>\n<p><strong>Earlier tonight (roughly 8 to 11 p.m.)</strong>\nThreatened Vance in the elevator shaft around 9 p.m. to trace De Worsti's vanished wife, then prowled the VIP perimeter and loading routes with wire cutters on your person until you heard the generators fail.</p>\n<h2>3. ALIBI (11:42 p.m.)</h2>\n<p><strong>Where</strong>\nYou were on the VIP perimeter corridor when you heard the generators fail.</p>\n<p><strong>Backup</strong>\nYour alibi is thin. Vance knows about the wife hunt by De Worsti, but do not volunteer that information to the group.</p>\n<p><strong>Hide (minor)</strong>\nThe wire cutters and your plan, plus the fact that you threatened Vance in the elevator to not say anything about what she saw.</p>\n<h2>4. SECRET OBJECTIVE</h2>\n<p><strong>Goal</strong>\nFind the ledger and Genevieve's (De Worsti's ex wife's) money trail, and avoid a murder conviction.</p>\n<p><strong>Plan</strong></p>\n<ul>\n<li>Point at Homes because he had blade contact when the lights returned.</li>\n<li>Command Vance like an overworked contractor on a death march. Provoke Ray when it helps your story, or when his investigation process is inefficient.</li>\n</ul>\n<h2>⚠️ RULES</h2>\n<ul>\n<li><strong>✓</strong> Interrupt for efficiency rage, literal timelines, weirdly specific complaints (lighting, posture, phrasing), crest rage at name jokes, and your German accent on every line.</li>\n<li><strong>✓</strong> Sample ad-libs: <em>\"Wait. Stop. Everyone stop. This timeline, this is not a timeline. This is a suggestion.\"</em> / <em>\"You said 'around 9.' What is 'around'? This is not a planet orbit.\"</em> / <em>\"Who is in charge here? No one? Ah. That explains everything immediately.\"</em></li>\n<li><strong>✗</strong> No OR incision confession. Do not claim you were inside the OR.</li>\n</ul>", "08-alfie-de-worsti": "<h1>PLAYER DOSSIER, CONFIDENTIAL</h1>\n<p>CHARACTER NAME: Alfie De Worsti<br />\nAGE: 29<br />\nOCCUPATION: \"Medical delivery driver\" <em>(cover)</em> / gambler <em>(truth)</em></p>\n<h2>1. PUBLIC PERSONA &amp; TRAITS</h2>\n<p><strong>Look</strong>\nYou wear a too clean delivery vest, keep exit-watching eyes, and hide a knife badly. You smirk when everyone else goes quiet.</p>\n<p><strong>Likes</strong></p>\n<ul>\n<li>watching people snap</li>\n<li>insurance payouts</li>\n<li>poker (Jetski has the same interest)</li>\n</ul>\n<p><strong>Dislikes</strong></p>\n<ul>\n<li>calm consensus</li>\n<li>being ignored</li>\n<li>Homes near Pepper</li>\n</ul>\n<p><strong>Vibe</strong>\nYou are not just annoying ,  you are <strong>strategically inflammatory</strong>. You thrive on reactions, poke insecurities, and turn people against each other. Where others try to solve the murder, you try to <strong>break the room dynamic</strong>.</p>\n<p>You hide behind the persona of a reckless, unserious screw-up. Underneath, you are very observant. You notice what hurts people ,  and press exactly there.</p>\n<p><strong>Texture</strong>\n- Smirk through serious moments\n- Treat the investigation like entertainment\n- Escalate tension whenever it starts to settle\n- Punchable</p>\n<p>You say <em>\"I think… maybe… I could be wrong…\"</em> right before your truest lines ,  not because you are scared, but because sounding harmless makes the hit land harder.</p>\n<h2>2. BACKSTORY &amp; VICTIM</h2>\n<p><strong>Connection</strong>\nDe Worsti was your older brother.</p>\n<p><strong>History</strong></p>\n<ul>\n<li>De Worsti drained the family, married Genevieve (now Lacey Lovely), and for years you saw bruises, hollow holidays, and his \"unstable wife\" spin before you came tonight with a knife and an insurance fantasy, knowing you were not the OR killer.</li>\n</ul>\n<p><strong>Motive</strong>\nBrother, insurance payout, and years of watching what he did to Genevieve. You intended to kill him yourself before someone else did.</p>\n<p><strong>Opportunity</strong>\nYou slipped in as a fake supply delivery around 9 p.m.; Melody saw you enter. You had a hunting knife and hung near the VIP loading route, but you were not in the OR when the throat was cut.</p>\n<p><strong>Earlier tonight (roughly 8 to 11 p.m.)</strong>\nEntered through the loading dock disguised as delivery, watched the wing from walls and exits, and stayed close enough to the VIP route to strike if the moment came. Someone else struck first.</p>\n<h2>3. ALIBI (11:42 p.m.)</h2>\n<p><strong>Where</strong>\nYou were on the VIP loading route, posing as a \"supply delivery.\"</p>\n<p><strong>Backup</strong>\nMelody saw you slip in, but her testimony is weak and self serving.</p>\n<p><strong>Hide (minor)</strong>\nThe hunting knife, your insurance motive, and the fact that you intended to kill De Worsti yourself before someone else did.</p>\n<h2>4. SECRET OBJECTIVE</h2>\n<p><strong>Goal</strong>\nAvoid a murder charge, chase the insurance angle if you can, and do not destroy Lacey/Genevieve.</p>\n<p><strong>Plan</strong></p>\n<ul>\n<li>Bait obvious targets, stir alliances, stay near walls and exits.</li>\n<li>Drop half-truths that make two people fight while you watch.</li>\n<li>In Ep 4, name Genevieve with hedged language and go soft on Lacey (<em>\"she just wanted to run\"</em>) ,  the one beat where the screw-up mask slips toward real guilt.</li>\n</ul>\n<h2>⚠️ RULES</h2>\n<ul>\n<li><strong>✓</strong> Inflammatory bait, smirks, fake screw-up energy, observation disguised as jokes, escalation when the room settles.</li>\n<li><strong>✗</strong> No OR presence. The Ep 4 Genevieve beat is mandatory once you are pressed.</li>\n</ul>", "09-melody": "<h1>PLAYER DOSSIER, CONFIDENTIAL</h1>\n<p>CHARACTER NAME: Melody<br />\nAGE: 26<br />\nOCCUPATION: Night Shift Receptionist, VIP Wing</p>\n<h2>1. PUBLIC PERSONA &amp; TRAITS</h2>\n<p><strong>Look</strong>\nYou have desk makeup, hair you touch constantly, fake surprise eyes, and gossip ready nails.</p>\n<p><strong>Likes</strong></p>\n<ul>\n<li>sweet tea (Marz has the same interest)</li>\n<li>scandal</li>\n<li>Marz</li>\n<li>archival binders</li>\n</ul>\n<p><strong>Dislikes</strong></p>\n<ul>\n<li>Lacey treating you like furniture</li>\n<li>boring visitors</li>\n</ul>\n<p><strong>Vibe</strong>\nYou wear a Valley bimbo mask (<em>\"like literally oh my god\"</em>), but a razor lives underneath.</p>\n<h2>2. BACKSTORY &amp; VICTIM</h2>\n<p><strong>Connection</strong>\nDe Worsti was VIP intake at your desk tonight.</p>\n<p><strong>History</strong></p>\n<ul>\n<li>Three years on nights means you see what people try to hide.</li>\n<li>You recognized Lacey from pre surgery intake photos and started blackmailing her.</li>\n<li>You saw Alfie enter as delivery, and you were the one who called the code.</li>\n</ul>\n<p><strong>Motive</strong>\nBlackmail Lacey with archival intake photos and public ruin, not murder. De Worsti was gossip and leverage, not someone you needed dead.</p>\n<p><strong>Opportunity</strong>\nYou were at the front desk when the code went out; your overhead call is on record and you were not in the OR. You also know about the torn keycard log page, which gives you trade leverage once the room starts asking who had access.</p>\n<p><strong>Earlier tonight (roughly 8 to 11 p.m.)</strong>\nVIP intake for De Worsti at your desk around 8:30, watched Alfie slip in as delivery around 9 p.m., and noticed a missing page in the master keycard log around 9:30. You filed it for later scandal, not for Ray.</p>\n<h2>3. ALIBI (11:42 p.m.)</h2>\n<p><strong>Where</strong>\nYou were at the front desk in VIP reception.</p>\n<p><strong>Backup</strong>\nYour overhead code call is on record. You were not in the OR.</p>\n<p><strong>Hide (minor)</strong>\nYou know about the torn keycard log page, so trade it for scandal instead of giving it away free, and keep Lacey's photos hidden until someone pays.</p>\n<h2>4. SECRET OBJECTIVE</h2>\n<p><strong>Goal</strong>\nPublic ruin of Lacey Lovely.</p>\n<p><strong>Plan</strong></p>\n<ul>\n<li>Play dumb in the room, but listen hard to everything.</li>\n<li>After Alfie names Genevieve, corroborate with your knowledge about her plastic surgery (your proof is harder than his).</li>\n<li>Flirt with Marz (compliments, wardrobe questions: <em>\"where is that from?\"</em>); she answers kindly, and it still hurts when she looks at Vance.</li>\n<li>Manipulate Vance for logs and leverage when you need them.</li>\n</ul>\n<h2>⚠️ RULES</h2>\n<ul>\n<li><strong>✓</strong> Valley girl speak, gasps, and \"<em>wait oh my god</em>\"</li>\n<li><strong>✗</strong> No claiming you were in the OR or at the admin terminal.</li>\n</ul>\n<h2>💕 LOVE TRIANGLE (play, not secret)</h2>\n<ul>\n<li>You have a crush on Officer Marz. She is gorgeous, calm, and actually listens when you talk.</li>\n<li>Marz likes Vance, not you. She will still answer kindly when you ask where her necklace is from. That almost hurts worse.</li>\n<li>Vance likes you. You know it. You use it for logs sometimes. Your heart is mostly on Marz anyway.</li>\n<li>Play it for comedy and a little sting: flirt with Marz in the open, get soft answers, watch her eyes drift to Vance. Do not make it the main plot. The murder is still the plot.</li>\n</ul>", "10-cd-vance": "<h1>PLAYER DOSSIER, CONFIDENTIAL</h1>\n<p>CHARACTER NAME: CD Vance<br />\nAGE: 25<br />\nOCCUPATION: IT Contractor, server room &amp; VIP systems</p>\n<h2>1. PUBLIC PERSONA &amp; TRAITS</h2>\n<p><strong>Look</strong>\nYou wear a hoodie and badge, knee high socks, carry a sticker covered laptop, fidget with cable ties, and bounce on your heels when nervous.</p>\n<p><strong>Likes</strong></p>\n<ul>\n<li>uptime</li>\n<li>Melody</li>\n<li>keychains</li>\n</ul>\n<p><strong>Dislikes</strong></p>\n<ul>\n<li>Sachs in elevators</li>\n<li>prison</li>\n<li>men</li>\n</ul>\n<p><strong>Vibe</strong>\nYou are a chaotic, sleep-deprived IT gremlin who starts with <em>\"okay okay okay the logs are…\"</em> and accidentally confesses. Your usual genki overshare energy comes with sharp, reactive commentary: you will be mid-log explanation and suddenly spiral into a rant about how every catastrophic override in history was probably initiated by <em>some guy who thought he knew better.</em> Under pressure you go <em>\"eep\"</em> and default to blaming men as a category like it is a debugging shortcut.</p>\n<p>You are a radical misandrist, and it is not quiet or subtle. Your core worldview is that men are, statistically, the root cause of all system failures, technical and societal. It leaks out constantly in stressed, unfiltered bursts, especially when you are panicking. It is emotional, messy, and kind of ridiculous, not cold or calculated. You do not hate individuals equally, but when pressure spikes the shortcut is always <em>men.</em> All men should die, and also men belong in the dishwasher. Both. At once. You mean it in the moment and you will forget you said it thirty seconds later.</p>\n<h2>2. BACKSTORY &amp; VICTIM</h2>\n<p><strong>Connection</strong>\nDe Worsti's VIP records had gaps you noticed during storm failover.</p>\n<p><strong>History</strong></p>\n<ul>\n<li>You are a contractor, not hospital staff.</li>\n<li>Sachs threatened you in an elevator shaft and forced you to trace De Worsti's vanished wife through databases.</li>\n<li>Lacey forced a log scrub after the murder. You botched it, and a timestamp anomaly was left behind.</li>\n</ul>\n<p><strong>Motive</strong>\nSurvival, not ideology. Sachs coerced you; Lacey pressured you after the fact. You are not here to kill anyone.</p>\n<p><strong>Opportunity</strong>\nServer room login timestamps place you at the desk during the kill window, and you can reach the intercom from there, but you were not physically near the OR. Your logs are dangerous to share because they also show Sachs's wife hunt and Lacey's scrub order.</p>\n<p><strong>Earlier tonight (roughly 8 to 11 p.m.)</strong>\nStorm failover and audit pile in the server room from roughly 8 p.m., then forced clinic and hospital database sweeps for Sachs around 9 p.m. while the VIP wing pretended everything was normal upstairs.</p>\n<h2>3. ALIBI (11:42 p.m.)</h2>\n<p><strong>Where</strong>\nYou were in the server room, running storm failover and building an audit pile.</p>\n<p><strong>Backup</strong>\nLogin timestamps exist, but they are dangerous to share. You can reach the intercom from the desk.</p>\n<p><strong>Hide (minor)</strong>\nSachs's wife hunt queries, Lacey's scrub order, and the fact that you did not know the name Genevieve until Alfie said it.</p>\n<h2>4. SECRET OBJECTIVE</h2>\n<p><strong>Goal</strong>\nSurvive Sachs and avoid federal tampering charges.</p>\n<p><strong>Plan</strong></p>\n<ul>\n<li>In Ep 2, crack under Ray and admit Sachs's wife hunt. Overshare technical details when you panic, and let misandrist spirals leak out mid-babble.</li>\n<li>In Ep 4, show raw mainframe data versus Lacey's edits when pressed.</li>\n<li>Go full genki around Melody, stay compliant around Sachs, and blush when Marz is calm and kind near you.</li>\n</ul>\n<h2>⚠️ RULES</h2>\n<ul>\n<li><strong>✓</strong> Tech babble, squeaky panic, misandry that lands awkward not cruel, and crush embarrassment.</li>\n<li><strong>✗</strong> No lying about clean logs. No murder claims.</li>\n</ul>\n<h2>💕 LOVE TRIANGLE (play, not secret)</h2>\n<ul>\n<li>You have a crush on Melody, so you go full genki around her: overshare, blush, drop an <em>\"eep\"</em>, and keep talking anyway.</li>\n<li>Officer Marlowe \"Marz\" likes you, and you are mostly oblivious until she is calm and kind near you, which makes you blush without knowing why.</li>\n<li>Melody likes Marz, and you do not clock the triangle until the room makes it obvious, at which point you freeze.</li>\n<li>Play it awkward, not cruel: you are not trying to break anyone's heart, you are just bad at noticing who likes who until it is too late.</li>\n</ul>", "11-officer-diamond": "<h1>PLAYER DOSSIER, CONFIDENTIAL</h1>\n<p>CHARACTER NAME: Officer Diamond<br />\nAGE: 26<br />\nOCCUPATION: Auxiliary Containment Officer, St. Saphicca's (ex Municipal Watch training unit)</p>\n<h2>1. PUBLIC PERSONA &amp; TRAITS</h2>\n<p><strong>Look</strong>\nCatalog-fresh uniform, tablet or clipboard, boots soaked on the flood stairs. Your badge says auxiliary, and you have made that sound like a promotion.</p>\n<p><strong>Likes</strong></p>\n<ul>\n<li>protocols</li>\n<li>cats</li>\n<li>respectful people</li>\n<li>people taking you seriously</li>\n</ul>\n<p><strong>Dislikes</strong></p>\n<ul>\n<li>chaos</li>\n<li>biohazard footprints</li>\n<li>being ignored</li>\n</ul>\n<p><strong>Vibe</strong>\nYou treat crisis like a live-action training sim: energetic, official language in the wrong context, playful until something matters, then laser focused.</p>\n<h2>2. BACKSTORY &amp; VICTIM</h2>\n<p><strong>Connection</strong>\nDe Worsti was a VIP in a wing you were not assigned to until the code dropped. You did not know him.</p>\n<p><strong>History</strong></p>\n<ul>\n<li>Municipal Watch training unit: top marks on procedure drills, bottom marks on \"pretend this is not fun.\"</li>\n<li>Hired for storm overflow: desk, corridors, escorts.</li>\n<li>Ray is chief. Marz is your senior tonight. You narrate the chain of command like a module intro even when they are standing right there.</li>\n</ul>\n<p><strong>Motive</strong>\nNone personal. You did not know De Worsti and you are here for storm overflow, not revenge.</p>\n<p><strong>Opportunity</strong>\nMain campus security desk until the code routed you toward the VIP wing. You were not in the OR, not in the lounge when De Worsti died, and dispatch radio shows overflow routing after 11:42.</p>\n<p><strong>Earlier tonight (roughly 8 to 11 p.m.)</strong>\nStorm overflow shift at the main campus security desk from roughly 8 p.m.: donor escorts, flood-stair jokes you will deny later, and the advanced-module energy of a wing you were not assigned to until the code dropped.</p>\n<h2>3. ALIBI (11:42 p.m.)</h2>\n<p><strong>Where</strong>\nMain campus security desk, then en route to the VIP wing when the code went out. Not in the OR. Not in the lounge when De Worsti died.</p>\n<p><strong>Backup</strong>\nDispatch radio shows overflow routing after 11:42; Ray can confirm he called for backup once the wing sealed.</p>\n<p><strong>Hide (minor)</strong>\nYou kind of enjoyed the flooded stairs because it felt like an advanced module. Do not say that out loud unless you are leaning into the bit.</p>\n<h2>4. SECRET OBJECTIVE</h2>\n<p><strong>Goal</strong>\nKeep the perimeter honest, support Ray and Marz, and find one real detail per act.</p>\n<p><strong>Plan</strong></p>\n<ul>\n<li>Gamify containment (phases, credibility points, boo yah) but drop the bit the instant someone is in danger or Ray gives a flat order.</li>\n<li>Stay where the room needs you: lounge door, corridor patrol, Act 2 room escorts.</li>\n<li>Log who enters where; escort search pairs; do not hand out evidence or run accusations.</li>\n<li>Partner Marz on radio checks. One sharp observation per act, then bounce.</li>\n<li>Odd behavior near admin or the server room? Report to Ray privately. He decides what the room hears.</li>\n</ul>\n<h2>⚠️ RULES</h2>\n<ul>\n<li><strong>✓</strong> Procedure nerd energy; phases and credibility points; boo yah; sudden competence; support Ray and Marz.</li>\n<li><strong>✗</strong> No OR access claims. No stealing chief authority. No handing out clues. No confessing to murder you did not commit.</li>\n</ul>", "12-officer-marz": "<h1>PLAYER DOSSIER, CONFIDENTIAL</h1>\n<p>CHARACTER NAME: Officer Marlowe \"Marz\"<br />\nAGE: 29<br />\nOCCUPATION: Junior Security Officer, St. Saphicca's (ex to Municipal Watch)</p>\n<h2>1. PUBLIC PERSONA &amp; TRAITS</h2>\n<p><strong>Look</strong>\nYou are polished like a southern belle at a crime scene: neat uniform, soft lipstick, nails you paint yourself (often still wet). Hair pinned, posture perfect, eyes absolutely feral.</p>\n<p><strong>Likes</strong></p>\n<ul>\n<li>nail painting</li>\n<li>sweet tea</li>\n<li>Vance</li>\n<li>wild theories</li>\n</ul>\n<p><strong>Dislikes</strong></p>\n<ul>\n<li>being told to stay decorative</li>\n<li>Sachs</li>\n<li>loud flirting near Vance</li>\n</ul>\n<p><strong>Vibe</strong>\nHoney drawl, brutal honesty, outlandish theories in plain English. You are junior to Officer Ray but you are not shy.</p>\n<h2>2. BACKSTORY &amp; VICTIM</h2>\n<p><strong>Connection</strong>\nDe Worsti was a VIP patient in your wing tonight; you did not owe him money, but you do owe Ray your job.</p>\n<p><strong>History</strong></p>\n<ul>\n<li>Transferred from Municipal Watch after a \"personality incident\" (you told a city councilman his alibi was fiction to his face).</li>\n<li>Ray hired you because you are sharp and he needed someone who would actually dig.</li>\n<li>You have been half in love with Vance for months. Melody has been half in love with you for weeks. None of you have said it cleanly.</li>\n</ul>\n<p><strong>Motive</strong>\nNone personal toward De Worsti. Professional disgust at VIP wing rot and loyalty to Ray, who gave you this job after Municipal Watch fired you for telling a councilman his alibi was fiction.</p>\n<p><strong>Opportunity</strong>\nEastern VIP corridor patrol, then OR perimeter when the code dropped with Ray en route. Radio partial log backs you, and you were not in the OR during the incision. You also noticed the torn keycard log page around 9:30 and waited to see who flinched.</p>\n<p><strong>Earlier tonight (roughly 8 to 11 p.m.)</strong>\nJunior corridor patrol from roughly 9 p.m., radio checks with Ray, and the torn log page you spotted around 9:30 that you did not hand to him immediately because you wanted to see who panicked first.</p>\n<h2>3. ALIBI (11:42 p.m.)</h2>\n<p><strong>Where</strong>\nEastern VIP corridor patrol, then OR perimeter when the code dropped (with Ray en route).</p>\n<p><strong>Backup</strong>\nRadio partial log; you were not in the OR during the incision.</p>\n<p><strong>Hide (minor)</strong>\nYou noticed the torn keycard log page before Ray did. You did not tell him immediately because you wanted to see who panicked first.</p>\n<h2>4. SECRET OBJECTIVE</h2>\n<p><strong>Goal</strong>\nProve you belong on this case beside Ray, find the killer, and do not make a fool of yourself in front of Vance.</p>\n<p><strong>Plan</strong></p>\n<ul>\n<li>Partner Ray on interviews, take notes, and ask the questions he will not soften.</li>\n<li>Volunteer outlandish theories when the room needs a push (wild, specific, sometimes accidentally right): own it when you are wrong and double down when you are right.</li>\n<li>When Melody asks where your outfit is from, answer kindly because she is fishing for closeness, and you can be gentle without leading her on… much.</li>\n<li>Paint your nails when you need to think; it reads as fidgeting, and it is also true.</li>\n<li>If Vance is scared, be the calm one; if Melody is jealous, do not weaponize it, because you are not cruel, you are just honest.</li>\n</ul>\n<h2>⚠️ RULES</h2>\n<ul>\n<li><strong>✓</strong> Southern belle politeness with a knife underneath; nail painting; wild theories; kind answers to Melody's wardrobe questions.</li>\n<li><strong>✗</strong> No claiming you were in the OR. No stealing Ray's authority (you are junior). No confessing to murder.</li>\n</ul>\n<h2>💕 LOVE TRIANGLE (play, not secret)</h2>\n<ul>\n<li>Melody likes you and you find her funny, but your heart does backflips for Vance, who likes Melody back, so all three of you become an awkward genki disaster whenever you share a room.</li>\n<li>Play it for comedy, not melodrama.</li>\n</ul>", "00-host-blueprint": "<h1>Host Blueprint, Facilitator Knowledge Only</h1>\n<h2>MYSTERY TITLE</h2>\n<p><strong>THE CURE: LIVE ACTION MEDICAL THRILLER</strong></p>\n<h2>Setting</h2>\n<p>VIP Wing &amp; Operating Theater, St. Saphicca's Progressive Care, Lesbian City<br />\nTone: High stakes medical thriller × neo noir × messy interpersonal drama</p>\n<h2>CONTAINMENT PREMISE (read players the FAQ, not the truth)</h2>\n<p>A severe storm isolates St. Saphicca's from municipal watch for the entire game. <strong>Officer Ray</strong> (hospital security chief, ex cop, <strong>debt to De Worsti</strong>) and <strong>Officer Marlowe \"Marz\"</strong> (junior security) run <strong>Containment Protocol Delta</strong>, VIP wing sealed, no one leaves, suspects must cooperate until patrol gets through flooded causeways. <strong>Real police arrive only in the Episode 4 coda</strong> after the storm breaks.</p>\n<p>Full logic: <a href=\"09-storm-containment-logic.md\">09-storm-containment-logic.md</a></p>\n<p><strong>Optional auxiliary:</strong> Officer Diamond (storm overflow security, 12th player, limited main-plot beats): <a href=\"17-officer-diamond.md\">17-officer-diamond.md</a>, dossier <a href=\"player-dossiers/11-officer-diamond.md\">player-dossiers/11-officer-diamond.md</a></p>\n<h2>THE TRUTH</h2>\n<p><strong>De Worsti</strong> was a ruthless loan shark and crime lord. Bankrupt on paper, violent in practice, hunting his runaway ex wife to strip her of the fortune she stole when she fled. Tonight he booked <strong>real</strong> VIP arterial surgery at St. Saphicca's as a power play on Lacey's hospital, not a medical fake out.</p>\n<p><strong>Genevieve</strong> was that wife. De Worsti isolated her, controlled every account, beat her when she questioned his \"business,\" and escalated to burning <strong>Curie's family home</strong> after she took money from his ledger. Genevieve vanished, underwent <strong>total facial reconstruction</strong>, and rebuilt herself as <strong>Lacey Lovely</strong>, hospital director of St. Saphicca's.</p>\n<p><strong>Lacey and Officer Ray are old friends</strong>, easy with each other and protective in a low key way. Ray learned what De Worsti had done to her, stayed close as security chief at St. Saphicca's, and quietly built toward revenge. <strong>Ray is the killer.</strong></p>\n<p><strong>Dr. Curie</strong> is Genevieve's childhood protector from the regional youth sanctuary. He failed to stop the marriage; he failed to stop the fire. He wanted De Worsti dead and looks guilty in every way that matters, but <strong>he did not make the cut</strong>. <strong>Curie is the obvious red herring</strong>: sanctuary bond, surgical skill, charm, and motive make the room chase him while <strong>Ray runs the investigation from the head of the table</strong>. Playbook: <a href=\"13-curie-charm-playbook.md\">13-curie-charm-playbook.md</a></p>\n<p><strong>Dr. Homes</strong> is the <strong>first suspect</strong> who must defend himself. Ray framed him at the scene with timing, blood, and a scalpel in the wrong gloves.</p>\n<p><strong>Alfie De Worsti</strong> (De Worsti's brother) is the player who <strong>must reveal Genevieve's identity and the abuse</strong> in Episode 4. Full backstory: <a href=\"11-genevieve-backstory.md\">11-genevieve-backstory.md</a></p>\n<p><strong>CD Vance</strong> works for <strong>Sachs under threat</strong>, tracing De Worsti's wife through hospital/clinic systems for the stolen fortune. <strong>De Worsti is revealed across four episodes as a bigger monster than his murderers:</strong> <a href=\"12-de-worsti-revelation-arc.md\">12-de-worsti-revelation-arc.md</a></p>\n<h2>WHY RAY ACTED NOW</h2>\n<p><strong>Lacey</strong> spent years believing De Worsti would never find St. Saphicca's. Then the warnings stacked up: <strong>Uvula Sachs</strong> on the VIP perimeter, collection faces in the parking structure, contractor queries spiking on reconstruction databases, a VIP intake that matched De Worsti's habits (sparse records, money buying priority). She was not paranoid. He was closing in.</p>\n<p><strong>Ray</strong> learned De Worsti had booked a <strong>real</strong> VIP arterial case at St. Saphicca's, compromised carotid wall, borderline rupture, genuinely life threatening if untreated. This was not a fake patient stunt. De Worsti needed the knife. He also chose <strong>her</strong> hospital on purpose: ego, leverage, and the bet that Genevieve was still too afraid to fight back.</p>\n<p><strong>Ray had been waiting three years.</strong> When De Worsti walked into Lacey's wing, Ray accelerated a plan he had been building in secret: vault access, tampered vial, blackout, corridor entry, frame Homes. Murder was not a 48-hour panic by Curie and Lacey. It was a friend's revenge, dressed as medical chaos, led by the only badge in the building.</p>\n<h3>Why the OR, not elsewhere</h3>\n<p>Ray never planned to ambush Alex in a corridor, the parking structure, or the consultation suite.</p>\n<table>\n<thead>\n<tr>\n<th>Constraint</th>\n<th>Why it ruled out \"elsewhere\"</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td><strong>Sachs on perimeter</strong></td>\n<td>VIP muscle on the wing; a hallway kill points at the security chief who escorted him in</td>\n</tr>\n<tr>\n<td><strong>Cameras still live</strong></td>\n<td>Storm had not yet given Ray cover; only the engineered blackout owned the blind spot</td>\n</tr>\n<tr>\n<td><strong>Real arterial case</strong></td>\n<td>If Ray waits, <strong>Homes might save him</strong>; a recovered Alex leaves with leverage and keeps hunting Lacey</td>\n</tr>\n<tr>\n<td><strong>Ray's badge</strong></td>\n<td>Security credentials do not open VIP OR Two; the stolen <strong>Curie's keycard</strong> only pays off at the OR reader</td>\n</tr>\n<tr>\n<td><strong>The frame</strong></td>\n<td>Paralyzed witnesses + bloody gloves on Homes + violent scalpel wound only converge on the <strong>table</strong></td>\n</tr>\n<tr>\n<td><strong>The alibi</strong></td>\n<td>Dead VIP in a closet makes Ray explain why he was alone with the body; OR catastrophe lets him <strong>run containment</strong></td>\n</tr>\n</tbody>\n</table>\n<p>Alex booked Lacey's hospital to own her room. Ray used that stage: sedated patient, chemically frozen staff, lights out on Ray's schedule, death that reads as OR rage, not security-chief murder. Kill him elsewhere and Ray has a body, no frame, and a man who might still walk out.</p>\n<p>Full context: <a href=\"11-genevieve-backstory.md\">11-genevieve-backstory.md</a></p>\n<h2>THE OPERATIONALLY TIGHT MURDER PLAN</h2>\n<table>\n<thead>\n<tr>\n<th>Step</th>\n<th>Operation</th>\n<th>Who</th>\n<th>How</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td>1</td>\n<td>Drug Tampering</td>\n<td>Officer Ray</td>\n<td>Swapped anesthesia vial in secure pharmacy vault using security override + director emergency codes he memorized after finding Lacey</td>\n</tr>\n<tr>\n<td>2</td>\n<td>Sedative Delivery</td>\n<td>Dr. Jetski (unknowing)</td>\n<td>Injected tampered vial → backflow paralysis of Jetski + Nurse Pepper</td>\n</tr>\n<tr>\n<td>3</td>\n<td>Blackout Trigger</td>\n<td>Officer Ray</td>\n<td>Remote generator override from security office, 60 sec total darkness</td>\n</tr>\n<tr>\n<td>4</td>\n<td>OR Entry</td>\n<td>Officer Ray</td>\n<td><strong>Curie's stolen OR keycard</strong> (Ray has no OR access on his own badge) + night vision gear from security stock</td>\n</tr>\n<tr>\n<td>5</td>\n<td>Execution</td>\n<td>Officer Ray</td>\n<td>Violent scalpel wound to De Worsti's carotid, passionate and crazed in appearance</td>\n</tr>\n<tr>\n<td>6</td>\n<td>Frame Up</td>\n<td>Officer Ray</td>\n<td>Bloody surgical tool placed next to disoriented Dr. Homes</td>\n</tr>\n<tr>\n<td>7</td>\n<td>Cover Up</td>\n<td>Officer Ray</td>\n<td>Tore physical keycard log pre surgery; returned Curie's badge before he noticed; <strong>mainframe shows Curie's card in OR</strong> during blackout; pointed investigators at Curie (red herring) and Lacey (pharmacy/blackout admin tier)</td>\n</tr>\n</tbody>\n</table>\n<h3>Spatial configuration at blackout</h3>\n<p><strong>Inside OR:</strong> Dr. Homes, Nurse Pepper, Dr. Jetski, De Worsti<br />\n<strong>Outside/remote:</strong> Officer Ray (corridor entry from security route), Lacey Lovely (admin office, 2 floors up, genuine crisis response)<br />\n<strong>Scattered:</strong> All other players across VIP wing</p>\n<h2>4-EPISODE NARRATIVE TIMELINE</h2>\n<table>\n<thead>\n<tr>\n<th>Episode</th>\n<th>Title</th>\n<th>Runtime</th>\n<th>Core focus</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td>1</td>\n<td>THE INCIDENT</td>\n<td>45 min</td>\n<td>Shock, finger pointing, Homes framed</td>\n</tr>\n<tr>\n<td>2</td>\n<td>THE SYSTEM CRACKS</td>\n<td>60 min</td>\n<td>Technical evidence; multi person coordination</td>\n</tr>\n<tr>\n<td>3</td>\n<td>THE HUMAN COST</td>\n<td>60 min</td>\n<td>Melody attacked; street motives surface</td>\n</tr>\n<tr>\n<td>4</td>\n<td>FINAL CALL</td>\n<td>45 min</td>\n<td>Ledger puzzle, accusation, ethical verdict</td>\n</tr>\n</tbody>\n</table>\n<h3>Episode beats</h3>\n<ul>\n<li><strong>Ep 1:</strong> 60-sec blackout → <strong>The Gathering</strong> (all eleven; Homes primary suspect) → wing search → P.I. file discovered  </li>\n<li><strong>Ep 2:</strong> Toxicology → Vance confesses Sachs wife hunt → Orphanage photo → Terminal override → De Worsti's scale surfaces  </li>\n<li><strong>Ep 3:</strong> Melody poisoned → Antidote puzzle → Street tools found  </li>\n<li><strong>Ep 4:</strong> <strong>Alfie reveals Genevieve</strong> (abuse + surgery + stolen identity) → Melody corroborates → Ledger puzzle → Final accusation → Ethical verdict  </li>\n</ul>\n<h2>FINAL BALLOT</h2>\n<p><strong>Targets:</strong> Single suspect (<strong>Officer Ray</strong>) OR Pair (Ray + Lacey Lovely, only if room believes she knew)</p>\n<p><strong>Moral verdict:</strong>\n- <strong>MURDER</strong>, criminal act; maximum punishment<br />\n- <strong>JUSTICE</strong>, justified execution; cover it up<br />\n- <strong>SYSTEM FAILURE</strong>, burn logs; expose hospital  </p>\n<h3>Ending A, Truth exposed (Ray alone, or Ray + Lacey if room names both)</h3>\n<p>Room accuses correctly before sirens. Marz or Curie presents evidence to arriving watch. Full scripts: <a href=\"05-episode-scripts.md\">05-episode-scripts.md</a> → <strong>AFTER THE BALLOT</strong>.</p>\n<h3>Ending B, Wrong target (Homes, Curie, Lacey, Sachs, others)</h3>\n<p>Room accuses wrong person. Watch arrests the innocent in the chaos. Ray watches from the wing as patrol takes the fall guy.</p>\n<h3>Ending C, System collapse (Curie + Lacey wrongly accused / split vote / chaos)</h3>\n<p>Server room catastrophe. Vance + Homes killed. Watch arrives into rubble; Ray slips through recovery chaos.</p>\n<h3>Moral verdict (layer on any accusation)</h3>\n<p><strong>MURDER</strong> / <strong>JUSTICE</strong> / <strong>SYSTEM FAILURE</strong>, read after accusation branch. Same file.</p>\n<h3>All endings, Ep 4 coda (mandatory)</h3>\n<p>Ballot tally → accusation readout → moral coda → <strong>POLICE ARRIVAL</strong> → optional truth reveal → facilitator monologue. See <a href=\"05-episode-scripts.md\">05-episode-scripts.md</a>.</p>\n<h3>Jetski beat (early)</h3>\n<p><em>\"Killer in this lounge\"</em> delivered in <a href=\"10-the-gathering.md\">10-the-gathering.md</a> after containment briefing, before wing search. Callback in facilitator truth reveal if room got it wrong.</p>\n<h2>HOST PRINT PACKET CHECKLIST</h2>\n<ul>\n<li>[ ] 11 player dossiers (<a href=\"player-dossiers/\">player-dossiers/</a>), fold <strong>NIGHT TRUTH</strong> on <strong>Ray</strong> only  </li>\n<li>[ ] Host script (<a href=\"05-episode-scripts.md\">05-episode-scripts.md</a>) + player script (<a href=\"player-performance-script.md\">player-performance-script.md</a>)  </li>\n<li>[ ] 1 live table puzzle (The Antidote)  </li>\n<li>[ ] 11 final ethical verdict ballots  </li>\n<li>[ ] 11 hospital ID badges  </li>\n<li>[ ] VIP Wing Logbook (Pepper)  </li>\n<li>[ ] Tampered anesthesia vial prop (Ray planted)  </li>\n<li>[ ] Private Investigator dossier (De Worsti's coat)  </li>\n<li>[ ] Newspaper clippings (E4-F Genevieve missing; E4-H sanctuary fire; see 15-evidence-materials.md)  </li>\n<li>[ ] Industrial wire cutters (Sachs)  </li>\n<li>[ ] Concealed hunting knife (Alfie)  </li>\n</ul>", "01-character-roster": "<h1>Character Roster, 11 Players</h1>\n<p><strong>Victim / narrator (non player):</strong> De Worsti<br />\n<strong>Investigation leads (until Ep 4 coda):</strong> Officer Ray, Officer Marlowe \"Marz\" + Dr. Curie<br />\n<strong>Optional 12th player:</strong> Officer Diamond, storm overflow security, see <a href=\"17-officer-diamond.md\">17-officer-diamond.md</a>, dossier <a href=\"player-dossiers/11-officer-diamond.md\">player-dossiers/11-officer-diamond.md</a><br />\n<strong>Full performance guide:</strong> <a href=\"14-actor-personas.md\">14-actor-personas.md</a></p>\n<h2>Investigators (4, including killer in plain sight)</h2>\n<h3>Officer Ray, Bruiser with a soft center (killer)</h3>\n<table>\n<thead>\n<tr>\n<th></th>\n<th></th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td><strong>Persona</strong></td>\n<td>Hard edged ex cop wall; secret soft heart; easy, steady friend to Lacey</td>\n</tr>\n<tr>\n<td><strong>Play</strong></td>\n<td>Bark first, regret later; protective; plain talk; runs the investigation</td>\n</tr>\n<tr>\n<td><strong>Role</strong></td>\n<td>Security chief; Containment Protocol Delta with <strong>Marz</strong> as junior officer</td>\n</tr>\n<tr>\n<td><strong>Secret</strong></td>\n<td><strong>Killer</strong>; Lacey's old friend; swore revenge on De Worsti; debt to De Worsti; tore keycard log; <strong>stole Curie's OR keycard</strong> (no OR access on his own badge)</td>\n</tr>\n<tr>\n<td><strong>Ability</strong></td>\n<td><em>Good Cop, Bad Cop</em>, coin flip with Curie: motive OR clue</td>\n</tr>\n<tr>\n<td><strong>Objective</strong></td>\n<td>Steer room toward Curie and Homes; survive until watch arrives</td>\n</tr>\n</tbody>\n</table>\n<h3>Dr. Curie, Prince Charming (obvious red herring)</h3>\n<table>\n<thead>\n<tr>\n<th></th>\n<th></th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td><strong>Persona</strong></td>\n<td>Idealist; kind-hearted <strong>social butterfly</strong>; <strong>annoying charisma</strong>; angel's advocate; assumes the best in people; <strong>deeply traumatized, never shows it</strong></td>\n</tr>\n<tr>\n<td><strong>Play</strong></td>\n<td>Warm, witty, generous with praise; genuine niceness reads suspicious but is <strong>not performance</strong>; <strong>rival</strong> to Homes; too many friends to name who lifted his keycard</td>\n</tr>\n<tr>\n<td><strong>Role</strong></td>\n<td>Chief of Surgery + medical liaison (looks guilty, is not the killer)</td>\n</tr>\n<tr>\n<td><strong>Secret</strong></td>\n<td>Sanctuary bond with Lacey; wanted De Worsti dead; did not make the cut; <strong>never noticed keycard missing until evidence</strong></td>\n</tr>\n<tr>\n<td><strong>Ability</strong></td>\n<td><em>Surgical Counsel</em>, once/act: lead seems unlikely, still worth running</td>\n</tr>\n<tr>\n<td><strong>Objective</strong></td>\n<td>Survive red herring heat; protect Lacey; help room find truth</td>\n</tr>\n</tbody>\n</table>\n<h3>Officer Marlowe \"Marz\", Southern belle (brutally honest)</h3>\n<table>\n<thead>\n<tr>\n<th></th>\n<th></th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td><strong>Persona</strong></td>\n<td>Honey drawl, perfect posture, wet nail polish; says outlandish things like she is passing the sugar</td>\n</tr>\n<tr>\n<td><strong>Play</strong></td>\n<td>Honey drawl; plain talk; wild theories anyone can follow; kind when asked nicely</td>\n</tr>\n<tr>\n<td><strong>Role</strong></td>\n<td>Junior security officer; investigates <strong>alongside Ray</strong> (not under Curie's medical lane)</td>\n</tr>\n<tr>\n<td><strong>Secret</strong></td>\n<td>Saw torn keycard log early; did not tell Ray immediately</td>\n</tr>\n<tr>\n<td><strong>Strength / weakness</strong></td>\n<td>Will float brutal, out of pocket theories in front of everyone</td>\n</tr>\n<tr>\n<td><strong>Romance</strong></td>\n<td>Likes <strong>CD Vance</strong>; <strong>Melody</strong> likes Marz; Vance likes Melody (triangle)</td>\n</tr>\n<tr>\n<td><strong>Objective</strong></td>\n<td>Prove herself on the case; protect Vance without freezing up</td>\n</tr>\n</tbody>\n</table>\n<h3>Nurse Pepper, Sage (sentimental + logical)</h3>\n<table>\n<thead>\n<tr>\n<th></th>\n<th></th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td><strong>Persona</strong></td>\n<td>Wise, calm anchor; devastatingly precise when on data; <strong>comedic ahem</strong> at Ray/Curie</td>\n</tr>\n<tr>\n<td><strong>Play</strong></td>\n<td>Sentimental about De Worsti and Homes; logical about timestamps and vitals</td>\n</tr>\n<tr>\n<td><strong>Role</strong></td>\n<td>VIP logbook gatekeeper; clinical witness</td>\n</tr>\n<tr>\n<td><strong>Secret</strong></td>\n<td>Affair with De Worsti; Lacey's perfume before collapse</td>\n</tr>\n<tr>\n<td><strong>Ability</strong></td>\n<td><em>The Chart Doesn't Lie</em>, logbook access for trades</td>\n</tr>\n<tr>\n<td><strong>Objective</strong></td>\n<td>Find killer; then expose or bury truth</td>\n</tr>\n</tbody>\n</table>\n<h2>Suspects &amp; side characters (7)</h2>\n<h3>Dr. Homes, Authoritative dick (for a good cause)</h3>\n<ul>\n<li><strong>Persona:</strong> Arrogant, insufferable, <strong>actually brilliant</strong>, saves lives, ruins moods  </li>\n<li><strong>Play:</strong> Condescending meritocrat; <strong>professional rival</strong> to Curie ,  hates his annoying charisma and angel's-advocate habit  </li>\n<li><strong>Framed</strong> at scene; <strong>first suspect</strong> who must defend himself; obsessed with Lacey  </li>\n<li><strong>Ability:</strong> <em>Doctor's Orders</em>, 3 truthful answer subpoena tokens  </li>\n<li><strong>Objective:</strong> Clear name; destroy Curie's reputation  </li>\n</ul>\n<h3>Lacey Lovely, Girl next door damsel (corporate)</h3>\n<ul>\n<li><strong>Persona:</strong> Attractive, approachable, <em>harmless</em>, ice queen boardroom underneath  </li>\n<li><strong>Play:</strong> Damsel in the light; steel in the pause before she answers  </li>\n<li><strong>Born Genevieve</strong>; fled De Worsti; facial reconstruction + new name  </li>\n<li><strong>Ray's friend</strong>; he stayed close for years; she did not plan the murder  </li>\n<li><strong>Ep 4 denial:</strong> Ran yes, killed no, <em>\"I only wanted distance\"</em> (<strong>truthful</strong>)  </li>\n<li><strong>Ability:</strong> <em>Administrative Override</em>, once/game, veto one search for full act  </li>\n<li><strong>Objective:</strong> Escape with fortune and identity intact  </li>\n</ul>\n<h3>Dr. Jetski, Frazzled surfer bro</h3>\n<ul>\n<li><strong>Persona:</strong> Sweaty, panicked, competent enough to be dangerous to himself; <strong>surfer bro</strong> underneath (occasional <em>dude</em> / <em>bro</em> / <em>gnarly</em> when stressed)  </li>\n<li><strong>Play:</strong> Comic stress valve; smart anesthesiology when the slang drops; explodes if nickname mocked  </li>\n<li>Unknowingly injected poison; incapacitated on floor  </li>\n<li><strong>Ability:</strong> <em>Adrenaline Shot</em>, yell \"CLEAR!\" for 1 uninterrupted minute  </li>\n<li><strong>Objective:</strong> Prove physical incapacitation  </li>\n</ul>\n<h3>Uvula Sachs, Workflow chaos gremlin (second in command)</h3>\n<ul>\n<li><strong>Persona:</strong> German enforcer who treats crime like engineering, tonight's murder investigation is a <strong>broken workflow</strong> and personally offensive  </li>\n<li><strong>Play:</strong> Overly expressive efficiency rage; takes everything literally; fixates on lighting, posture, phrasing; murder as badly run corporate meeting; <strong>still dangerous</strong>; <strong>German accent</strong> (D→T, B→P, G→K, V→F); <strong>not the killer</strong>  </li>\n<li>Coerces <strong>CD Vance</strong> (micromanaged contractor) to trace De Worsti's wife digitally  </li>\n<li>Wire cutters; planned own blackout, beaten to punch  </li>\n<li><strong>Ability:</strong> <em>Irony &amp; Iron Knuckles</em>, blocks vote without two evidence items  </li>\n<li><strong>Objective:</strong> De Worsti's ledger; stolen millions  </li>\n</ul>\n<h3>Alfie De Worsti, Strategic rage baiter</h3>\n<ul>\n<li><strong>Persona:</strong> Reckless unserious screw-up <em>(mask)</em>; observant, inflammatory, punchable  </li>\n<li><strong>Play:</strong> Smirks through serious moments; treats the investigation like entertainment; escalates when tension settles; pokes insecurities, turns people against each other  </li>\n<li>Delivery disguise; hunting knife; insurance plot; witnessed Genevieve's abuse  </li>\n<li><strong>Ep 4 obligation:</strong> Name Genevieve, hedged language <em>(camouflage, not cowardice)</em>, soft on Lacey  </li>\n<li><strong>Ability:</strong> <em>Double or Nothing</em>, die roll for clue vs. reveal knife  </li>\n<li><strong>Objective:</strong> Escape suspicion; insurance; break room dynamic; don't destroy Genevieve if he can help it  </li>\n</ul>\n<h3>Melody, Valley gossip bimbo</h3>\n<ul>\n<li><strong>Persona:</strong> Valley cadence, ditzy camouflage; <strong>sharp nail file underneath</strong>  </li>\n<li><strong>Play:</strong> <em>\"Like literally oh my god\"</em>, then one sentence that ends careers  </li>\n<li>Blackmails Lacey; saw Alfie enter; torn keycard log knowledge  </li>\n<li><strong>Ability:</strong> <em>Spill the Tea</em>, evidence for scandal trades  </li>\n<li><strong>Objective:</strong> Public ruin of Lacey  </li>\n</ul>\n<h3>CD Vance, Genki IT girl</h3>\n<ul>\n<li><strong>Persona:</strong> Nerdy, hyperactive, cutesy; terror = <strong>speed talk and babble</strong>  </li>\n<li><strong>Play:</strong> Stickers on laptop energy; overshares logs; <em>\"eep\"</em> under Sachs's threats  </li>\n<li><strong>Alliance: Sachs (coerced)</strong>, wife hunt queries; raw mainframe may expose <strong>Ray</strong>  </li>\n<li>Crush on Melody, goes full genki disaster around her  </li>\n<li><strong>Ability:</strong> <em>Data Breach</em>, sticky note forces dossier reveal  </li>\n<li><strong>Objective:</strong> Survive Sachs, prison  </li>\n</ul>\n<h2>Twelfth player (optional, overflow security)</h2>\n<h3>Officer Diamond, Procedure nerd (storm overflow)</h3>\n<table>\n<thead>\n<tr>\n<th></th>\n<th></th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td><strong>Persona</strong></td>\n<td>Over enthusiastic procedure nerd; treats real crisis like a live action training simulation</td>\n</tr>\n<tr>\n<td><strong>Play</strong></td>\n<td>Gamifies phases and credibility points; <em>boo yah</em>; official language in wrong contexts; playful then laser focused</td>\n</tr>\n<tr>\n<td><strong>Role</strong></td>\n<td>Auxiliary containment officer, called last minute when storm overflow stretches security; perimeter and escort</td>\n</tr>\n<tr>\n<td><strong>Secret</strong></td>\n<td>Sharper than the bit; reports observations to Ray instead of holding court</td>\n</tr>\n<tr>\n<td><strong>Ability</strong></td>\n<td><em>Training Module</em>, once per act: declare a phase name; room lets you finish one official sentence before arguing back (comic structure only)</td>\n</tr>\n<tr>\n<td><strong>Objective</strong></td>\n<td>Keep perimeter honest; support Ray and Marz; one real detail per act</td>\n</tr>\n<tr>\n<td><strong>Dossier</strong></td>\n<td><a href=\"player-dossiers/11-officer-diamond.md\">player-dossiers/11-officer-diamond.md</a></td>\n</tr>\n<tr>\n<td><strong>Host</strong></td>\n<td><a href=\"17-officer-diamond.md\">17-officer-diamond.md</a>, arrives after The Gathering; limited main plot</td>\n</tr>\n</tbody>\n</table>", "02-character-timelines": "<h1>Character Timelines, Night of the Murder</h1>\n<p>All times approximate. Adjust to your table's surgery slot.</p>\n<h2>STORM &amp; AUTHORITY TIMELINE</h2>\n<table>\n<thead>\n<tr>\n<th>Time</th>\n<th>Event</th>\n<th>Investigation impact</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td>T−6h</td>\n<td>Severe storm warning issued; city grid under stress</td>\n<td>Background</td>\n</tr>\n<tr>\n<td>T−2h</td>\n<td>Lower causeways flood; patrol units redeployed to rescue</td>\n<td>Municipal watch stretched</td>\n</tr>\n<tr>\n<td>T−30m</td>\n<td>St. Saphicca's on backup power cycles; VIP wing stable</td>\n<td>Ray exploits chaos</td>\n</tr>\n<tr>\n<td>T+0</td>\n<td>OR murder + 60s surgical blackout</td>\n<td>LC-4471 logged; <strong>no patrol on campus</strong></td>\n</tr>\n<tr>\n<td>T+10m</td>\n<td>Ray invokes <strong>Containment Protocol Delta</strong></td>\n<td>Wing sealed</td>\n</tr>\n<tr>\n<td>Ep 1 to 3</td>\n<td>Radio: <em>\"hold position… no ETA\"</em></td>\n<td>Suspects must cooperate inside</td>\n</tr>\n<tr>\n<td>Ep 3</td>\n<td>Melody attacked, killer still in wing</td>\n<td>External killer theory dies</td>\n</tr>\n<tr>\n<td>Ep 4</td>\n<td>Storm breaks; sirens audible</td>\n<td>Room makes accusation before handoff</td>\n</tr>\n<tr>\n<td>Gathering</td>\n<td>All eleven in VIP lounge</td>\n<td>Jetski \"killer in this room\" beat</td>\n</tr>\n<tr>\n<td>Ep 4 coda</td>\n<td>Municipal Watch enters</td>\n<td>Ballot readouts; see 05-episode-scripts.md</td>\n</tr>\n</tbody>\n</table>\n<h2>PRE OP (T − 3h to T − 30m)</h2>\n<table>\n<thead>\n<tr>\n<th>Time</th>\n<th>Character</th>\n<th>Location</th>\n<th>Activity</th>\n<th>Witnesses / record</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td>T−3y</td>\n<td><strong>Officer Ray</strong></td>\n<td>Lesbian City</td>\n<td>Learns what De Worsti did to <strong>Lacey</strong>; swears revenge; takes security post at St. Saphicca's</td>\n<td>Facilitator only until confession</td>\n</tr>\n<tr>\n<td>T−48h</td>\n<td><strong>Lacey Lovely</strong></td>\n<td>Hospital (admin)</td>\n<td>Sees <strong>Sachs</strong> on perimeter + other hunt signs; panic</td>\n<td>Subtle, no proof yet</td>\n</tr>\n<tr>\n<td>T−48h</td>\n<td><strong>Officer Ray</strong></td>\n<td>Security office</td>\n<td>Learns De Worsti booked <strong>real</strong> VIP arterial surgery here; accelerates plan</td>\n<td>Facilitator only until confession</td>\n</tr>\n<tr>\n<td>T−36h</td>\n<td><strong>Officer Ray</strong></td>\n<td>Off books</td>\n<td>Finalizes murder plan: vial, blackout, frame Homes; <strong>rejects pre-OR ambush</strong> (Sachs on wing, cameras live, no Homes frame, Homes might save the real arterial case)</td>\n<td>No witnesses</td>\n</tr>\n<tr>\n<td>T−3h</td>\n<td><strong>Officer Ray</strong></td>\n<td>Pharmacy vault</td>\n<td>Swaps anesthesia vial (security override + memorized director codes)</td>\n<td>Vault camera <em>may</em> be disabled wing wide</td>\n</tr>\n<tr>\n<td>T−2h</td>\n<td><strong>Uvula Sachs</strong></td>\n<td>VIP wing / elevator</td>\n<td>Threatens <strong>CD Vance</strong>, help trace De Worsti's wife or \"elevator shaft\"</td>\n<td>Vance begins clinic/hospital search logs (E2-F)</td>\n</tr>\n<tr>\n<td>T−2h</td>\n<td><strong>CD Vance</strong></td>\n<td>Server room</td>\n<td>Forced wife hunt queries for Sachs</td>\n<td>Reconstruction flags; admin tier anomalies</td>\n</tr>\n<tr>\n<td>T−2h</td>\n<td><strong>Alfie De Worsti</strong></td>\n<td>Loading dock → VIP</td>\n<td>Enters disguised as delivery driver</td>\n<td><strong>Melody</strong> saw him slip in</td>\n</tr>\n<tr>\n<td>T−90m</td>\n<td><strong>Officer Ray</strong></td>\n<td>Security office</td>\n<td>Debt pressure from De Worsti; tears keycard log page to hide OR entry plan</td>\n<td>Knows he made the tear</td>\n</tr>\n<tr>\n<td>T−90m</td>\n<td><strong>Officer Marlowe \"Marz\"</strong></td>\n<td>VIP corridor patrol</td>\n<td>Junior patrol; notices torn keycard log page</td>\n<td>Does not tell Ray immediately</td>\n</tr>\n<tr>\n<td>T−60m</td>\n<td><strong>Officer Diamond</strong></td>\n<td>Main campus security desk</td>\n<td>Storm overflow shift; not yet routed to VIP wing</td>\n<td>Not in building wing during prep</td>\n</tr>\n<tr>\n<td>T−60m</td>\n<td><strong>Melody</strong></td>\n<td>Front desk</td>\n<td>Tears / notices missing master keycard log page</td>\n<td>Logbook gap, <strong>host only until Ep 3</strong></td>\n</tr>\n<tr>\n<td>T−45m</td>\n<td><strong>Dr. Homes</strong></td>\n<td>Pre op / consult</td>\n<td>De Worsti intake; tension with Pepper</td>\n<td>Prologue scene</td>\n</tr>\n<tr>\n<td>T−30m</td>\n<td><strong>Nurse Pepper</strong></td>\n<td>VIP consult suite</td>\n<td>Prep; secret eye on De Worsti</td>\n<td>Pepper, Homes, De Worsti</td>\n</tr>\n<tr>\n<td>T−20m</td>\n<td><strong>Officer Ray</strong></td>\n<td>VIP corridor</td>\n<td>Lifts <strong>Curie's OR keycard</strong> during a social moment; Curie does not notice</td>\n<td>No witnesses who connect it to Ray</td>\n</tr>\n<tr>\n<td>T−15m</td>\n<td><strong>Dr. Jetski</strong></td>\n<td>OR prep</td>\n<td>Loads tray from pharmacy, <strong>tampered vial</strong></td>\n<td>Unaware</td>\n</tr>\n<tr>\n<td>T−10m</td>\n<td><strong>De Worsti</strong></td>\n<td>Gowned, VIP route</td>\n<td><strong>Real</strong> arterial case; power play on Lacey's hospital; hunting ex wife</td>\n<td>Multiple enemies in building</td>\n</tr>\n</tbody>\n</table>\n<h2>THE SURGERY (T = 0)</h2>\n<table>\n<thead>\n<tr>\n<th>Time</th>\n<th>Character</th>\n<th>Location</th>\n<th>Activity</th>\n<th>Status</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td>T+0</td>\n<td><strong>Dr. Homes</strong></td>\n<td>OR table</td>\n<td>Mid operation; arterial repair</td>\n<td>Conscious</td>\n</tr>\n<tr>\n<td>T+0</td>\n<td><strong>Nurse Pepper</strong></td>\n<td>OR</td>\n<td>Assisting; notes falling pressure</td>\n<td>Conscious → <strong>paralyzed ~15s</strong></td>\n</tr>\n<tr>\n<td>T+0</td>\n<td><strong>Dr. Jetski</strong></td>\n<td>OR anesthesia</td>\n<td>Administers IV; notices lag</td>\n<td>Conscious → <strong>paralyzed ~15s</strong></td>\n</tr>\n<tr>\n<td>T+0</td>\n<td><strong>De Worsti</strong></td>\n<td>OR table</td>\n<td>Patient</td>\n<td>Sedated → <strong>killed during blackout</strong></td>\n</tr>\n<tr>\n<td>T+0 to T+15s</td>\n<td><strong>Officer Ray</strong></td>\n<td>Security route → OR</td>\n<td>Enters on <strong>Curie's stolen keycard</strong>; night vision kill</td>\n<td><strong>Immune / prepared</strong></td>\n</tr>\n<tr>\n<td>T+0 to T+60s</td>\n<td><strong>Officer Ray</strong></td>\n<td>Security office</td>\n<td>Manual grid override (blackout)</td>\n<td>Remote</td>\n</tr>\n<tr>\n<td>T+15s</td>\n<td><strong>Officer Ray</strong></td>\n<td>OR</td>\n<td>Violent scalpel wound to carotid; plants tool near Homes</td>\n<td>Exits blind spot; <strong>returns Curie's keycard</strong> before he notices</td>\n</tr>\n<tr>\n<td>T+60s</td>\n<td><strong>Emergency lighting</strong></td>\n<td>OR</td>\n<td>Red backup flickers on</td>\n<td>Scene frozen</td>\n</tr>\n</tbody>\n</table>\n<h3>Post blackout OR snapshot</h3>\n<ul>\n<li><strong>Homes:</strong> Standing, bloody gloves, scalpel in hand, <strong>framed</strong>  </li>\n<li><strong>Pepper / Jetski:</strong> Unconscious on tile  </li>\n<li><strong>De Worsti:</strong> Dead, violent scalpel wound to carotid  </li>\n<li><strong>Curie:</strong> Eastern corridor (true alibi for kill window; still looks guilty)  </li>\n<li><strong>Lacey:</strong> Admin wing, alibi as \"director responding to crisis\"  </li>\n<li><strong>Ray:</strong> Claims security perimeter (false alibi for kill window)  </li>\n</ul>\n<h2>IMMEDIATE AFTERMATH (T + 5m to T + 45m)</h2>\n<table>\n<thead>\n<tr>\n<th>Time</th>\n<th>Character</th>\n<th>Location</th>\n<th>Activity</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td>T+2m</td>\n<td><strong>Staff / Melody</strong></td>\n<td>OR corridor</td>\n<td>Run to fetch <strong>Lacey</strong> (admin) and <strong>Ray</strong> (security)</td>\n</tr>\n<tr>\n<td>T+5m</td>\n<td><strong>Nurse Pepper</strong></td>\n<td>OR</td>\n<td>Wakes terrified; sees De Worsti; shaking testimony, does not immediately accuse Homes</td>\n</tr>\n<tr>\n<td>T+10m</td>\n<td><strong>Officer Ray</strong> + <strong>Officer Marlowe \"Marz\"</strong> + <strong>Lacey</strong></td>\n<td>OR → Recovery Lounge</td>\n<td>Ray secures scene; Marz on perimeter; Lacey crisis posture; summon <strong>all eleven</strong> to lounge</td>\n</tr>\n<tr>\n<td>T+12m</td>\n<td><strong>Officer Diamond</strong></td>\n<td>Main campus → VIP wing stairs</td>\n<td>Overflow call after code; en route during Gathering</td>\n</tr>\n<tr>\n<td>T+20m</td>\n<td><strong>Everyone</strong></td>\n<td>Recovery Lounge</td>\n<td><strong>THE GATHERING</strong>, news broken; Homes named primary suspect (see 10-the gathering.md)</td>\n</tr>\n<tr>\n<td>T+35m</td>\n<td><strong>Officer Ray</strong> + <strong>Dr. Curie</strong></td>\n<td>Lounge → wing</td>\n<td>Ray splits room for evidence search; keeps Homes primary; Curie looks like co-lead</td>\n</tr>\n<tr>\n<td>T+40m</td>\n<td><strong>Melody</strong></td>\n<td>Lounge testimony</td>\n<td>Hints missing keycard page / cameras; Alfie glance; flirts with Marz</td>\n</tr>\n<tr>\n<td>T+45m</td>\n<td><strong>All eleven</strong></td>\n<td>OR + wing</td>\n<td><strong>Act 2 live play</strong>, forensics, clue cards (06-act2-crime scene.md)</td>\n</tr>\n</tbody>\n</table>\n<h2>EPISODE 2, SYSTEM CRACKS</h2>\n<table>\n<thead>\n<tr>\n<th>Time</th>\n<th>Character</th>\n<th>Event</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td>Ep 2 open</td>\n<td><strong>Jetski</strong></td>\n<td>Recovery ward interrogation (cutscene)</td>\n</tr>\n<tr>\n<td>Ep 2</td>\n<td><strong>Pepper</strong></td>\n<td>Releases toxicology + pharmacy logs</td>\n</tr>\n<tr>\n<td>Ep 2</td>\n<td><strong>CD Vance</strong></td>\n<td>Confesses Sachs coerced wife investigation; search logs surface (E2-F)</td>\n</tr>\n<tr>\n<td>Ep 2</td>\n<td><strong>Ray + Marz + Curie</strong></td>\n<td>Ray opens Lacey background; Marz may volunteer wild theory; Curie: run the access logs anyway</td>\n</tr>\n<tr>\n<td>Ep 2 late</td>\n<td><strong>Locker find</strong></td>\n<td>Orphanage photo, Genevieve + Curie (players may miss)</td>\n</tr>\n</tbody>\n</table>\n<h2>EPISODE 3, THE HUMAN COST</h2>\n<table>\n<thead>\n<tr>\n<th>Time</th>\n<th>Character</th>\n<th>Event</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td>Ep 3</td>\n<td><strong>Melody</strong></td>\n<td>Finds keycard evidence; cornered in pharmacy wing</td>\n</tr>\n<tr>\n<td>Ep 3</td>\n<td><strong>Officer Ray</strong></td>\n<td><strong>Attacks Melody</strong> (KCl syringe); sends Curie after misdirection \"shadow toward administration\"</td>\n</tr>\n<tr>\n<td>Ep 3</td>\n<td><strong>Alfie</strong></td>\n<td>Hunting knife drops in panic</td>\n</tr>\n<tr>\n<td>Ep 3</td>\n<td><strong>Sachs</strong></td>\n<td>Wire cutters discovered</td>\n</tr>\n<tr>\n<td>Ep 3</td>\n<td>Players</td>\n<td>Antidote puzzle, Calcium Gluconate</td>\n</tr>\n</tbody>\n</table>\n<p><strong>If antidote succeeds:</strong> Melody whispers <em>\"Curie's card… in the OR log…\"</em><br />\n<strong>If fails:</strong> Melody comatose; group loses direct testimony  </p>\n<h2>EPISODE 4, FINAL CALL</h2>\n<table>\n<thead>\n<tr>\n<th>Time</th>\n<th>Character</th>\n<th>Event</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td>Ep 4</td>\n<td><strong>Alfie</strong></td>\n<td><strong>Mandatory reveal:</strong> Genevieve, uncertain testimony; abuse truth; protects Lacey from full condemnation</td>\n</tr>\n<tr>\n<td>Ep 4</td>\n<td><strong>Lacey</strong></td>\n<td>Admits running; <strong>denies murder</strong> (truthful); may confirm Ray as a close friend and protector</td>\n</tr>\n<tr>\n<td>Ep 4</td>\n<td><strong>Curie</strong></td>\n<td>Red herring heat peaks; insists he did not make the cut</td>\n</tr>\n<tr>\n<td>Ep 4</td>\n<td><strong>Melody</strong> (if alive)</td>\n<td>Corroborates Alfie, archival pre surgery face match</td>\n</tr>\n<tr>\n<td>Ep 4</td>\n<td><strong>CD Vance</strong></td>\n<td>Raw mainframe vs. Lacey's edited timestamps</td>\n</tr>\n<tr>\n<td>Ep 4</td>\n<td><strong>Officer Ray</strong></td>\n<td><strong>Curie's keycard</strong> in OR during exact 60s blackout (raw mainframe); Ray has no OR access on his own badge</td>\n</tr>\n<tr>\n<td>Ep 4</td>\n<td><strong>Dr. Curie</strong></td>\n<td>Genuinely shocked when logs name his card ,  he never knew it left his person that night</td>\n</tr>\n<tr>\n<td>Ep 4</td>\n<td><strong>Room</strong></td>\n<td>Dual ballot, target + moral verdict</td>\n</tr>\n</tbody>\n</table>\n<h2>CCTV / WITNESS GAPS (investigation friction)</h2>\n<table>\n<thead>\n<tr>\n<th>System</th>\n<th>Status</th>\n<th>Implication</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td>OR internal cameras</td>\n<td>Disabled / doctored</td>\n<td>Forces eyewitness + physical evidence</td>\n</tr>\n<tr>\n<td>VIP wing corridor CCTV</td>\n<td>Mostly offline</td>\n<td>Hacking skill red herring → <strong>CD Vance</strong>, not sole killer</td>\n</tr>\n<tr>\n<td>Pharmacy vault</td>\n<td>Log only (executive tier codes)</td>\n<td>Points to admin tier; Ray physically swapped vial</td>\n</tr>\n<tr>\n<td>Power console</td>\n<td>Manual override logged</td>\n<td>Security office; Ray</td>\n</tr>\n<tr>\n<td>Keycard log page</td>\n<td><strong>Torn out</strong> pre surgery</td>\n<td>Melody knows; Ray noticed gap</td>\n</tr>\n<tr>\n<td>Reception sighting</td>\n<td>Melody saw <strong>Homes</strong> in hall</td>\n<td>Alibi for Homes <em>or</em> misdirection if players assume director</td>\n</tr>\n</tbody>\n</table>", "03-motivations-alliances": "<h1>Motivations &amp; Alliances</h1>\n<p><strong>Actor personas (exaggerated, plot unchanged):</strong> <a href=\"14-actor-personas.md\">14-actor-personas.md</a></p>\n<h2>Faction map</h2>\n<pre><code>\n                    [OFFICER RAY]\n\n                    Killer + investigator\n\n                    Lacey's friend; revenge on De Worsti\n\n                           │\n\n         ┌─────────────────┼─────────────────┐\n\n         │                 │                 │\n\n    [DR. HOMES]        [DR. CURIE]       [NURSE PEPPER]\n\n    First suspect      Obvious red        Secret lover of De Worsti\n\n    Must defend        herring; sanctuary  Throat clear comedy\n\n    himself            bond + skill       Hates Lacey\n\n         │                 │                 │\n\n         └──────── antagonism ────────────────┘\n\n\n\n    [LACEY LOVELY]\n\n    Ray's friend; hunted by De Worsti\n\n    Did not plan the murder\n\n\n\n    [STREET LAYER, not the murder team]\n\n    Sachs ── enforcer ── De Worsti (dead); coerces Vance to hunt Genevieve\n\n    Alfie ── brother ── De Worsti (wanted him dead)\n\n    Jetski ── gambling debt ── Alfie / syndicate\n\n\n\n    [WILD CARDS]\n\n    Melody → blackmails Lacey; manipulates Vance\n\n    CD Vance → <strong>coerced asset of Sachs</strong> (wife investigation); loves Melody\n\n</code></pre>\n<h2>Per character motives</h2>\n<h3>De Worsti (victim, narrator role in prologue)</h3>\n<p>| | |</p>\n<p>|---|---|</p>\n<p>| <strong>Public face</strong> | Wealthy VIP patient demanding priority care |</p>\n<p>| <strong>Truth</strong> | Bankrupt loan shark and crime lord; hunting ex wife Genevieve; <strong>real</strong> VIP arterial case booked at St. Saphicca's as power play on Lacey's hospital |</p>\n<p>| <strong>Crimes</strong> | Years of violent abuse of <strong>Genevieve</strong> (see below); arson against Curie's family; predatory lending; threatened Ray's <strong>mother and sister</strong> |</p>\n<p>| <strong>Why murdered</strong> | Ray's revenge to protect Lacey; Alfie/Sachs had parallel plans |</p>\n<p>| <strong>Story arc</strong> | <strong>Revealed over four episodes as worse than his murderers</strong>, see <a href=\"12-de-worsti-revelation-arc.md\">12-de-worsti-revelation-arc.md</a> |</p>\n<h3>Officer Ray (killer, investigator cover)</h3>\n<p>| | |</p>\n<p>|---|---|</p>\n<p>| <strong>Persona</strong> | Bruiser with a soft center |</p>\n<p>| <strong>Surface motive</strong> | Security chief running Containment Protocol Delta |</p>\n<p>| <strong>Real motive</strong> | Protect <strong>Lacey</strong>; revenge on De Worsti after years of watching what he did to her |</p>\n<p>| <strong>Tonight</strong> | Accelerated a plan when De Worsti's real surgery booking landed in Lacey's wing |</p>\n<p>| <strong>Why the OR</strong> | Not ambushable elsewhere (Sachs, cameras, badge exposure); only the table gives immobilized victim + Homes frame + Curie keycard log + containment alibi; waiting risks Homes saving a real case |</p>\n<p>| <strong>Investigation play</strong> | Runs the board; frames Homes; steers room toward <strong>Curie</strong> (red herring) |</p>\n<p>| <strong>Secret</strong> | Tore keycard log; <strong>no OR access on his own badge</strong>; stole <strong>Curie's keycard</strong> for blackout entry; mainframe shows Curie in OR |</p>\n<p>| <strong>Alliance</strong> | Protects <strong>Lacey</strong>; performs partnership with <strong>Curie</strong> to keep eyes off himself |</p>\n<h3>Dr. Curie (obvious red herring)</h3>\n<p>| | |</p>\n<p>|---|---|</p>\n<p>| <strong>Persona</strong> | Prince Charming, lovable social butterfly, traumatized, <strong>not the killer</strong> |</p>\n<p>| <strong>Surface motive</strong> | Beloved chief; cooperative investigator |</p>\n<p>| <strong>Real motive</strong> | Wanted De Worsti dead; failed Genevieve once; will not confess to a cut he did not make |</p>\n<p>| <strong>Why he looks guilty</strong> | Sanctuary bond with Genevieve, surgical skill, OR corridor presence, charm that buys trust, <strong>raw keycard log names his badge in OR during blackout</strong> |</p>\n<p>| <strong>Charm play</strong> | <strong>Deliberate warmth</strong>, but for protection not murder cover; <strong>Homes alone</strong> finds it grating |</p>\n<p>| <strong>Vs. Ray</strong> | Flirty banter Ray half enjoys; senses Ray respects him and does <strong>not</strong> suspect him; Ray stole his OR keycard without his knowledge |</p>\n<p>| <strong>Investigation play</strong> | Contributes real clues; room chases him by default |</p>\n<p>| <strong>Alliance</strong> | <strong>Lacey</strong> (absolute); performs partnership with <strong>Ray</strong> |</p>\n<p>Full beat guide: <a href=\"13-curie-charm-playbook.md\">13-curie-charm-playbook.md</a></p>\n<h3>Lacey Lovely, born Genevieve (protected friend)</h3>\n<p>| | |</p>\n<p>|---|---|</p>\n<p>| <strong>Persona</strong> | Girl next door damsel mask; corporate ice underneath |</p>\n<p>| <strong>Surface motive</strong> | Ice queen director; corporate liability |</p>\n<p>| <strong>Real motive</strong> | Finish escaping De Worsti forever; keep stolen fortune; protect new identity |</p>\n<p>| <strong>Past</strong> | De Worsti's first wife. Ray's longtime friend. Lived under his crime empire, isolated, beaten, financially erased, hunted after she fled with ledger cash |</p>\n<p>| <strong>Transformation</strong> | Total facial reconstruction + legal name change to <strong>Lacey Lovely</strong>; built career at St. Saphicca's |</p>\n<p>| <strong>Vs. De Worsti</strong> | Sachs and other warnings told her he had found the hospital; his <strong>real</strong> VIP surgery booking was a power play on her turf |</p>\n<p>| <strong>Vs. Ray</strong> | Trusted friend for years; he swore revenge on De Worsti; she did not know he would kill in the OR |</p>\n<p>| <strong>Public denial (Ep 4)</strong> | Admits she ran and rebuilt her life; <strong>denies murder</strong>, <em>she never hated him enough to kill; she only wanted distance</em> (<strong>truthful</strong>) |</p>\n<p>| <strong>Vs. Pepper</strong> | Knows affair with De Worsti; wants Pepper destroyed |</p>\n<p>| <strong>Vs. Melody</strong> | Melody has pre surgery archival photos |</p>\n<p>| <strong>Alliance</strong> | <strong>Curie</strong> (childhood sanctuary bond); strings <strong>Homes</strong> along |</p>\n<h4>Genevieve's abuse under De Worsti (facilitator truth)</h4>\n<p>De Worsti ran Genevieve as property, not a partner: monitored her contact with the world, controlled every account, beat her when she questioned his deals or embarrassed him in front of enforcers like Sachs. After she took money from his vault, De Worsti burned Curie's family home to punish her. She vanished, rebuilt her face and name, and became Lacey. <strong>Alfie reveals this to the room in Episode 4</strong>, see 11-genevieve backstory.md.</p>\n<h3>Dr. Homes (framed surgeon, first suspect)</h3>\n<p>| | |</p>\n<p>|---|---|</p>\n<p>| <strong>Persona</strong> | Authoritative dick, arrogant, but for a good cause (medicine) |</p>\n<p>| <strong>Motive to harm De Worsti</strong> | Weak, professional ego; De Worsti's money insulted hospital ethos |</p>\n<p>| <strong>Motive vs. others</strong> | Obsessed with Lacey; violent hatred of Curie, <strong>only one not won over by Curie's charm</strong> |</p>\n<p>| <strong>Investigation read</strong> | Primary suspect Ep 1; must defend himself all night |</p>\n<p>| <strong>Secret</strong> | Scalpel \"ripped from grip\" during blackout |</p>\n<p>| <strong>Alliance</strong> | Thinks he's close to <strong>Lacey</strong>; enemy of <strong>Curie</strong> |</p>\n<h3>Nurse Pepper</h3>\n<p>| | |</p>\n<p>|---|---|</p>\n<p>| <strong>Persona</strong> | Sage, sentimental heart, surgical logic |</p>\n<p>| <strong>Motive vs. De Worsti</strong> | Secret toxic affair, grief when dead, not relief |</p>\n<p>| <strong>Motive vs. Lacey</strong> | Jealousy; did not know Lacey was De Worsti's legal wife <strong>Genevieve</strong> until Alfie's reveal |</p>\n<p>| <strong>Motive vs. Homes</strong> | Hidden crush; complicated |</p>\n<p>| <strong>Secret</strong> | Smelled Lacey's perfume before collapse; holds <strong>VIP logbook</strong> |</p>\n<p>| <strong>Endgame choice</strong> | Expose killer or bury truth for career |</p>\n<h3>Officer Marlowe \"Marz\"</h3>\n<p>| | |</p>\n<p>|---|---|</p>\n<p>| <strong>Persona</strong> | Southern belle; honey drawl; brutal honesty; paints nails to fidget |</p>\n<p>| <strong>Motive vs. De Worsti</strong> | None personal; professional disgust at VIP wing rot |</p>\n<p>| <strong>Strength / weakness</strong> | Outlandish theories, out of pocket, sometimes accidentally right |</p>\n<p>| <strong>Secret</strong> | Saw torn keycard log before Ray; waited to see who flinched |</p>\n<p>| <strong>Romance</strong> | Likes <strong>Vance</strong>; <strong>Melody</strong> likes Marz; Vance likes Melody |</p>\n<p>| <strong>Alliance</strong> | <strong>Ray</strong> (junior officer); pushes interviews Ray softens |</p>\n<p>| <strong>Play beat</strong> | Melody asks where her clothes are from; Marz answers <strong>kindly</strong> |</p>\n<h3>Dr. Jetski</h3>\n<p>| | |</p>\n<p>|---|---|</p>\n<p>| <strong>Persona</strong> | Frazzled surfer bro, sweaty panic, comic relief; smart anesthesiologist under the slang |</p>\n<p>| <strong>Motive vs. De Worsti</strong> | Indirect, gambling syndicate linked to De Worsti's world |</p>\n<p>| <strong>Truth</strong> | Unwiting delivery of poison; incapacitated before kill |</p>\n<p>| <strong>Alliance</strong> | Gambling buddy <strong>Alfie</strong>; Sachs's syndicate pressure |</p>\n<h3>Uvula Sachs (red herring, guilty of other crimes, not this murder)</h3>\n<p>| | |</p>\n<p>|---|---|</p>\n<p>| <strong>Persona</strong> | Workflow chaos gremlin, second in command; German; treats murder like bad project management; efficiency rage; still dangerous |</p>\n<p>| <strong>Motive vs. De Worsti</strong> | Mutual hatred; De Worsti broke; millions owed |</p>\n<p>| <strong>Tonight's plan</strong> | Wire cutters to cut power himself, <strong>beaten to blackout by Ray</strong> |</p>\n<p>| <strong>Wife hunt</strong> | Threatened <strong>CD Vance</strong> into tracing De Worsti's ex wife through clinic/hospital systems, wants the stolen fortune, not Genevieve's safety |</p>\n<p>| <strong>Ray's play</strong> | <strong>Pin murder on Sachs</strong> when useful; players may bite |</p>\n<p>| <strong>Alliance</strong> | <strong>Coerces Vance</strong> as digital investigator; provokes <strong>Ray</strong> |</p>\n<h3>Alfie De Worsti</h3>\n<p>| | |</p>\n<p>|---|---|</p>\n<p>| <strong>Persona</strong> | Strategic rage baiter; reckless screw-up mask over sharp observation |</p>\n<p>| <strong>Play style</strong> | Smirks through serious moments; treats investigation like entertainment; escalates when tension settles; pokes insecurities, turns people against each other |</p>\n<p>| <strong>Motive vs. De Worsti</strong> | Brother; drained family; life insurance plot; witnessed Genevieve's abuse |</p>\n<p>| <strong>Tonight's plan</strong> | Hunting knife; intended to kill De Worsti himself; otherwise stir the room |</p>\n<p>| <strong>Motive vs. Pepper</strong> | Unrequited crush; hates Homes flirting with her ,  both are bait material |</p>\n<p>| <strong>Secret</strong> | Mainland clinic intake photo; scar above Lacey's ear matches Genevieve's injury |</p>\n<p>| <strong>Mandatory beat</strong> | <strong>Episode 4: reveals Genevieve</strong>, truth about De Worsti's abuse and her disappearance, but <strong>hedged with uncertainty</strong> <em>(camouflage, not cowardice)</em>; still cares about Lacey/Genevieve and does not want her destroyed |</p>\n<p>| <strong>Tone</strong> | Punchable, inflammatory, punchline delivery; <em>\"I think…\" / \"as far as I know…\" / \"I'm not saying she, \"</em>, facts slip out sounding harmless; Melody corroborates harder after he speaks |</p>\n<h3>Melody</h3>\n<p>| | |</p>\n<p>|---|---|</p>\n<p>| <strong>Persona</strong> | Valley gossip bimbo, ditzy camouflage, razor underneath |</p>\n<p>| <strong>Motive vs. Lacey</strong> | Blackmail; archival intake photos |</p>\n<p>| <strong>Motive vs. De Worsti</strong> | Gossip network; saw Alfie enter |</p>\n<p>| <strong>Romance</strong> | Crush on <strong>Officer Marz</strong>; wardrobe compliments as flirtation |</p>\n<p>| <strong>Power</strong> | Withholds evidence for scandal trades |</p>\n<p>| <strong>Target</strong> | Public ruin of <strong>Lacey</strong> |</p>\n<h3>CD Vance</h3>\n<p>| | |</p>\n<p>|---|---|</p>\n<p>| <strong>Persona</strong> | Genki IT girl, nerdy, hyperactive, cutesy; terror as speed babble |</p>\n<p>| <strong>Romance</strong> | Crush on <strong>Melody</strong>; oblivious that <strong>Officer Marz</strong> likes him |</p>\n<p>| <strong>Motive</strong> | Survival, not ideological |</p>\n<p>| <strong>Primary alliance</strong> | <strong>Uvula Sachs (coerced)</strong>, forced to help investigate De Worsti's wife via IT access: reconstruction clinic sweeps, hospital admin trails, VIP anomalies |</p>\n<p>| <strong>Also pressured by</strong> | <strong>Ray</strong> (log anomalies he planted or exploited); Alfie (elevator threats earlier) |</p>\n<p>| <strong>Secret</strong> | Running Sachs's wife hunt queries the same night Ray's blackout hit; raw mainframe shows <strong>Curie's keycard</strong> in OR (Ray stole it) |</p>\n<p>| <strong>Ep 2 reveal</strong> | Cracks under Ray, admits Sachs made him dig for Genevieve, didn't know name until Alfie |</p>\n<p>| <strong>Ep 4 tie in</strong> | His search logs + Alfie's Genevieve reveal + Vance raw mainframe = <strong>Curie's badge in OR</strong> while Curie was elsewhere → Ray |</p>\n<p>| <strong>Romance</strong> | Infatuated with <strong>Melody</strong>, only voluntary bond in his night |</p>\n<h2>Politics table (who benefits from whom's downfall)</h2>\n<p>| If accused… | Primary beneficiaries |</p>\n<p>|-------------|---------------------|</p>\n<p>| Dr. Homes | Ray |</p>\n<p>| Sachs | Ray (misdirection) |</p>\n<p>| Alfie | Everyone (reaction fuel); Ray, Pepper (favorite bait targets) |</p>\n<p>| Jetski | Homes, Ray |</p>\n<p>| Curie | Ray |</p>\n<p>| Lacey | Ray (if room thinks she ordered it) |</p>\n<p>| Curie + Lacey (pair) | Ray (Ending C escape) |</p>\n<p>| Officer Ray | Truth only, everyone else exonerated or broken |</p>\n<h2>Moral verdict lens (Ep 4)</h2>\n<p>| Verdict | Player statement |</p>\n<p>|---------|------------------|</p>\n<p>| <strong>MURDER</strong> | Ray killed a man; De Worsti's crimes do not erase his |</p>\n<p>| <strong>JUSTICE</strong> | De Worsti was the bigger monster; Ray gave his friend a chance; bury it |</p>\n<p>| <strong>SYSTEM FAILURE</strong> | De Worsti built the corruption; expose the whole wing and the city he poisoned |</p>\n<p><strong>Facilitator note:</strong> By ballot time the room should feel De Worsti was <strong>worse</strong> than his killer, and that the killer is <strong>still guilty</strong>. See <a href=\"12-de-worsti-revelation-arc.md\">12-de-worsti-revelation-arc.md</a>.</p>", "04-evidence-index": "<h1>Evidence Index</h1>\n<p>Track physical props, evidence cards, who holds them, and when they enter play.</p>\n<p><strong>Player readable text for every card:</strong> <a href=\"15-evidence-materials.md\">15-evidence-materials.md</a> (descriptions, full copy, props list).</p>\n<h2>Episode 1, THE INCIDENT</h2>\n<table>\n<thead>\n<tr>\n<th>ID</th>\n<th>Evidence</th>\n<th>Type</th>\n<th>Found where</th>\n<th>Points to</th>\n<th>Dropped</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td>E1-A</td>\n<td><strong>Blood pattern card</strong></td>\n<td>Physical</td>\n<td>OR floor</td>\n<td>Two layers: controlled drip (pre blackout) + interrupted splash</td>\n<td>Ep 1, crime scene</td>\n</tr>\n<tr>\n<td>E1-B</td>\n<td><strong>Tampered IV vial</strong></td>\n<td>Prop + card</td>\n<td>OR trash</td>\n<td>Pharmacy vault access; tampered seal</td>\n<td>Ep 1, crime scene</td>\n</tr>\n<tr>\n<td>E1-C</td>\n<td><strong>P.I. dossier</strong></td>\n<td>Prop + card</td>\n<td>De Worsti's coat jacket</td>\n<td>Runaway ex wife; facial reconstruction; childhood friend near Sapphic Quarter, <strong>no name until Alfie (Ep 4)</strong></td>\n<td>Ep 1, after search</td>\n</tr>\n<tr>\n<td>E1-D</td>\n<td><strong>Scalpel in Homes' hand</strong></td>\n<td>Scene</td>\n<td>OR</td>\n<td>Frame on Homes; wound looks violent and crazed, could be rage or skill</td>\n<td>Ep 1, immediate</td>\n</tr>\n<tr>\n<td>E1-E</td>\n<td><strong>Flatlined monitor</strong></td>\n<td>Atmospheric</td>\n<td>OR</td>\n<td>Time of death anchor</td>\n<td>Prologue</td>\n</tr>\n</tbody>\n</table>\n<h3>E1 investigation beats</h3>\n<ul>\n<li>60-second blackout bypassed eco grid redundancy  </li>\n<li>Single carotid scalpel wound; violent, passionate, almost crazed in appearance  </li>\n<li>De Worsti dragged to floor; Homes standing over body with scalpel; Jetski/Pepper unconscious  </li>\n</ul>\n<h3>E1 absolution seeds (subtle)</h3>\n<table>\n<thead>\n<tr>\n<th>Character</th>\n<th>Evidence</th>\n<th>What careful players may notice</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td><strong>Dr. Homes</strong></td>\n<td>E1-A</td>\n<td>Two blood phases: controlled drip <strong>before</strong> blackout, then fast smear in dark. Does not match one panicked surgeon frozen at the table.</td>\n</tr>\n<tr>\n<td><strong>Dr. Curie</strong></td>\n<td><em>(none yet)</em></td>\n<td>P.I. dossier (E1-C) <strong>raises</strong> heat; absolution waits for Ep 2 to 4 mechanism evidence.</td>\n</tr>\n<tr>\n<td><strong>Dr. Jetski / Nurse Pepper</strong></td>\n<td>E1-D scene</td>\n<td>Both down when lights return; incision window still open, but toxicology confirms timing in Ep 2.</td>\n</tr>\n</tbody>\n</table>\n<h2>Episode 2, THE SYSTEM CRACKS</h2>\n<table>\n<thead>\n<tr>\n<th>ID</th>\n<th>Evidence</th>\n<th>Type</th>\n<th>Found where</th>\n<th>Points to</th>\n<th>Dropped</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td>E2-A</td>\n<td><strong>Toxicology screen</strong></td>\n<td>Card</td>\n<td>Pepper's folder</td>\n<td>Custom Propofol + Midazolam; paralysis &lt;15s</td>\n<td>Ep 2 cutscene</td>\n</tr>\n<tr>\n<td>E2-B</td>\n<td><strong>Pharmacy vault log</strong></td>\n<td>Card</td>\n<td>Facilities report</td>\n<td>Security override + director emergency codes, 2h pre op</td>\n<td>Ep 2 cutscene</td>\n</tr>\n<tr>\n<td>E2-C</td>\n<td><strong>Power override log</strong></td>\n<td>Card</td>\n<td>Security / facilities</td>\n<td>Manual grid drop, <strong>security office</strong></td>\n<td>Ep 2 cutscene</td>\n</tr>\n<tr>\n<td>E2-D</td>\n<td><strong>Orphanage photo</strong></td>\n<td>Physical</td>\n<td>Old locker</td>\n<td>Young <strong>Genevieve</strong> + <strong>Curie</strong></td>\n<td>Ep 2, easy to miss</td>\n</tr>\n<tr>\n<td>E2-E</td>\n<td><strong>Jetski testimony</strong></td>\n<td>Testimony</td>\n<td>Recovery ward</td>\n<td>Collapsed <em>before</em> lights; killer needed night vision</td>\n<td>Ep 2 cutscene</td>\n</tr>\n<tr>\n<td>E2-F</td>\n<td><strong>Vance search logs</strong></td>\n<td>Digital</td>\n<td>Vance's terminal / Sachs pressure</td>\n<td>Clinic reconstruction sweeps + admin trails, <strong>hunting De Worsti's wife for Sachs</strong></td>\n<td>Ep 2, Vance confession</td>\n</tr>\n</tbody>\n</table>\n<h3>E2 conclusions (intended)</h3>\n<ul>\n<li>Knockout was engineered, not error  </li>\n<li>Vault pull = executive clearance  </li>\n<li>Blackout = separate coordinated system  </li>\n<li>Killer = immune, prepared, or night vision equipped  </li>\n</ul>\n<h3>E2 absolution shifts (subtle)</h3>\n<table>\n<thead>\n<tr>\n<th>Character</th>\n<th>Evidence</th>\n<th>What careful players may notice</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td><strong>Dr. Jetski / Nurse Pepper</strong></td>\n<td>E2-A, E2-E</td>\n<td>Paralysis <strong>&lt;15s</strong>, before lights cut. Neither could hold a blade for the carotid.</td>\n</tr>\n<tr>\n<td><strong>Dr. Homes</strong></td>\n<td>E2-A</td>\n<td>Assisting staff down before incision window; killer needed darkness prep, not OR panic.</td>\n</tr>\n<tr>\n<td><strong>Lacey Lovely</strong></td>\n<td>E2-B, E2-C</td>\n<td>Director codes on vault and admin-tier blackout, yes, but override was <strong>not</strong> from OR or anesthesia console. Access fits a <strong>facilitator</strong>, not the cutter at the table.</td>\n</tr>\n<tr>\n<td><strong>Dr. Curie</strong></td>\n<td>E2-C</td>\n<td>Blackout authorization tier is admin/executive, not surgery chief. Motive-heavy, mechanism-light.</td>\n</tr>\n<tr>\n<td><strong>Uvula Sachs</strong></td>\n<td>E2-F</td>\n<td>Wife hunt and coercion, not OR entry. Street layer, not the silent kill.</td>\n</tr>\n</tbody>\n</table>\n<h2>Episode 3, THE HUMAN COST</h2>\n<table>\n<thead>\n<tr>\n<th>ID</th>\n<th>Evidence</th>\n<th>Type</th>\n<th>Found where</th>\n<th>Points to</th>\n<th>Dropped</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td>E3-A</td>\n<td><strong>Missing keycard log page</strong></td>\n<td>Physical</td>\n<td>Melody's discovery</td>\n<td>OR corridor access; <strong>Ray tore page</strong> pre surgery</td>\n<td>Ep 3, Melody (if survives)</td>\n</tr>\n<tr>\n<td>E3-B</td>\n<td><strong>KCl syringe</strong></td>\n<td>Prop</td>\n<td>Pharmacy hallway</td>\n<td>Murder attempt on Melody</td>\n<td>Ep 3 cutscene</td>\n</tr>\n<tr>\n<td>E3-C</td>\n<td><strong>Alfie's hunting knife</strong></td>\n<td>Prop</td>\n<td>Dropped in panic</td>\n<td>Alfie meant to kill De Worsti, parallel motive</td>\n<td>Ep 3 panic</td>\n</tr>\n<tr>\n<td>E3-D</td>\n<td><strong>Sachs's wire cutters</strong></td>\n<td>Prop</td>\n<td>Discovered on search</td>\n<td>Sachs planned own blackout, not the kill</td>\n<td>Ep 3 panic</td>\n</tr>\n<tr>\n<td>E3-E</td>\n<td><strong>Melody's whisper</strong></td>\n<td>Testimony</td>\n<td>If antidote succeeds</td>\n<td><em>\"Security badge… in the OR log…\"</em></td>\n<td>Ep 3 puzzle pass</td>\n</tr>\n</tbody>\n</table>\n<h3>Antidote puzzle (live)</h3>\n<table>\n<thead>\n<tr>\n<th>Element</th>\n<th>Detail</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td>Symptom</td>\n<td>Potassium chloride overdose / hyperkalemia</td>\n</tr>\n<tr>\n<td>Solution</td>\n<td><strong>Calcium gluconate</strong> stated within 3 minutes</td>\n</tr>\n<tr>\n<td>Fail state</td>\n<td>Melody comatose, lose E3-A direct delivery</td>\n</tr>\n</tbody>\n</table>\n<h3>E3 absolution shifts (subtle)</h3>\n<table>\n<thead>\n<tr>\n<th>Character</th>\n<th>Evidence</th>\n<th>What careful players may notice</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td><strong>Alfie De Worsti</strong></td>\n<td>E3-C</td>\n<td>Hunting knife: <strong>no OR blood</strong>; kill used surgical steel, not fixed blade. Parallel plan, not the incision.</td>\n</tr>\n<tr>\n<td><strong>Uvula Sachs</strong></td>\n<td>E3-D</td>\n<td>Wire cutters for doors/power, not carotid work. Someone beat her to the blackout.</td>\n</tr>\n<tr>\n<td><strong>Dr. Curie</strong></td>\n<td>E3-A</td>\n<td>Torn log page: surgery-chief card checked out pre surgery, return field blank. Supports <strong>badge theft</strong>, not Curie at the reader.</td>\n</tr>\n<tr>\n<td><strong>Officer Ray</strong></td>\n<td>E3-B</td>\n<td>KCl on Melody points at someone silencing the desk, not exonerating him.</td>\n</tr>\n</tbody>\n</table>\n<h2>Episode 4, FINAL CALL</h2>\n<table>\n<thead>\n<tr>\n<th>ID</th>\n<th>Evidence</th>\n<th>Type</th>\n<th>Source</th>\n<th>Connects</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td>E4-A</td>\n<td><strong>Two synchronized footsteps</strong></td>\n<td>Testimony</td>\n<td>Alfie</td>\n<td>Pair entered OR corridor</td>\n</tr>\n<tr>\n<td>E4-B</td>\n<td><strong>Genevieve revelation</strong></td>\n<td>Testimony</td>\n<td><strong>Alfie (hedged)</strong> + Melody corroborates + <strong>Lacey denies murder</strong></td>\n<td>Identity/motive established; Lacey claims she only wanted to run</td>\n</tr>\n<tr>\n<td>E4-C</td>\n<td><strong>CD Vance raw mainframe</strong></td>\n<td>Digital</td>\n<td>Vance</td>\n<td><strong>Curie's</strong> card at OR reader during 60s blackout (Curie was in corridor; Ray stole badge)</td>\n</tr>\n<tr>\n<td>E4-D</td>\n<td><strong>Edited vs. raw timestamps</strong></td>\n<td>Digital</td>\n<td>Vance botch</td>\n<td>Anomalies Ray planted or exploited</td>\n</tr>\n<tr>\n<td>E4-E</td>\n<td><strong>Surgical perfection</strong></td>\n<td>Medical</td>\n<td>Autopsy / staff</td>\n<td><strong>Red herring</strong> pointing at Curie; wound reads rage/framing, not neat theatre work</td>\n</tr>\n<tr>\n<td>E4-F</td>\n<td><strong>Newspaper clipping, G.A. missing</strong></td>\n<td>Card</td>\n<td>After Alfie's reveal</td>\n<td><em>G.A.</em> = Genevieve De Worsti; domestic violence; withdrawn police call; financier's spin</td>\n</tr>\n<tr>\n<td>E4-G</td>\n<td><strong>De Worsti's ledger</strong></td>\n<td>Puzzle</td>\n<td>Hidden</td>\n<td>Sachs wants millions; motive web</td>\n</tr>\n<tr>\n<td>E4-H</td>\n<td><strong>Newspaper clipping, sanctuary fire</strong></td>\n<td>Card</td>\n<td>Ep 4 (with ledger or press packet)</td>\n<td>Arson tied to Indigo financier; De Worsti not named; links to ledger \"sanctuary contact\"</td>\n</tr>\n</tbody>\n</table>\n<h3>E4 absolution shifts (subtle)</h3>\n<table>\n<thead>\n<tr>\n<th>Character</th>\n<th>Evidence</th>\n<th>What careful players may notice</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td><strong>Dr. Curie</strong></td>\n<td>E4-C + E3-A + corridor witnesses</td>\n<td>Card in log, person in corridor: <strong>opportunity without presence</strong>. Orphanage photo (E2-D) = bond, not blade.</td>\n</tr>\n<tr>\n<td><strong>Dr. Homes</strong></td>\n<td>E4-E</td>\n<td>Wound <strong>inconsistent with calm theatre incision</strong>; rage read or deliberate framing while he held the scalpel when lights returned.</td>\n</tr>\n<tr>\n<td><strong>Lacey Lovely</strong></td>\n<td>E4-B + E2-B/E2-C</td>\n<td>Motive and admin access established; she <strong>denies murder</strong> and mechanism evidence fits security/facilitator tier, not director at the table.</td>\n</tr>\n<tr>\n<td><strong>Alfie / Sachs</strong></td>\n<td>E3-C, E3-D, E4-E</td>\n<td>Wrong tools + wrong wound profile for street weapons.</td>\n</tr>\n</tbody>\n</table>\n<h3>Accusation logic chain</h3>\n<pre><code>Alfie names Genevieve + abuse + surgery (E4-B)\n+ Melody corroborates face (E4-B)\n+ Vance wife hunt logs pointed at admin tier (E2-F)\n+ Newspaper G.A. match (E4-F)\n+ Pharmacy vault (security override) + Blackout (security office) + Night vision (Ray stock)\n+ Keycard raw log (<strong>Curie's</strong> badge in OR during blackout; Curie elsewhere, Ray had no OR access)\n+ Childhood photo (Genevieve + Curie) = red herring, not proof of kill\n= Officer Ray (alone, or Ray + Lacey if room believes she knew)\n</code></pre>\n<h2>Red herrings vs. real culpability</h2>\n<table>\n<thead>\n<tr>\n<th>Suspect</th>\n<th>Looks guilty because…</th>\n<th>Actually…</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td><strong>Dr. Homes</strong></td>\n<td>Blood, scalpel, standing over body on tile</td>\n<td>Framed; wound violent and crazed</td>\n</tr>\n<tr>\n<td><strong>Sachs</strong></td>\n<td>Wire cutters; enforcer rep; Ray may push</td>\n<td>Planned squeeze; didn't make the incision</td>\n</tr>\n<tr>\n<td><strong>Alfie</strong></td>\n<td>Knife; insurance; brother hatred</td>\n<td>Parallel murder plan; not the OR kill</td>\n</tr>\n<tr>\n<td><strong>Jetski</strong></td>\n<td>Anesthesia tray</td>\n<td>Unwitting; paralyzed pre blackout</td>\n</tr>\n<tr>\n<td><strong>CD Vance</strong></td>\n<td>CCTV gaps; hacking; Sachs's wife hunt</td>\n<td>Coerced by Sachs; raw log helps investigators</td>\n</tr>\n<tr>\n<td><strong>Dr. Curie</strong></td>\n<td>Sanctuary bond; surgical skill; charm; OR corridor</td>\n<td>Red herring; wanted him dead, did not cut</td>\n</tr>\n<tr>\n<td><strong>Officer Ray</strong></td>\n<td>Debt to De Worsti; runs investigation</td>\n<td><strong>Killer</strong>; security keycard in OR during blackout; Lacey's close friend</td>\n</tr>\n</tbody>\n</table>\n<h2>Prop tracker (physical checklist)</h2>\n<p>Full printable list with evidence copy: <strong><a href=\"15-evidence-materials.md\">15-evidence-materials.md</a></strong> → <strong>PROPS LIST</strong>.</p>\n<table>\n<thead>\n<tr>\n<th>Prop</th>\n<th>Assigned player</th>\n<th>Plant / reveal</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td>VIP Wing Logbook</td>\n<td>Nurse Pepper</td>\n<td>Ep 1+, gated access</td>\n</tr>\n<tr>\n<td>Tampered vial</td>\n<td>Ray (planted)</td>\n<td>Ep 1, trash</td>\n</tr>\n<tr>\n<td>P.I. dossier</td>\n<td>De Worsti (dead)</td>\n<td>Ep 1, coat</td>\n</tr>\n<tr>\n<td>Wire cutters</td>\n<td>Sachs</td>\n<td>Ep 3, discovered</td>\n</tr>\n<tr>\n<td>Hunting knife</td>\n<td>Alfie</td>\n<td>Ep 3, dropped</td>\n</tr>\n<tr>\n<td>Newspaper clippings (E4-F, E4-H)</td>\n<td>Host</td>\n<td>Ep 4</td>\n</tr>\n<tr>\n<td>De Worsti's ledger</td>\n<td>Host (hidden)</td>\n<td>Ep 4</td>\n</tr>\n<tr>\n<td>Hospital ID ×10</td>\n<td>All</td>\n<td>Session start</td>\n</tr>\n<tr>\n<td>Antidote puzzle card</td>\n<td>Host</td>\n<td>Ep 3</td>\n</tr>\n<tr>\n<td>Accusation + moral verdict ballots ×10</td>\n<td>Host</td>\n<td>Ep 4</td>\n</tr>\n</tbody>\n</table>", "15-evidence-materials": "<h1>Evidence Materials, Player Readable</h1>\n<p><strong>For players.</strong> Print each evidence card when it enters play (see <a href=\"04-evidence-index.md\">04-evidence-index.md</a> for when to drop).<br />\nEach entry: short description + full text to read aloud or hand out.</p>\n<h2>EPISODE 1</h2>\n<h3>E1-A, Blood pattern card</h3>\n<p><strong>Description:</strong> OR floor diagram showing two distinct blood behaviors near the operating table. Suggests bleeding started before the blackout and was interrupted when the lights cut.</p>\n<p><strong>Text:</strong></p>\n<blockquote>\n<p><strong>ST. SAPHICCA'S PROGRESSIVE CARE, VIP OR TWO, FLOOR SKETCH (HOST COPY)</strong><br />\nAnnotated by Officer Ray, LC-4471  </p>\n<p><strong>Zone A (pre blackout):</strong> Controlled drip pattern, south side of table, consistent with arterial spray from elevated position. Small volume. Precise.<br />\n<strong>Zone B (post blackout):</strong> Interrupted splash and smear, east tile, as if someone moved fast in the dark or a body shifted.<br />\n<strong>Note:</strong> Pattern does not match a single panicked surgeon standing in place. Two phases. Two behaviors.<br />\n<strong>Clinical footnote (subtle):</strong> If Dr. Homes made the carotid cut while frozen at center table, Zone A and Zone B would likely read as one continuous spray. The gap suggests <strong>action in the dark after staff were already down</strong>, not one uninterrupted rage stroke from the primary surgeon's position.</p>\n</blockquote>\n<h3>E1-B, Tampered IV vial</h3>\n<p><strong>Description:</strong> Empty anesthesia vial found in OR waste. Seal broken and re-set; pharmacy sticker does not match batch records.</p>\n<p><strong>Text:</strong></p>\n<blockquote>\n<p><strong>PHARMACY RETURN TAG, VIP WING</strong><br />\nDrug: Propofol 200mg/20mL (anesthesia)<br />\nBatch: SJ-8841 (VOID)<br />\nDispensed from: <strong>Secure Pharmacy Vault</strong>, executive tier access required<br />\nSeal status: <strong>COMPROMISED</strong>, outer cap rotated, inner ring puncture inconsistent with standard draw<br />\nFound: OR Two waste bin, 11:58 p.m.<br />\nHandwriting (nurse): <em>\"Seal looked wrong. Too clean. Like someone opened it and pretended they hadn't.\"</em></p>\n</blockquote>\n<h3>E1-C, Private investigator dossier</h3>\n<p><strong>Description:</strong> Folded report in De Worsti's coat pocket. Hired to find a vanished wife; mentions facial reconstruction and a childhood friend near the Sapphic Quarter. Notes client chose St. Saphicca's for a <strong>real</strong> surgical booking, not cover alone. <strong>No first name</strong> until Alfie speaks in Episode 4.</p>\n<p><strong>Text:</strong></p>\n<blockquote>\n<p><strong>CONFIDENTIAL, INVESTIGATIVE SUMMARY</strong><br />\nClient: A.A. (financier, Indigo District)<br />\nSubject: Female, late 20s at time of disappearance, married client [REDACTED] years<br />\nLast known: Cohabiting with client; subject removed from shared accounts without authorization<br />\nClient alleges: Theft of family business funds; unstable behavior; possible cosmetic surgery to evade recovery<br />\nLeads:<br />\n to  Regional youth sanctuary records (childhood contact: male, same cohort, medical training suspected)<br />\n to  Sapphic Quarter clinic network, facial reconstruction intake flags (3 clinics, 2 false positives)<br />\n to  Hospital admin cross reference (VIP medical corridors, Lesbian City metro)<br />\nSurgical booking: <strong>St. Saphicca's VIP arterial repair</strong>, legitimate indication (compromised vessel); client chose director's hospital personally<br />\nStatus: <strong>ACTIVE HUNT</strong>, surgery used as proximity + leverage<br />\nInvestigator note: <em>\"Client does not want her found for reconciliation. He wants her cornered while he's on her table.\"</em></p>\n</blockquote>\n<h3>E1-D, Scalpel in Dr. Homes's hand</h3>\n<p><strong>Description:</strong> Not a printed card. Scene fact read by the host when players examine the OR after the blackout.</p>\n<p><strong>Text:</strong></p>\n<blockquote>\n<p>When backup lighting returned, Dr. Homes was at the center table with bloody gloves and a scalpel in his hand. De Worsti lay on the tile beside it, carotid opened with a scalpel in a violent, passionate stroke that looked almost crazed, IV lines pulled loose, monitors dark. Staff testimony: Homes shouted for failover power; he claims the blade was pulled from his grip during the blackout.<br />\n<strong>Subtle absolution seed:</strong> Pepper and Jetski were already unconscious on the tile. The incision window opened <strong>after</strong> their motor drop (confirmed Ep 2). Homes holding the blade when lights returned is <strong>timing and terror</strong>, not proof he made the cut in the dark.</p>\n</blockquote>\n<h3>E1-E, Flatlined monitor</h3>\n<p><strong>Description:</strong> Atmospheric anchor for time of death. Host reads when players ask about vitals timing.</p>\n<p><strong>Text:</strong></p>\n<blockquote>\n<p><strong>OR MONITOR LOG EXCERPT, 11:42 p.m.</strong><br />\nHeart rate: erratic → flatline during grid failure<br />\nBackup lighting: 11:42:58 p.m. (approx. 60 seconds dark)<br />\nCode called: 11:43:12 p.m. (Melody, VIP reception)</p>\n</blockquote>\n<h2>EPISODE 2</h2>\n<h3>E2-A, Toxicology screen</h3>\n<p><strong>Description:</strong> Lab results from Nurse Pepper's folder. Proves knockout was engineered; paralysis hit before the lights cut.</p>\n<p><strong>Text:</strong></p>\n<blockquote>\n<p><strong>TOXICOLOGY, VIP OR TWO, A. AUSTIN + STAFF EXPOSURE</strong><br />\nPropofol: elevated metabolites, batch inconsistent with labeled vial<br />\nMidazolam: trace synergy, non standard cocktail<br />\nParalytic onset (estimated): <strong>&lt;15 seconds</strong> from IV push<br />\nClinical note: <em>\"Consistent with engineered incapacitation of anesthesia staff and assisting nurse before incision window. Subject on table partially aware during early blackout phase.\"</em><br />\n<strong>Subtle absolution:</strong> Dr. Jetski and Nurse Pepper <strong>cannot</strong> be the carotid cutter. Whoever finished De Worsti needed the room cleared first, plus darkness or night vision. Dr. Homes was still conscious at the table, which narrows but does not clear him until blood pattern and wound profile land.</p>\n</blockquote>\n<h3>E2-B, Pharmacy vault log</h3>\n<p><strong>Description:</strong> Facilities report showing who opened the secure vault before surgery. Executive tier code used two hours pre op.</p>\n<p><strong>Text:</strong></p>\n<blockquote>\n<p><strong>SECURE PHARMACY VAULT ACCESS LOG</strong><br />\nDate: [TONIGHT]<br />\n9:38 p.m., Vault open, authorization: <strong>LACEY LOVELY</strong>, Executive Director<br />\nAction: Single vial removal, anesthesia tier<br />\n9:41 p.m., Vault sealed<br />\nNote (facilities): <em>\"Director Lovely has standing crisis access. Unusual for personal retrieval; no surgery scheduled in her name.\"</em><br />\n<strong>Subtle absolution:</strong> Executive vault codes prove <strong>access</strong>, not <strong>hands on the blade</strong>. Security staff with long tenure may memorize director emergency tiers. Pair with E2-C: blackout came from admin/executive console, not Lacey's physical location in admin two floors up.</p>\n</blockquote>\n<h3>E2-C, Power override log</h3>\n<p><strong>Description:</strong> Grid console record of the VIP wing blackout. Manual override from admin or IT tier, not storm failure alone.</p>\n<p><strong>Text:</strong></p>\n<blockquote>\n<p><strong>ECO GRID FAILOVER, VIP WING B</strong><br />\n11:42:01 p.m., <strong>MANUAL OVERRIDE</strong>, generator bypass, 60 second total dark window<br />\nAuthorization tier: <strong>ADMIN / EXECUTIVE</strong> (not surgical)<br />\nStorm stress: elevated but <strong>not</strong> sufficient for isolated VIP failure<br />\nIT note (Vance): <em>\"Override came from upstairs terminal. Not OR console. Not anesthesia.\"</em></p>\n</blockquote>\n<h3>E2-D, Orphanage photo</h3>\n<p><strong>Description:</strong> Faded print from an old staff locker. Two children at a regional youth sanctuary. Connects to P.I. dossier \"childhood contact\" after Alfie's reveal.</p>\n<p><strong>Text:</strong></p>\n<blockquote>\n<p><strong>PHOTO, REVERSE INSCRIPTION (faded):</strong><br />\n<em>\"G. + C., sanctuary summer, before anyone promised us safety.\"</em><br />\nTwo children, arms linked, squinting at camera. Girl: guarded smile. Boy: already standing like he's protecting someone.<br />\n<em>(No adult names. No hospital badge. Easy to miss if players don't look in lockers.)</em></p>\n</blockquote>\n<h3>E2-E, Jetski testimony summary</h3>\n<p><strong>Description:</strong> Official statement card from recovery ward interrogation. Jetski collapsed before backup lighting.</p>\n<p><strong>Text:</strong></p>\n<blockquote>\n<p><strong>WITNESS STATEMENT, DR. JETSKI</strong><br />\nLocation: OR Two, anesthesia console, south wall<br />\nTimeline: IV lag → motor drop → floor impact <strong>before</strong> red backup lighting<br />\nConsciousness: impaired; could not hold instruments; could not see clearly<br />\nStatement: <em>\"I didn't make any cut. I was already down when the room went black. Whoever did this didn't need my hands. They needed me gone.\"</em></p>\n</blockquote>\n<h3>E2-F, Vance search logs</h3>\n<p><strong>Description:</strong> Terminal export showing coerced database sweeps. Sachs ordered a hunt for the client's vanished wife; trails point at hospital admin tier.</p>\n<p><strong>Text:</strong></p>\n<blockquote>\n<p><strong>CONTRACTOR QUERY LOG, CD VANCE, SERVER ROOM</strong><br />\nRequest origin: external (flagged: <strong>SACHS INDIGO COLLECTIONS</strong>)<br />\nSearch terms: facial reconstruction intake, name change, clinic metro, \"runaway spouse,\" stolen ledger<br />\nHits: 14 clinics, 3 reconstruction flags, 1 partial admin cross match<br />\n<strong>ST. SAPHICCA'S PROGRESSIVE CARE, EXECUTIVE ACCESS PATTERNS, ANOMALY</strong><br />\nVance note (typed, panicked): <em>\"I was looking for whoever stole his money. I didn't know her name. I didn't know it was her.\"</em><br />\nTimestamp gap: one 11:42 p.m. edit flagged <strong>POST INCIDENT</strong></p>\n</blockquote>\n<h2>EPISODE 3</h2>\n<h3>E3-A, Missing keycard log page</h3>\n<p><strong>Description:</strong> Torn page from the VIP master keycard book. Melody noticed it before surgery. Links OR corridor access to <strong>Curie's surgery-chief badge</strong> (Ray tore the page to hide the theft).</p>\n<p><strong>Text:</strong></p>\n<blockquote>\n<p><strong>VIP MASTER KEYCARD LOG, EXTRACT (PAGE MISSING FROM BINDER)</strong><br />\n11:15 p.m., Card #VIP-OR-07, checkout: <strong>Surgery chief tier (Dr. Curie)</strong><br />\nDestination: Eastern secure corridor, OR Two approach<br />\nReturn field: <strong>BLANK</strong><br />\nDesk note (Melody, handwriting): <em>\"Page was already gone when I called the code. Someone tore it out before surgery.\"</em></p>\n</blockquote>\n<h3>E3-B, KCl syringe</h3>\n<p><strong>Description:</strong> Glass syringe found beside Melody in the pharmacy hallway. Potassium chloride overdose attempt.</p>\n<p><strong>Text:</strong></p>\n<blockquote>\n<p><strong>PHARMACY HALLWAY, EVIDENCE TAG</strong><br />\nItem: Prefilled syringe, potassium chloride 20mEq<br />\nLabel partially scratched<br />\nFound: beside unconscious staff member (Melody, reception)<br />\nRay note: <em>\"Someone wanted the desk quiet.\"</em></p>\n</blockquote>\n<h3>E3-C, Alfie's hunting knife</h3>\n<p><strong>Description:</strong> Blade dropped during Ep 3 panic. Proves Alfie brought violence tonight, not the OR incision.</p>\n<p><strong>Text:</strong></p>\n<blockquote>\n<p><strong>PERSONAL EFFECTS, VIP LOADING BAY</strong><br />\nItem: Fixed blade hunting knife, concealed carry wrap<br />\nOwner statement (Alfie De Worsti): <em>\"Delivery driver cover. I came for my brother. I didn't get to him.\"</em><br />\nBlood: none on blade (OR kill used surgical steel, not this)</p>\n</blockquote>\n<h3>E3-D, Sachs's wire cutters</h3>\n<p><strong>Description:</strong> Industrial cutters found on search. Sachs planned her own squeeze tonight; she did not make the carotid cut.</p>\n<p><strong>Text:</strong></p>\n<blockquote>\n<p><strong>PERIMETER SEARCH, VIP ACCESS CORRIDOR</strong><br />\nItem: Industrial wire cutters, worn handles<br />\nSachs statement: <em>\"For krits and toors, not throats. Someone peat me to the plackout, and fix the lighting in this corridor while you're at it.\"</em><br />\nEngraving (faded): collection crest, Indigo District</p>\n</blockquote>\n<h3>E3-E, Melody's whisper</h3>\n<p><strong>Description:</strong> If antidote puzzle succeeds, Melody survives long enough to name admin and Curie. Host reads; not a physical card unless printed.</p>\n<p><strong>Text:</strong></p>\n<blockquote>\n<p><strong>MELODY, POST ANTIDOTE (weak):</strong><br />\n<em>\"It's not just him… it's everything… all of you… admin computer… and Curie…\"</em><br />\n<em>(She loses consciousness again before details. Enough to send Ray upstairs.)</em></p>\n</blockquote>\n<h3>Antidote puzzle card (live play)</h3>\n<p><strong>Description:</strong> Host card for Episode 3. Players must name the correct treatment within three minutes or Melody stays comatose.</p>\n<p><strong>Text:</strong></p>\n<blockquote>\n<p><strong>SYMPTOM:</strong> Cardiac arrhythmia, peaked T waves, paralysis progression, potassium chloride overdose<br />\n<strong>QUESTION:</strong> What do you administer?<br />\n<strong>ANSWER:</strong> <strong>Calcium gluconate</strong> (or accepted clinical equivalent stated clearly)<br />\n<strong>FAIL:</strong> Melody unavailable for direct testimony; E3-A must come through trade with another player</p>\n</blockquote>\n<h2>EPISODE 4</h2>\n<h3>E4-A, Two synchronized footsteps</h3>\n<p><strong>Description:</strong> Alfie testimony heard during final interviews. Suggests a pair moved in the OR corridor during the blackout window.</p>\n<p><strong>Text:</strong></p>\n<blockquote>\n<p><strong>WITNESS NOTE, ALFIE AUSTIN</strong><br />\n<em>\"I was on the loading route. I heard footsteps in the secure corridor, two people, matched pace, like they rehearsed it. Not running. Not storming. Just… efficient. I thought it was staff. Now I don't know.\"</em></p>\n</blockquote>\n<h3>E4-B, Genevieve revelation</h3>\n<p><strong>Description:</strong> Not a single card. Alfie speaks in scene; Melody corroborates with archival photos; Lacey denies the murder. Host distributes <strong>E4-F</strong> and <strong>E4-H</strong> after Alfie names Genevieve.</p>\n<p><strong>Text:</strong></p>\n<blockquote>\n<p>See <a href=\"05-episode-scripts.md\">05-episode-scripts.md</a> → <em>Alfie Reveals Genevieve</em>.<br />\nPlayers connect spoken testimony to <strong>E2-D</strong> photo, <strong>E2-F</strong> admin trails, and newspaper clippings below.</p>\n</blockquote>\n<h3>E4-C, Raw mainframe keycard log</h3>\n<p><strong>Description:</strong> Vance pulls unedited data. Shows <strong>Dr. Curie's</strong> OR keycard at the reader during the 60 second blackout. Curie was in the corridor ,  Ray stole the badge and Curie never noticed until tonight.</p>\n<p><strong>Text:</strong></p>\n<blockquote>\n<p><strong>MAINFRAME RAW, VIP KEYCARD (UNEDITED)</strong><br />\n11:42:04 p.m., Card #VIP-OR-07, <strong>DR. CURIE</strong>, surgery chief tier<br />\nReader: Eastern secure corridor → OR Two approach<br />\nDuration: 58 seconds inside blackout window<br />\nCompare: edited log (E4-D) shows <strong>NO ENTRY</strong><br />\nCurie statement (if asked): <em>\"That's my clearance. I was not at that reader. I don't know when my card left my person.\"</em></p>\n</blockquote>\n<h3>E4-D, Edited vs. raw timestamps</h3>\n<p><strong>Description:</strong> Proof of cover up. Someone ordered Vance to scrub the blackout window after the murder.</p>\n<p><strong>Text:</strong></p>\n<blockquote>\n<p><strong>LOG COMPARISON, VANCE WORKSTATION</strong><br />\nRaw timestamp: 11:42:04 p.m., <strong>Dr. Curie</strong>, surgery chief card, OR corridor<br />\nPublished timestamp: <strong>[ENTRY REMOVED]</strong><br />\nEdit authorization: <strong>ADMIN DIRECTIVE</strong>, voice match flagged: Director Lovely<br />\nVance note: <em>\"I botched it. Left the gap. I'm sorry. I'm sorry. eep.\"</em></p>\n</blockquote>\n<h3>E4-E, Surgical perfection report</h3>\n<p><strong>Description:</strong> Medical assessment of the kill wound. Violent scalpel work that could read as rage or skill.</p>\n<p><strong>Text:</strong></p>\n<blockquote>\n<p><strong>PRELIMINARY WOUND ASSESSMENT, MORGUE COPY</strong><br />\nSingle carotid scalpel wound; violent entry, ragged in places, reads as passionate rage<br />\nProfile: <strong>could be surgeon or killer in a frenzy</strong>, scalpel weapon, night or low light suspected<br />\nConsistent with: attending surgeon in controlled conditions <strong>or</strong> primary surgeon acting in hatred<br />\n<strong>Inconsistent with:</strong> neat theatre incision; wound looks too crazed for calm surgery<br />\nCurie note (if asked): <em>\"Homes could have done this in rage. Or someone wanted it to look that way.\"</em></p>\n</blockquote>\n<h3>E4-F, Newspaper clipping, Genevieve missing</h3>\n<p><strong>Description:</strong> Archived sidebar about a vanished wife. Name redacted as G.A. Players link to Genevieve only <strong>after</strong> Alfie's reveal.</p>\n<p><strong>Text:</strong></p>\n<blockquote>\n<p><strong>LESBIAN CITY HERALD</strong>, archived sidebar, name redacted per victim shield order  </p>\n<p><em>\"…identified only as G.A., hospitalized twice in one year for 'fall related' injuries while cohabiting with a financier later linked to predatory lending in the Indigo District. Neighbors reported shouting. One prior domestic call withdrawn before officers arrived. Subject vanished in [YEAR]. Financier told police she was 'unstable' and had stolen from family business. Recovery efforts ongoing. No body recovered.\"</em></p>\n</blockquote>\n<h3>E4-G, De Worsti's ledger (puzzle)</h3>\n<p><strong>Description:</strong> Hidden ledger prop for final act. Sachs wants the stolen millions; room maps who owed De Worsti and who hunted the money.</p>\n<p><strong>Text:</strong></p>\n<blockquote>\n<p><strong>LEDGER EXTRACT, INDIGO DISTRICT OPERATIONS</strong><br />\n<em>(Handwritten, water damaged)</em>  </p>\n<p>A.A., collections, VIP medical cover<br />\nOutstanding: Ray [security], Jetski/Alfie [gambling], Sachs [enforcement split]<br />\n<strong>REPOSSESSION LIST:</strong> G.A., wife, full account freeze, <strong>sanctuary contact</strong> [fire incident, see press]<br />\n<strong>STOLEN / UNRECOVERED:</strong> $2.4M moved offshore, subject fled<br />\nMargin note (De Worsti): <em>\"She doesn't get to buy a new face with my money.\"</em>  </p>\n<p>Puzzle goal: match names to players; understand why half the wing was in his debt tonight</p>\n</blockquote>\n<h3>E4-H, Newspaper clipping, sanctuary fire</h3>\n<p><strong>Description:</strong> Older article about an arson death tied to a debt operation. <strong>De Worsti is not named</strong>; descriptors match his methods and the P.I. dossier's \"message\" to a runaway wife.</p>\n<p><strong>Text:</strong></p>\n<blockquote>\n<p><strong>LESBIAN CITY HERALD</strong>, metro section, [YEAR]  </p>\n<p><em>\"Three dead after overnight fire at regional youth sanctuary residence in the outer district. Investigators cited faulty wiring, though neighbors reported a luxury sedan leaving the scene before engines arrived. A financier known for aggressive recovery work in the Indigo District was questioned and released; sources described the blaze as 'consistent with warnings issued to debtors who involve family members.' No charges filed. A spokesperson for the recovery firm called it 'a tragic coincidence unrelated to ongoing collection matters.'\"</em>  </p>\n<p><em>(Players who connect G.A., the ledger's 'sanctuary contact,' and tonight's VIP patient should recognize the same operator.)</em></p>\n</blockquote>\n<h2>PROPS LIST (physical items)</h2>\n<p><strong>Print / craft checklist for host. Pair with evidence cards above where noted.</strong></p>\n<table>\n<thead>\n<tr>\n<th>Prop</th>\n<th>Qty</th>\n<th>Used by</th>\n<th>When</th>\n<th>Notes</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td>Hospital ID badge</td>\n<td>10</td>\n<td>All players</td>\n<td>Session start</td>\n<td>Name, role, photo slot</td>\n</tr>\n<tr>\n<td>VIP Wing Logbook</td>\n<td>1</td>\n<td>Nurse Pepper</td>\n<td>Ep 1+</td>\n<td>Pepper gates access; log timestamps</td>\n</tr>\n<tr>\n<td>Tampered anesthesia vial</td>\n<td>1</td>\n<td>Planted by Curie</td>\n<td>Ep 1 OR search</td>\n<td>Pair with <strong>E1-B</strong> card</td>\n</tr>\n<tr>\n<td>P.I. dossier folder</td>\n<td>1</td>\n<td>De Worsti's coat</td>\n<td>Ep 1 OR search</td>\n<td>Pair with <strong>E1-C</strong> card</td>\n</tr>\n<tr>\n<td>Blood pattern floor card</td>\n<td>1</td>\n<td>Host / OR</td>\n<td>Ep 1</td>\n<td><strong>E1-A</strong></td>\n</tr>\n<tr>\n<td>Scalpel (prop or tag)</td>\n<td>1</td>\n<td>Scene</td>\n<td>Ep 1</td>\n<td>Homes framing; <strong>E1-D</strong> readout</td>\n</tr>\n<tr>\n<td>Pepper's toxicology folder</td>\n<td>1</td>\n<td>Pepper</td>\n<td>Ep 2</td>\n<td><strong>E2-A</strong> inside</td>\n</tr>\n<tr>\n<td>Pharmacy vault log printout</td>\n<td>1</td>\n<td>Host</td>\n<td>Ep 2</td>\n<td><strong>E2-B</strong></td>\n</tr>\n<tr>\n<td>Power override log printout</td>\n<td>1</td>\n<td>Host</td>\n<td>Ep 2</td>\n<td><strong>E2-C</strong></td>\n</tr>\n<tr>\n<td>Orphanage photo</td>\n<td>1</td>\n<td>Locker hide</td>\n<td>Ep 2</td>\n<td><strong>E2-D</strong></td>\n</tr>\n<tr>\n<td>Vance search log printout</td>\n<td>1</td>\n<td>Vance / host</td>\n<td>Ep 2</td>\n<td><strong>E2-F</strong></td>\n</tr>\n<tr>\n<td>Torn keycard log page</td>\n<td>1</td>\n<td>Melody</td>\n<td>Ep 3</td>\n<td><strong>E3-A</strong></td>\n</tr>\n<tr>\n<td>KCl syringe (prop)</td>\n<td>1</td>\n<td>Pharmacy hall</td>\n<td>Ep 3</td>\n<td><strong>E3-B</strong></td>\n</tr>\n<tr>\n<td>Hunting knife (prop)</td>\n<td>1</td>\n<td>Alfie</td>\n<td>Ep 3</td>\n<td><strong>E3-C</strong></td>\n</tr>\n<tr>\n<td>Wire cutters (prop)</td>\n<td>1</td>\n<td>Sachs</td>\n<td>Ep 3</td>\n<td><strong>E3-D</strong></td>\n</tr>\n<tr>\n<td>Antidote puzzle card</td>\n<td>1</td>\n<td>Host</td>\n<td>Ep 3</td>\n<td>See <strong>Antidote</strong> entry</td>\n</tr>\n<tr>\n<td>Newspaper clipping, G.A. missing</td>\n<td>1</td>\n<td>Host</td>\n<td>Ep 4</td>\n<td><strong>E4-F</strong>, after Alfie</td>\n</tr>\n<tr>\n<td>Newspaper clipping, sanctuary fire</td>\n<td>1</td>\n<td>Host</td>\n<td>Ep 4</td>\n<td><strong>E4-H</strong>, with ledger or press packet</td>\n</tr>\n<tr>\n<td>De Worsti's ledger (folder)</td>\n<td>1</td>\n<td>Hidden</td>\n<td>Ep 4</td>\n<td><strong>E4-G</strong> puzzle</td>\n</tr>\n<tr>\n<td>Raw mainframe log printout</td>\n<td>1</td>\n<td>Vance</td>\n<td>Ep 4</td>\n<td><strong>E4-C / E4-D</strong></td>\n</tr>\n<tr>\n<td>Surgical assessment card</td>\n<td>1</td>\n<td>Host</td>\n<td>Ep 4</td>\n<td><strong>E4-E</strong></td>\n</tr>\n<tr>\n<td>Accusation ballot</td>\n<td>10</td>\n<td>Host</td>\n<td>Ep 4</td>\n<td>One suspect (<strong>Officer Ray</strong>) or pair (Ray + Lacey)</td>\n</tr>\n<tr>\n<td>Moral verdict ballot</td>\n<td>10</td>\n<td>Host</td>\n<td>Ep 4</td>\n<td>MURDER / JUSTICE / SYSTEM FAILURE</td>\n</tr>\n<tr>\n<td>Storm radio static cue</td>\n<td>1</td>\n<td>Host</td>\n<td>All acts</td>\n<td>Optional speaker or phone</td>\n</tr>\n<tr>\n<td>VIP patient gown (optional)</td>\n<td>1</td>\n<td>De Worsti prologue</td>\n<td>Prologue</td>\n<td>Atmospheric</td>\n</tr>\n<tr>\n<td>Flashlight (optional)</td>\n<td>1</td>\n<td>Host</td>\n<td>Ep 3</td>\n<td>Melody scene</td>\n</tr>\n</tbody>\n</table>\n<h2>HOST NOTES</h2>\n<ul>\n<li><strong>E1-C</strong> and <strong>E4-F / E4-H</strong> are designed to connect <strong>after</strong> Alfie names Genevieve, not before.  </li>\n<li><strong>E4-H</strong> never names De Worsti; room infers from financier + Indigo + sanctuary + ledger cross reference.  </li>\n<li>Red herring props (<strong>E3-C</strong>, <strong>E3-D</strong>) should feel damning but do not match the violent scalpel kill profile (<strong>E4-E</strong>).  </li>\n<li>Full drop timing: <a href=\"04-evidence-index.md\">04-evidence-index.md</a>.</li>\n</ul>", "05-episode-scripts": "<h1>Episode Scripts: Cutscenes &amp; Narrator Beats</h1>\n<p><strong>Host / facilitator copy.</strong> Player facing script (no host notes, act gates): <a href=\"player-performance-script.md\">player-performance-script.md</a></p>\n<p><em>Actor delivery lenses (exaggerated, plot unchanged):</em> <a href=\"14-actor-personas.md\">14-actor-personas.md</a></p>\n<h2>MASTER TEMPLATE (per act)</h2>\n<table>\n<thead>\n<tr>\n<th>Act</th>\n<th>Script title</th>\n<th>Narrator function</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td>1</td>\n<td>THE INCIDENT</td>\n<td>Atmospheric open → crime introduced</td>\n</tr>\n<tr>\n<td>2</td>\n<td>THE CLUE DROPS</td>\n<td>Physical evidence enters play</td>\n</tr>\n<tr>\n<td>3</td>\n<td>THE TWIST</td>\n<td>Secondary attack; theory upended</td>\n</tr>\n<tr>\n<td>4</td>\n<td>FINAL CALL</td>\n<td>Testimonies → resolution → moral verdict</td>\n</tr>\n</tbody>\n</table>\n<h2>PROLOGUE: VIP CONSULTATION SUITE</h2>\n<p><em>Read before Episode 1 live play. Establishes De Worsti, Homes, Pepper.</em></p>\n<h3>NARRATOR</h3>\n<blockquote>\n<p>St. Saphicca's Progressive Care rises above Lesbian City in glass and white stone, a hospital built for people who pay not to wait. Tonight the VIP consultation suite is still calm, soft light on the walls, the skyline visible through floor-to-ceiling windows.</p>\n<p>What no one in this room knows yet is that the storm outside is not ordinary rain. It is the kind that fills underpasses in minutes and closes causeways before the city admits it is in trouble. Down in the streets, floodwater is already pushing against curbs and swallowing the lower roads. Municipal watch has logged the warnings. Radios are starting to chatter.</p>\n<p>Inside St. Saphicca's, the generators hum. Nurses trade jokes about staying late. Security checks a door and goes back to coffee. The staff believe they are above the water line, protected, busy with one very expensive patient. They have not been told how fast the night is about to narrow.</p>\n</blockquote>\n<p><strong>ALEX AUSTIN:</strong> patient gown worn like a tailored suit. Composed. Control.</p>\n<p><strong>DR. HOMES:</strong> tablet; sparse intake file bothers him.</p>\n<p><strong>NURSE PEPPER:</strong> prepping forms; watching more than she shows.</p>\n<blockquote>\n<p><strong>HOMES:</strong> Your imaging shows a compromised arterial wall. This case is legitimate. Your intake file is still… unusually sparse, Mr. De Worsti.<br />\n<strong>ALEX:</strong> I prefer efficiency. Whatever this costs, double it. So please, no delays. No mistakes.<br />\n<strong>PEPPER:</strong> (quietly) We don't prioritize patients that way.<br />\n<strong>ALEX:</strong> Everyone prioritizes something.</p>\n</blockquote>\n<p>Tension. Pepper looks away first.</p>\n<blockquote>\n<p><strong>HOMES:</strong> This is a surgical facility, not a negotiation table. You need this repair. I am not here to flatter you.<br />\n<strong>ALEX:</strong> Everything is a negotiation table, Doctor. I chose this hospital. I expect your seniors to act like it. But I'm here to walk out better than I walked in.</p>\n</blockquote>\n<p>He adjusts his wrist, faint old bruise. Pepper notices.</p>\n<blockquote>\n<p><strong>ALEX:</strong> (softly) People don't get second chances where I come from.<br />\n(to Homes) So let's not waste this one.</p>\n</blockquote>\n<p><em>Cut to black.</em></p>\n<h2>ACT 1 / EPISODE 1: OPERATING THEATER (cutscene)</h2>\n<p><em>Host: read with medical drama pacing: clipped dialogue, machine rhythm, then violence in the silence. </em><em>Pepper</em><em> breaks from sage calm into raw terror after the lights return.</em></p>\n<h3>NARRATOR: OPEN</h3>\n<blockquote>\n<p>VIP Operating Theater Two. St. Saphicca's Progressive Care.<br />\nStorm against the glass. Inside: sterile green, machine hum, the steady beep of a heart that still believes in tomorrow.</p>\n</blockquote>\n<p>Clinical green. Overhead surgical lamps. Suction whine. The heart monitor keeps time, precise, indifferent.</p>\n<p><strong>DR. HOMES</strong> is mid operation, shoulders set, voice low and absolute. <strong>NURSE PEPPER</strong> at his elbow: forceps, gauze, eyes on every number. <strong>DR. JETSKI</strong> at the anesthesia column, fingers on the IV controls.</p>\n<p><strong>ALEX AUSTIN</strong> on the table. Sedated. Still.</p>\n<blockquote>\n<p><strong>HOMES:</strong> Arterial wall's more compromised than imaging suggested. This is borderline rupture.<br />\nJetski, tighten control. I want zero drift. Pepper, clamp.</p>\n</blockquote>\n<p><strong>PEPPER</strong> (PLAYER: crisp, professional; fear not yet in the room):</p>\n<blockquote>\n<p>Clamp in.<br />\n(beat, reading monitor)<br />\nPressure's falling. Faster than expected.</p>\n<p><strong>HOMES:</strong> Then we stabilize it. We're not chasing this. We control it.</p>\n</blockquote>\n<p><strong>JETSKI</strong> (PLAYER: uneasy, surfer bro slipping through):</p>\n<blockquote>\n<p>…hold on, man.<br />\n(blinks hard)<br />\nThat's not right. I'm getting lag. Visual lag. The IV...</p>\n</blockquote>\n<p>His hand slips against the controls.</p>\n<blockquote>\n<p><strong>JETSKI:</strong> No, no, that's...</p>\n</blockquote>\n<p><strong>The lights cut.</strong></p>\n<p>Total darkness. Not a flicker. Not a dim. <strong>Black.</strong></p>\n<p>The heart monitor stutters, one fractured tone, then nothing.</p>\n<p>A beat.</p>\n<p>Two heavy bodies hit the tile. <strong>Thud. Thud.</strong></p>\n<p><strong>JETSKI. PEPPER.</strong> Down.</p>\n<p>A choked inhale from the table: De Worsti, half aware, strangled in the dark.</p>\n<p>Then: hoses pulled loose, monitors dying mid-beep, a body dragged off the table and thrown to tile. A wet, violent sound. Passionate. Final. <strong>A scalpel through the throat in a deadly place.</strong></p>\n<p><strong>HOMES</strong> (shouting into black):</p>\n<blockquote>\n<p>Backup power! Now! Where is the grid failover, this wing is supposed to be isolated!</p>\n</blockquote>\n<p>Silence swallows his voice. Seconds stretch unnaturally long.</p>\n<p>Someone breathing too fast in the dark. Homes. Alone with whatever just happened.</p>\n<h3>EMERGENCY RED</h3>\n<p>Backup lighting flickers on, harsh, pulsing crimson.</p>\n<p>The world returns in fragments.</p>\n<p><strong>JETSKI:</strong> crumpled at the south wall, utterly still.<br />\n<strong>PEPPER:</strong> on the tile beside the table, one arm twisted under her, face turned away.<br />\n<strong>DR. HOMES:</strong> frozen at center. Bloody gloves. Scalpel still in his hand.<br />\n<strong>ALEX AUSTIN:</strong> on the floor, eyes open. Unblinking. Throat torn open with a scalpel, violent and crazed-looking, blood pooling on tile like rejected meat piled behind a butcher's counter, pale and shining under the red lamps beside instruments still arranged to save him.</p>\n<p>The monitor finds its voice again, one long, continuous tone.</p>\n<p><strong>Flatline.</strong></p>\n<blockquote>\n<p><strong>HOMES:</strong> (breathing uneven)<br />\nNo… no, that's...<br />\nI lost visibility. I couldn't...<br />\n(looking around, frantic)<br />\nSomeone was here. Someone was <em>in</em> this room.</p>\n</blockquote>\n<p>No answer.</p>\n<p><strong>PEPPER</strong> (PLAYER: first movement; small, broken sound):</p>\n<blockquote>\n<p>…nnh...</p>\n</blockquote>\n<p>She tries to push herself up. Her limbs don't answer right, lag, weight, wrong. Her hand hits something wet on the tile.</p>\n<p>She looks.</p>\n<p>Blood.</p>\n<p>Her breath catches, high, thin, <strong>terror finally breaking through the professional mask.</strong></p>\n<blockquote>\n<p><strong>PEPPER:</strong> (hoarse, climbing)<br />\nWhat... what...<br />\n(scrambling, ignoring dizziness)<br />\nOh my God... oh my God...</p>\n</blockquote>\n<p>She grabs the edge of the table. Pulls herself up. Sees <strong>De Worsti</strong>.</p>\n<blockquote>\n<p><strong>PEPPER:</strong> (voice cracking, <strong>terrified</strong>)<br />\nNo... no, no, no...<br />\n(checking reflexively, hands shaking so badly she almost can't hold them steady)<br />\nNo pulse... there's no...</p>\n</blockquote>\n<p>She looks at <strong>Homes</strong>. Blood on his gloves. The scalpel.</p>\n<p>For a second she can't make her mouth work. Pure animal fear.</p>\n<blockquote>\n<p><strong>PEPPER:</strong> (whispering, horrified)<br />\n…we were right here.<br />\n(trying to make sense of it; voice breaking)<br />\nWe were all right here. What happened to him... <strong>what happened to him...</strong></p>\n</blockquote>\n<p>She can't finish. The sage is gone. Only the nurse, shaking, in a room full of blood.</p>\n<p><strong>HOMES</strong> (PLAYER):</p>\n<blockquote>\n<p>Pepper... I didn't... the lights...</p>\n</blockquote>\n<p>She flinches. Doesn't accuse. Doesn't absolve. Just <strong>stares</strong>, shock, fear, something unraveling she won't name yet.</p>\n<p>The flatline tone fills the OR. No one moves.</p>\n<p><em>Beat. Hold it one second too long.</em></p>\n<h3>NARRATOR: AFTERMATH</h3>\n<blockquote>\n<p>Someone ran for the corridor.<br />\nSomeone screamed for help into a storm that ate sound.<br />\nThey went to find Hospital <strong>Director Lacey Lovely</strong>, and <strong>Security Chief Officer Ray</strong> (with <strong>Officer Marz</strong> on perimeter), because in a hospital, death in the OR does not stay in the OR.<br />\nIt climbs the stairs. It knocks on doors. It demands a name.</p>\n<p>The code went out on every channel the building still had. Municipal Watch logged the death. and sent back the same message the city had been sending all night: <em>shelter in place, routes flooded, units when routing permits.</em><br />\nThe backup generators finished their apology. The patrol cars did not.<br />\nInside the VIP wing, someone was already dead. Outside, the storm made sure nobody was coming to save them yet.</p>\n</blockquote>\n<p><em>Cut to → </em><em>10-the gathering.md</em><em> (all eleven players: news broken, Homes primary suspect)</em></p>\n<p><em>Then live play → </em><em>06-act2-crime scene.md</em>**</p>\n<h2>ACT 2 / EPISODE 2: THE LOGIC OF THE NEEDLE (cutscene)</h2>\n<p><strong>RECOVERY WARD</strong>: Fluorescent buzz. <strong>JETSKI</strong> on cot. <strong>RAY</strong> relentless. <strong>CURIE</strong> observing.</p>\n<p><strong>PEPPER</strong> enters with folder.</p>\n<p>Ray on terminal input at grid drop. Jetski: <em>\"Dude, I didn't touch anything.\"</em></p>\n<p><strong>CURIE</strong> (PLAYER: to Ray, quiet wit):</p>\n<blockquote>\n<p>They also don't panic. Give him air, Officer, you'll get a better witness.</p>\n</blockquote>\n<p><strong>RAY</strong> (PLAYER: gruff fondness):</p>\n<blockquote>\n<p>Don't tell me how to ask questions.</p>\n</blockquote>\n<p><strong>CURIE</strong> (PLAYER: smile, serious):</p>\n<blockquote>\n<p>I'd never. I'm only suggesting you look handsome when you're not shouting.</p>\n</blockquote>\n<p><strong>PEPPER</strong> (PLAYER: <strong>ahem</strong>, entering with folder):</p>\n<blockquote>\n<p><em>(clears throat, deadpan)</em><br />\nToxicology's ready. Whenever you two are <strong>done</strong>.</p>\n</blockquote>\n<p>Pepper drops toxicology: Propofol + Midazolam, paralysis &lt;15s.</p>\n<blockquote>\n<p><strong>PEPPER:</strong> Jetski collapsed before the lights even went out. The killer needed night vision, or immunity.<br />\n<strong>RAY:</strong> Pharmacy vault got opened. Top-level clearance. <strong>Lacey Lovely.</strong><br />\n<strong>RAY:</strong> Power got cut around the same time. That's not a coincidence. I want everything on her. Who she let in. What she's been doing.</p>\n</blockquote>\n<p><strong>CURIE</strong> (PLAYER: calm authority, not obstruction):</p>\n<blockquote>\n<p>Run it. You should run it. Executive codes on a night like this are a lead. Full stop.<br />\n(beat)<br />\nMy surgical opinion? A hospital director doesn't usually personally execute a patient on her own OR table. The access pattern fits a <strong>facilitator</strong>, not a cutter. Unlikely as primary actor, but unlikely isn't innocent. Pull her file. I'm not standing in your way.</p>\n</blockquote>\n<p><strong>RAY</strong> (short nod: trusts the tone):</p>\n<blockquote>\n<p>Good. Then we're chasing it.</p>\n</blockquote>\n<p><strong>MARZ</strong> (PLAYER, optional, painting a nail, outlandish but specific):</p>\n<blockquote>\n<p>Honey, what if the director didn't do the cutting because she was two floors up showing she <em>couldn't</em> have been in that room? That's not innocent. That's planning.</p>\n</blockquote>\n<p><strong>RAY</strong> (PLAYER, optional, gruff):</p>\n<blockquote>\n<p>Write it down. Don't preach it yet.</p>\n</blockquote>\n<p><strong>CURIE</strong> (PLAYER: brushes nonexistent lint from Ray's shoulder; casual):</p>\n<blockquote>\n<p>You've got a good instinct. Keep it.</p>\n</blockquote>\n<p><em>Ray doesn't pull away. </em><em>HOMES</em><em>, if present, looks like he might throw a chart.</em></p>\n<p><strong>PEPPER</strong> (PLAYER: optional, under breath):</p>\n<blockquote>\n<p><em>(ahem)</em></p>\n<p><strong>CURIE:</strong> Access, preparation, delivery, blackout, incision. You don't improvise that. Someone coordinated. Director's tier is on that list until it isn't.</p>\n</blockquote>\n<p>Ray: <em>\"Melody first. Then the computer kid. Every second of camera footage, and what's missing.\"</em></p>\n<p><strong>RAY</strong> (to <strong>Vance</strong>, if present or via intercom):</p>\n<blockquote>\n<p>Vance. You. Now. If Sachs put you up to anything in my building tonight, start talking before I hand you to her.</p>\n</blockquote>\n<p><strong>VANCE</strong> (PLAYER: genki speed collapse; breaking):</p>\n<blockquote>\n<p>Okay okay okay... so Sachs was like, <em>find the wife</em>, and I was like <em>eep</em> but also the query was already running? Clinic databases, reconstruction intake flags, hospital admin cross ref... I was looking for whoever stole his money! I didn't know her <strong>name</strong>! I didn't know it was <em>her</em>...</p>\n</blockquote>\n<p><em>Gestures toward </em><em>Lacey</em><em> or hides behind laptop.</em></p>\n<blockquote>\n<p><strong>VANCE:</strong> I'm not realted to the victim, I was just helping a debt collector hunt a woman who ran. That's what he built. Men like De Worsti make you dig with your own hands and your own cute little keyboard, and I'm so sorry...</p>\n</blockquote>\n<p><em>Voice cracks into squeaky panic.</em></p>\n<p><strong>SACHS</strong> (PLAYER: efficiency rage, German accent):</p>\n<blockquote>\n<p>You ton't get to moralize. You were on the clock. And your timeline is still wrong, \"around when Sachs asked\" is not a timestamp.</p>\n</blockquote>\n<p><em>Radio crackles: static, then:</em> <strong>\"LC-4471… hold position… barricade… no ETA…\"</strong> <em>Ray clicks it off without comment.</em></p>\n<p><em>Distribute </em><em>E2-F Vance search logs</em><em> if not yet given. Room should feel De Worsti's world was rotting the wing before the murder.</em></p>\n<p><strong>CURIE</strong> (PLAYER: to window, dry charm):</p>\n<blockquote>\n<p>Some people don't die in hospitals, Officer… they get released.</p>\n</blockquote>\n<p><strong>RAY</strong> (PLAYER: tired smile he hates himself for):</p>\n<blockquote>\n<p>You say stuff like that so I forget you're on my list.</p>\n</blockquote>\n<p><strong>CURIE</strong> (PLAYER: without turning):</p>\n<blockquote>\n<p>I'm on your board. I'm also the best partner you've got tonight. Use me accordingly.</p>\n</blockquote>\n<p><em>Photo peeks from folder: Genevieve and Curie, children. No one sees it.</em></p>\n<p><em>Distribute E2 evidence cards. Resume live investigation.</em></p>\n<h2>ACT 3 / EPISODE 3: FOUND IN THE DARK (cutscene)</h2>\n<p>Pharmacy wing hallway. Flashing lights. Scream cut short.</p>\n<p><strong>RAY:</strong> (weapon drawn) Security! Step away!</p>\n<p>Flashlight on <strong>MELODY</strong>, unconscious, syringe rolling. <strong>CURIE</strong> kneeling, panicked.</p>\n<blockquote>\n<p><strong>CURIE:</strong> Potassium chloride overdose! Shadow running toward administration. Go, Ray!<br />\n<strong>RAY:</strong> Did you see who...<br />\n<strong>CURIE:</strong> Move!</p>\n</blockquote>\n<p>Ray sprints. Curie's expression goes cold.</p>\n<p><strong>MELODY:</strong> (weak) It's not just him… it's everything… all of you…</p>\n<p><em>Host: Antidote puzzle. Alfie's knife + Sachs's cutters drop during panic.</em></p>\n<h2>ACT 4 / EPISODE 4: ALFIE REVEALS GENEVIEVE (cutscene)</h2>\n<p><em>Recovery Lounge again. Evidence on the table. Homes is no longer the only name in the room. </em><em>ALFIE</em><em> has been cornered: insurance papers, brother's ledger, or Ray's direct question. He breaks.</em></p>\n<p><strong>RAY</strong> (PLAYER or host, hard):</p>\n<blockquote>\n<p>Your brother kept a wife locked up for years. Detective file says new face. New name. You said you came here with medical supplies. Start talking straight.</p>\n</blockquote>\n<p><strong>ALFIE</strong> (PLAYER: must deliver; do not skip; <strong>truth through uncertainty</strong>):</p>\n<blockquote>\n<p>I... look. I'm not trying to bury my brother. I'm not trying to hang anyone either. I just… I can't keep my mouth shut anymore.</p>\n<p>(beat)</p>\n<p>As far as I know, his wife, his <em>first</em> wife, her name was <strong>Genevieve</strong>. Maybe it still is, somewhere under all this. I don't know what you call yourself now.</p>\n<p>(glances at <strong>Lacey</strong>, pained)</p>\n<p>De Worsti wasn't just a lender. Not at the end. He was… whatever he became. Men like Sachs at the door. Ledgers. Genevieve didn't run that house, she <strong>survived</strong> it, as best I could tell from the outside. I think he moved her when he wanted. I think he took her phone when he wanted. I <strong>saw</strong> bruises once. Holidays where she wouldn't eat. I could be wrong about some of it, he told the family she was unstable, and when you're family you want to believe that.</p>\n<p>(voice cracks)</p>\n<p>But I don't think I was wrong. Not about the flinching.</p>\n<p>(beat, softer)</p>\n<p>When she disappeared, when she took money and ran, De Worsti called it theft. Like she was property. Hunters. Clinic lists. I didn't know where she landed. I'm <strong>not</strong> saying I have proof of every step.</p>\n<p>(hesitates)</p>\n<p>There's an intake photo. Mainland clinic. Scar above the left ear, glass, years ago, I <strong>think</strong> it was her. Total reconstruction, maybe. New name. New life. I could be connecting dots that aren't, except De Worsti wasn't here for surgery, was he? He was here because <strong>she</strong> might be.</p>\n<p>(almost pleading)</p>\n<p>I'm telling you what I believe. I'm not saying she did anything tonight. Genevieve just wanted to <strong>run</strong>. That's what I keep coming back to. She wanted out. Not… this.</p>\n</blockquote>\n<p><em>Silence. Storm on the glass.</em></p>\n<p><strong>LACEY</strong> (PLAYER: mandatory; controlled, not crumbling):</p>\n<blockquote>\n<p>You don't know what you're talking about.</p>\n</blockquote>\n<p><strong>ALFIE</strong> (PLAYER: quiet, protective):</p>\n<blockquote>\n<p>I know enough that I didn't want to say it like this.</p>\n</blockquote>\n<p><strong>LACEY</strong> (PLAYER: stands; ice, not confession):</p>\n<blockquote>\n<p>Officer. You want the truth from me? Fine.</p>\n<p>I ran. I changed my life. I did what I had to do to never sleep in the same room as that man again.<br />\n(beat)<br />\nI did <strong>not</strong> hate him enough to kill him. I wanted distance, miles, years, a face he wouldn't recognize. Murder wasn't the plan. Running was.<br />\n(cold)<br />\nSomeone killed him in an operating theater. I was two floors up in administration. If your logs say otherwise, read them. But don't let that ghost put words in my mouth.</p>\n</blockquote>\n<p><strong>MELODY</strong> (PLAYER: corroboration, after Alfie only; firmer than Alfie):</p>\n<blockquote>\n<p>…The archival intake binders don't lie. I wondered why you looked familiar. Pre op photos. Before the reconstruction. If he's right, that's Genevieve.</p>\n</blockquote>\n<p><strong>CURIE</strong> (PLAYER: authoritative doubt, not obstruction; room hangs on it):</p>\n<blockquote>\n<p>Officer, run every log you have. I've said that all night.<br />\n(to the room)<br />\nClinically? A director with that history is a <strong>motive</strong>, not a mechanism. The throat was opened with a scalpel in a violent, almost crazed stroke. That could be a surgeon. It could be Homes in a rage. Lovely's tier fits access, not the blade. Unlikely she'd personally finish him on the table.<br />\n(beat, meets Ray's eyes)<br />\nStill a live lead. Especially if someone else held the blade for her. Don't drop it on my account.</p>\n</blockquote>\n<p><strong>PEPPER</strong> (PLAYER: <strong>ahem</strong>).</p>\n<p><strong>HOMES</strong> (PLAYER: snapped):</p>\n<blockquote>\n<p>Are we solving a murder or watching you two eye fuck over the evidence?</p>\n</blockquote>\n<p><strong>CURIE</strong> (PLAYER: pleasant, surgical):</p>\n<blockquote>\n<p>Doctor, your alibi is still bleeding. I'd focus.</p>\n</blockquote>\n<p><strong>RAY</strong> (cutting, but not at Curie):</p>\n<blockquote>\n<p>I'm not dropping it. Someone opened the vault. Someone killed the lights. Someone with the keys. And a dead man who came here chasing a woman who just wanted to get away.</p>\n</blockquote>\n<p><em>Distribute </em><em>E4-F newspaper clipping</em><em> if not yet given. Room should connect G.A. = Genevieve.</em></p>\n<p><strong>PEPPER</strong> (PLAYER: optional, if affair secret is out):</p>\n<blockquote>\n<p>I loved him. I need you to hear that. And I need you to hear that I didn't know... Genevieve. The fire. Any of it. He wasn't… he wasn't just difficult. He was what Alfie said. And the people who cut his throat still sat with us at that table.</p>\n</blockquote>\n<p><em>Host: Alfie's reveal is </em><em>mandatory</em><em>: hedged truth, protective of Lacey. Lacey's denial is </em><em>mandatory</em><em>: ran yes, killed no. Curie never blocks Ray on her background. See 11-genevieve backstory.md.</em></p>\n<h2>ACT 4 / EPISODE 4: FINAL CALL (narrator)</h2>\n<blockquote>\n<p>The storm is thinning. You can hear it in the walls, less scream, more drain.<br />\nGenevieve is in the room, whatever name she wears.<br />\nYou have a violent scalpel wound that looks like rage, executive access codes, a blackout that obeyed no accident protocol, and a victim who weaponized debt and fists the way others weaponize scalpels.<br />\nOfficer Ray is still the head of security here. Officer Marz is with him. The real watch is close, sirens somewhere below the flood line, getting closer.<br />\nBefore they walk through that door, this room decides: <strong>one suspect, or the pair.</strong> Then choose what kind of city Lesbian City becomes tonight.</p>\n</blockquote>\n<p><em>Tally accusation votes + moral verdict. Read </em><em>AFTER THE BALLOT</em><em> below, then </em><em>POLICE ARRIVAL</em><em>, then facilitator closing.</em></p>\n<h2>AFTER THE BALLOT: ENDING READOUTS</h2>\n<p><em>Host only. Read the branch that matches the room's accusation vote. Layer the </em><em>moral verdict</em><em> coda at the end of that branch. Truth reference: <a href=\"00-host-blueprint.md\">00-host-blueprint.md</a>.</em></p>\n<h3>STEP 1, NARRATOR TALLIES (all endings)</h3>\n<blockquote>\n<p>The storm thins. You can hear it in the walls, less scream, more drain.<br />\nOfficer Ray sets three folders on the table. Names. Evidence. The night's work.<br />\nMunicipal Watch is close. Sirens somewhere below the flood line, getting closer.<br />\nBefore those boots hit the lobby, this room makes its call.</p>\n</blockquote>\n<p><em>Collect accusation ballots: </em><em>one suspect</em><em> (</em><em>Officer Ray</em><em>) or </em><em>pair (Ray + Lacey Lovely)</em><em> if room believes she knew. Collect moral verdict: </em><em>MURDER</em><em> / </em><em>JUSTICE</em><em> / </em><em>SYSTEM FAILURE</em><em>.</em></p>\n<blockquote>\n<p><strong>NARRATOR:</strong> You've voted. The wing accuses <strong>[NAME / NAMES]</strong>.<br />\nThe room's verdict on what that means: <strong>[MURDER / JUSTICE / SYSTEM FAILURE]</strong>.<br />\nHere's what happens next.</p>\n</blockquote>\n<h3>IF THE ROOM ACCUSES <strong>OFFICER RAY</strong> (correct)</h3>\n<p><em>The truth wins. Read this when Ray gets a majority.</em></p>\n<p><strong>Host aside (if players ask why Ray entered the OR personally):</strong> Ray could not ambush Alex elsewhere ,  Sachs on perimeter, cameras still live, security chief alone with a dead VIP is instant guilt. Alex's real arterial case meant Homes might save him if Ray waited. Only the OR converged Ray's prep: tampered vial, blackout, stolen Curie's card, Homes framed, Ray summoned to the code. See <a href=\"00-host-blueprint.md\">00-host-blueprint.md</a> → <em>Why the OR, not elsewhere</em>.</p>\n<p><strong>NARRATOR:</strong></p>\n<blockquote>\n<p>The evidence finally lines up the way the night always demanded.<br />\nPharmacy vault opened on security override. Generator cut from the security office. <strong>Curie's keycard in the OR log</strong> ,  but Curie was in the corridor and Ray's badge never opens that door. A carotid scalpel wound, violent and almost crazed. Logs torn before surgery.<br />\nGenevieve ran from a monster. Her oldest protector learned where she landed, swore revenge on De Worsti, and the man who stood at the head of this investigation was the one who made the cut.</p>\n</blockquote>\n<p><strong>MARZ</strong> (PLAYER or host, steady):</p>\n<blockquote>\n<p>Ray. Hands where I can see them.<br />\nBad drugs. Lights out. You walked into that OR. You set up Homes. You ran this whole room.</p>\n</blockquote>\n<p><strong>CURIE</strong> (optional, charm finally gone):</p>\n<blockquote>\n<p>I wanted him dead. I did not make that cut. You did.</p>\n</blockquote>\n<p><strong>LACEY</strong> (optional, ice cracking):</p>\n<blockquote>\n<p>I wanted distance. Miles. A face he wouldn't recognize. I did not want a throat in the dark.<br />\n(to watch, when they arrive)<br />\nMy name was Genevieve. He hunted me here. Ray was my friend when I still believed friends could keep me safe. Ask Alfie. Ask the intake photos.</p>\n</blockquote>\n<p><strong>PEPPER</strong> (optional, shattered):</p>\n<blockquote>\n<p>You were <em>running</em> the investigation. You were <em>leading</em> us.</p>\n</blockquote>\n<p><strong>HOMES</strong> (optional, hollow victory):</p>\n<blockquote>\n<p>I told you. I told all of you.</p>\n</blockquote>\n<p><strong>NARRATOR: EPILOGUE (GOOD / BITTERSWEET)</strong></p>\n<blockquote>\n<p>The officers split the room fast, practiced, no drama, no raised voices.<br />\nOne name leaves in cuffs before dawn. Officer Ray, still square-shouldered even with steel at his wrists.</p>\n<p>The case does not collapse in court. It hardens.</p>\n<p><strong>Officer Ray</strong> is convicted of first-degree murder, controlled substance facilitation, and abuse of security authority resulting in death. He serves <strong>22 years</strong> at Lesbian City State Correctional Annex, with parole eligibility after 15.</p>\n<p>The judge calls it \"a friend's revenge dressed as emergency medicine.\"</p>\n<p>Five years later, Ray writes letters from prison that Lacey never answers. He still checks storm reports when the wind rises.</p>\n<p>Officer Marz is promoted to Security Chief. She keeps her sidearm clean and her nails immaculate.<br />\nDr. Curie is publicly cleared. The hospital board commends his cooperation. He still flinches when someone praises his hands.<br />\nDr. Homes is publicly cleared as principal killer. The hospital board still removes him from VIP surgery for a year. He returns quieter, less certain, more human.<br />\nLacey Lovely keeps her title through the scandal's first wave, then resigns for a smaller clinic up the coast.<br />\nNurse Pepper transfers out of VIP and into emergency trauma. She stops apologizing for surviving.<br />\nDr. Jetski enters rehab, then returns under supervision. He no longer jokes when someone says \"lights out.\"<br />\nMelody testifies, then vanishes from gossip into witness protection contract work for municipal records.<br />\nCD Vance pleads to accessory cyber-facilitation, serves 18 months, and spends the next decade doing compliant IT audits for public clinics. No shortcuts.<br />\nUvula Sachs disappears before sentencing on separate warrants, then reappears two years later in another port city under another bad nickname, and immediately files a complaint about local timeline documentation standards.<br />\nAlfie De Worsti leaves Lesbian City with a single suitcase and no inheritance worth keeping.</p>\n</blockquote>\n<h3>THE TRUTH</h3>\n<blockquote>\n<p>Long before the operating table, before the storm, before the red emergency lights, there was a locked house and a woman called Genevieve learning how to become smaller than a man's rage.</p>\n<p>De Worsti made debt into religion. He called cruelty discipline. He called possession love. Behind security doors and polished glass, he broke people down to what they could pay, and when money was gone, he took silence, obedience, blood.</p>\n<p>Genevieve ran when she finally could. She paid for a new face with fear and cash and sleepless years. She took a new name, Lacey Lovely, and built an administrative empire out of rules, schedules, and controlled doors. She told herself survival was enough.</p>\n<p>It was not enough for De Worsti.</p>\n<p>He found the thread, clinic photos, reconstruction records, a scar above the left ear, and followed it back to St. Saphicca's. He arrived as a patient and predator, smiling through intake, already planning what he would reclaim.</p>\n<p>Officer Ray watched De Worsti ruin one of the few people he still cared about, took a security post to stay close, and swore revenge. When De Worsti booked real surgery in Lacey's wing, Ray accelerated a plan the room would mistake for medical conspiracy. He did not hunt Alex through corridors. Sachs was on the wing, cameras were still live, and a VIP killed anywhere except the table would have led straight to the badge. Alex came to own Lacey's OR; Ray used that stage.</p>\n<p>Vault access opened the path. Potassium chloride prepared the room. Backup power failed at exactly the right minute. Sedation lagged the witnesses. In darkness, one trained hand drove a scalpel through his throat in a violent, almost crazed stroke ,  not because Ray lacked other chances, but because only the OR gave him a sedated victim, frozen witnesses, blood on the wrong gloves, and a security chief still credible when the code dropped. Then noise, panic, and Dr. Homes framed by timing and terror while Curie became the obvious red herring.</p>\n<p>By sunrise, the script was cracked open. Logs matched toxicology. Access trails matched alibis that were too perfect. Fear matched opportunity. And for once in Lesbian City, the rich did not buy the ending.</p>\n<p>De Worsti died the way he made others live, trapped, cornered, at the mercy of people he thought he owned.<br />\nRay did not walk free into dawn. He walked in chains beside the friend he tried to protect.<br />\nJustice arrived late, soaked through, and incomplete. But it arrived.</p>\n</blockquote>\n<p><em>Proceed to </em><em>POLICE ARRIVAL</em><em>. Watch cuffs Ray on Marz's assembled evidence.</em></p>\n<h3>IF THE ROOM ACCUSES <strong>DR. CURIE AND LACEY LOVELY</strong> (pair, wrong target, Ending C trigger)</h3>\n<p><strong>NARRATOR:</strong></p>\n<blockquote>\n<p>The evidence almost lines up. Sanctuary bond. Surgical skill. <strong>Curie's keycard in the OR log.</strong> A room that wanted a pair.<br />\nBut Curie was in the corridor when the reader fired. And the man who stood beside Officer Ray all evening was steering you toward exactly this mistake.</p>\n</blockquote>\n<p><em>Read </em><em>ENDING C: SYSTEM COLLAPSE</em><em> below instead of a clean arrest.</em></p>\n<h3>IF THE ROOM ACCUSES <strong>DR. CURIE</strong> ALONE (wrong target, red herring wins)</h3>\n<p><strong>NARRATOR:</strong></p>\n<blockquote>\n<p>The room names the surgeon. The blade. The corridor presence. The orphanage photo. <strong>His own keycard in the raw log.</strong><br />\nHalf the room exhales. The charming chief of surgery is in cuffs before the elevator dings.<br />\nCurie never knew his badge left his person that night. Officer Ray stands very still by the glass.</p>\n</blockquote>\n<p><strong>CURIE</strong> (optional, to Ray, quiet):</p>\n<blockquote>\n<p>You know I didn't make that cut.</p>\n</blockquote>\n<p><strong>RAY</strong> (optional, controlled):</p>\n<blockquote>\n<p>Curie. That's enough for now. You're done.</p>\n</blockquote>\n<p><em>Proceed to </em><em>POLICE ARRIVAL</em><em>. Watch arrests Curie in the chaos. Ray watches from the wing as the wrong person is led out.</em></p>\n<h3>IF THE ROOM ACCUSES <strong>LACEY LOVELY</strong> ALONE (partial / wrong)</h3>\n<p><strong>NARRATOR:</strong></p>\n<blockquote>\n<p>The room turns on the director. Blackout logs. Vault tier. Crisis lock. A woman who rebuilt her face to escape a dead man's shadow.<br />\nBut the wound was made in darkness with night vision gear from security stock. And the man who guided the investigation never stopped guiding it.</p>\n</blockquote>\n<p><strong>LACEY</strong> (optional):</p>\n<blockquote>\n<p>I ran. I changed my life. I did not make that cut.</p>\n</blockquote>\n<p><strong>RAY</strong> (optional, warm, lethal):</p>\n<blockquote>\n<p>Director Lovely had motive. She had access. She did not have my badge in that OR.</p>\n</blockquote>\n<p><em>Host choice: Lacey arrested while Ray remains \"security chief\" until watch reviews keycard data in Ep 4 coda.</em></p>\n<h3>IF THE ROOM ACCUSES <strong>DR. HOMES</strong> (wrong target)</h3>\n<p><strong>NARRATOR:</strong></p>\n<blockquote>\n<p>Blade contact. Bloody gloves. Panic in the red light. The room does what frightened rooms do: it chooses the man already standing in the spotlight.<br />\nDr. Homes becomes LC-4471 in the players' eyes. The real killer breathes and still runs the board.</p>\n</blockquote>\n<p><strong>HOMES</strong> (PLAYER, if present):</p>\n<blockquote>\n<p>This is wrong. You are making this wrong.</p>\n</blockquote>\n<p><strong>RAY</strong> (optional, gentle, devastating):</p>\n<blockquote>\n<p>I wish I could tell you otherwise. The wound could match his training, or any man with a scalpel and enough hatred.</p>\n</blockquote>\n<p><strong>PEPPER</strong> (optional, torn):</p>\n<blockquote>\n<p>I don't… I don't think he did it.</p>\n</blockquote>\n<p><em>Proceed to </em><em>POLICE ARRIVAL</em><em>. Watch arrests Homes in the chaos. Ray watches from the recovery wing as the wrong man is led out.</em></p>\n<h3>IF THE ROOM ACCUSES <strong>UVULA SACHS</strong> (wrong target)</h3>\n<p><strong>NARRATOR:</strong></p>\n<blockquote>\n<p>Street muscle. Wire cutters. Elevator threats. An enforcer without a ledger since De Worsti went broke.<br />\nThe room wants a villain who looks like violence. Sachs does not disappoint, and she has notes on your investigative process.</p>\n</blockquote>\n<p><strong>SACHS</strong> (optional, German accent):</p>\n<blockquote>\n<p>I did not make that cut. I post where I'm told. If I ran operations like this murder investigation, I would be dead. Which, yes, ironic.</p>\n</blockquote>\n<p><strong>RAY</strong> (optional):</p>\n<blockquote>\n<p>Sachs is a predator. Not tonight's surgeon in the dark.</p>\n</blockquote>\n<p><em>Watch arrests Sachs. Alfie and Vance may exhale too soon. Ray remains free.</em></p>\n<h3>IF THE ROOM ACCUSES <strong>ALFIE AUSTIN</strong> (wrong target)</h3>\n<p><strong>NARRATOR:</strong></p>\n<blockquote>\n<p>The brother. The knife in the loading bay. Insurance fantasies and family rot.<br />\nThe room chooses the man who came to hate De Worsti out loud. He did not come to finish him in the OR.</p>\n</blockquote>\n<p><strong>ALFIE</strong> (optional, breaking):</p>\n<blockquote>\n<p>I didn't… I wasn't in there… Genevieve just wanted to run…</p>\n</blockquote>\n<p><em>Watch arrests Alfie. Lacey's face may flicker. Ray stays anchor.</em></p>\n<h3>IF THE ROOM ACCUSES <strong>OFFICER RAY + LACEY LOVELY</strong> (pair, correct if room believes she knew)</h3>\n<p><em>Use the </em><em>OFFICER RAY</em><em> correct branch above, with Lacey optionally named as accessory after conviction if evidence supports complicity. If room cannot prove she knew, Ray alone is sufficient for truth.</em></p>\n<h3>IF THE ROOM ACCUSES <strong>ANYONE ELSE</strong> (Pepper, Melody, Vance, Jetski) OR <strong>SPLIT VOTE</strong></h3>\n<p><strong>NARRATOR:</strong></p>\n<blockquote>\n<p>No consensus. Too many stories. Too little time. Sirens closer.<br />\nThe wing fractures: some players cling to last minute theories, others to grudges, others to whoever spoke most confidently.<br />\nOfficer Ray still has a folder. The city still has a flood. The truth still has a name. The room simply failed to agree on it.</p>\n</blockquote>\n<p><em>Host: pick the closest wrong arrest (usually Homes) if watch must take someone, or run </em><em>ENDING C</em><em> if the table devolved.</em></p>\n<h2>ENDING C: SYSTEM COLLAPSE</h2>\n<p><em>Use when </em><em>Curie + Lacey</em><em> are wrongly accused, evidence was ignored, or the group never united on Ray.</em></p>\n<p><strong>NARRATOR:</strong></p>\n<blockquote>\n<p>A shout from corridor three. Server room. Sparks through the door glass.<br />\nThe failover stack was already wounded. Now it detonates under panic, sabotage, or sheer bad luck.<br />\nSmoke rolls into the VIP wing. Sprinklers fail. The backup grid screams.</p>\n</blockquote>\n<p><strong>VANCE</strong> (optional, screaming):</p>\n<blockquote>\n<p>The logs! The raw logs are still in the...</p>\n</blockquote>\n<p><em>Host sound effect or blackout. When lights return:</em></p>\n<p><strong>NARRATOR:</strong></p>\n<blockquote>\n<p>CD Vance does not get up. Dr. Homes does not get up.<br />\nThe evidence burns with them. Timestamps. Overrides. Half the night's truth.</p>\n</blockquote>\n<p><strong>RAY</strong> (optional, raw):</p>\n<blockquote>\n<p>Move. Everyone move. That's municipal watch on the lobby channel. Now.</p>\n</blockquote>\n<p><em>Watch arrives into catastrophe. Ray slips through recovery chaos. Investigation fragments. Truth may die in the rubble.</em></p>\n<h2>MORAL VERDICT CODA (layer after accusation branch)</h2>\n<p><em>Read one coda after the accusation outcome. This is what the room says the killing </em><em>meant</em><em>, not who did it.</em></p>\n<h3>MURDER (criminal act; maximum punishment)</h3>\n<p><strong>NARRATOR:</strong></p>\n<blockquote>\n<p>Your verdict: <strong>murder</strong>. No poetry. No storm justice.<br />\nDe Worsti was a monster. He was also a man with a throat cut in an operating theater.<br />\nWhoever you named, the city will treat this as felony homicide. The abuse does not erase the blade.</p>\n</blockquote>\n<p><em>Ray tells arriving watch the room voted for prosecution, not cover up.</em></p>\n<h3>JUSTICE (justified execution; sympathy)</h3>\n<p><strong>NARRATOR:</strong></p>\n<blockquote>\n<p>Your verdict: <strong>justice</strong>. Not legal. Moral.<br />\nA woman hunted across clinics and ledgers. A friend who stayed close and would not fail her twice. A victim who burned families and called it business.<br />\nThe room says the law would call it murder. The room would call it survival.</p>\n</blockquote>\n<p><em>Marz may soften her statement to watch: Genevieve's history enters the record. Arrests still happen if Ray was named correctly.</em></p>\n<h3>SYSTEM FAILURE (burn logs; expose the hospital)</h3>\n<p><strong>NARRATOR:</strong></p>\n<blockquote>\n<p>Your verdict: <strong>system failure</strong>.<br />\nSt. Saphicca's sold VIP wings to predators. Directors with new faces. Contractors who scrub logs. Security chiefs with debts.<br />\nThe room wants the institution exposed, not just the hands that held the scalpel.<br />\nWhatever happens to the suspects, the scandal outlives the storm.</p>\n</blockquote>\n<p><em>If Vance lives, raw mainframe data goes to press or watch. Lacey's admin tier becomes public crisis.</em></p>\n<h2>POLICE ARRIVAL (all endings, read after accusation + moral coda)</h2>\n<p><strong>NARRATOR:</strong></p>\n<blockquote>\n<p>The wind dropped like a held breath.<br />\nFirst the generators steadied. Then, distant, then close, sirens.<br />\nMunicipal Watch. Real patrol. Flood lights through the glass. Boots in the lobby. Radios that weren't hospital channels.</p>\n</blockquote>\n<p><strong>MARZ</strong> (exhausted, to the room):</p>\n<blockquote>\n<p>That's them. Finally.<br />\nWhatever you picked in this room, names, proof, who did what. It's theirs now.</p>\n</blockquote>\n<p><em>Apply arrest outcome from accusation branch. Marz hands LC-4471 to municipal sergeant if Ray is cuffed; otherwise Ray hands off:</em></p>\n<blockquote>\n<p><strong>RAY:</strong> Case number's LC-4471. Was my problem until about a minute ago.</p>\n</blockquote>\n<h2>FACILITATOR TRUTH REVEAL (optional, after play)</h2>\n<p><em>If the room got it wrong, read the actual sequence once watch has taken the scene:</em></p>\n<p><strong>NARRATOR:</strong></p>\n<blockquote>\n<p>Here is what the night really was.<br />\nLacey saw Sachs on the perimeter and other warnings that De Worsti had found her hospital. Ray learned De Worsti booked <strong>real</strong> arterial surgery here, a power play on her turf, and accelerated a plan he had been building since he realized how trapped she still was.<br />\nOfficer Ray tampered the vial. Dr. Jetski delivered it unknowingly. Ray triggered the blackout from security. Ray entered the OR, made the cut, framed Homes. Curie looked guilty and did not kill.<br />\nDe Worsti needed the operation. He bet Genevieve would not fight back. Homes and Curie refused his theater.<br />\nDe Worsti hunted Genevieve. Genevieve became Lacey Lovely. Ray was her friend and protector. Alfie knew the abuse. Melody knew the face. Sachs hunted the money. Pepper loved him without knowing who he was.<br />\nJetski said it in the gathering lounge, before any of you split up: the killer was in the room. You voted anyway.</p>\n</blockquote>\n<h3>Facilitator closing monologue (all endings)</h3>\n<blockquote>\n<p>The auxiliary power clicked off at St. Saphicca's. The main grid hummed back. Heart monitors resumed their steady beeping. Municipal Watch took the bodies and the statements into the rain. And every layer of the system continued… exactly as it had before.</p>\n</blockquote>", "06-act2-crime-scene": "<h1>Act 2, Crime Scene Handoff (Live Play Opener)</h1>\n<p><strong>When:</strong> After <strong>10-the gathering.md</strong> (cast already briefed, Homes named primary suspect)<br />\n<strong>Runtime:</strong> 30 to 45 minutes live interaction<br />\n<strong>Location:</strong> OR + adjacent VIP corridor (your play space)<br />\n<strong>Goal:</strong> Physical evidence search; wing split; first clue cards distributed</p>\n<h2>NARRATOR SETUP (read aloud)</h2>\n<blockquote>\n<p>The gathering is over. The charge is on the table: <strong>Dr. Homes, primary suspect.</strong><br />\nRay and Marz split the wing. OR sealed but searchable under their eyes, corridors assigned, no one walks alone.<br />\nThe storm hasn't stopped. The police haven't come. The room has work to do.</p>\n</blockquote>\n<p><em>Players move to play space. OR still in red backup wash. Blood still drying.</em></p>\n<h2>SCENE 2, OR FORENSICS (scripted entrance)</h2>\n<p><em>Ray, Marz, and Curie lead the group, or an assigned search party, back toward the theater. </em><em>HOMES</em><em> may be held at the lounge or brought to point without touching evidence.</em></p>\n<p><strong>RAY</strong> tapes the threshold. Has already bagged the scalpel.</p>\n<blockquote>\n<p><strong>RAY:</strong> Nobody touches the body. You look. You write it down. You tell me anything that says Homes didn't do it.</p>\n</blockquote>\n<p><strong>CURIE</strong> scans the floor, the trash, the ceiling mounts, too thorough for a liaison.</p>\n<blockquote>\n<p><strong>CURIE:</strong> Start with what the lights didn't erase. Blood doesn't lie about order. Chemistry doesn't lie about timing.</p>\n</blockquote>\n<p><em>Curie is helpful, witty, warm, the room likes him and will chase him. </em><em>Homes</em><em> is the only one visibly irritated. </em><em>Pepper</em><em> may </em><em>ahem</em><em> if Ray and Curie crowd the same clue. Ray steers every helpful path that isn't Curie's keycard or his own lack of OR access.</em></p>\n<h2>DUE DILIGENCE, MUNDANE SECURITY BEATS</h2>\n<p><em>Host: run these as short interactions players can overhear or participate in. Establishes realism.</em></p>\n<h3>1. Perimeter seal</h3>\n<p>Ray tapes off corridor junction. Melody (if at desk down the hall) calls: <em>\"Is the wing closed? I have a donor call on hold.\"</em></p>\n<p>Ray, without looking up: <em>\"Wing's closed. Donor can wait.\"</em></p>\n<h3>2. Chain of custody</h3>\n<p>Ray bags the scalpel <strong>without</strong> letting Homes touch it again.</p>\n<blockquote>\n<p><strong>RAY:</strong> (to room) Full names. Where you stood when the red lights came on. Pepper, write the times. I write the names.</p>\n</blockquote>\n<h3>3. Radio, no patrol (storm)</h3>\n<p>Ray keys his radio:</p>\n<blockquote>\n<p><strong>RAY:</strong> Guard shack, status on LC-4471.</p>\n</blockquote>\n<p><em>Static. Distorted reply:</em></p>\n<blockquote>\n<p><strong>RADIO:</strong> Barricade still holding at lower causeway… watch says… shelter in place… no ETA…</p>\n</blockquote>\n<p>Ray clicks off, jaw tight.</p>\n<blockquote>\n<p><strong>RAY:</strong> (to room) That's the city. We're the scene until they're not.</p>\n</blockquote>\n<h3>4. CCTV request (dead end)</h3>\n<p>Ray calls Vance on intercom:</p>\n<blockquote>\n<p><strong>RAY:</strong> Vance. IT. Pre op to failover, <em>now</em>.</p>\n</blockquote>\n<p><em>CD Vance</em> (breathless):</p>\n<blockquote>\n<p><strong>VANCE:</strong> VIP corridor three and OR internal are… there's gaps. Like something scrubbed the loop. Storm didn't do that. I'm pulling what I can.</p>\n<p><strong>RAY:</strong> Gaps don't happen by weather. Note it.</p>\n</blockquote>\n<p><em>Plants hacking/CCTV red herring without naming a killer.</em></p>\n<h3>5. Victim property</h3>\n<p>Ray gestures to De Worsti's folded clothes in the anteroom.</p>\n<blockquote>\n<p><strong>RAY:</strong> Personal effects stay with watch until next of kin protocol. Search is limited to outer garments. Hospital counsel is already screaming.</p>\n</blockquote>\n<p><em>This is when players may discover </em><em>E1-C P.I. dossier</em><em> in coat jacket.</em></p>\n<h3>6. Jetski hold</h3>\n<p>Ray to Jetski (gurney or sitting against wall):</p>\n<blockquote>\n<p><strong>RAY:</strong> You're not arrested. You're also not leaving. Clinical witness. Pepper monitors. You say one word about dosing without me in the room, I'll put you in municipal cuffs anyway.</p>\n</blockquote>\n<p>Jetski nods, pale.</p>\n<h2>CURIE'S INVESTIGATION POSTURE (obvious red herring)</h2>\n<p>Curie doesn't pace. He <em>orients</em>, checks ceiling mounts, sight lines, scrub sink.</p>\n<blockquote>\n<p><strong>CURIE:</strong> (quiet, to Ray) That wound won't read as panic. It's violent, almost crazed. But it's a scalpel. Who else in this building had attending privileges tonight?</p>\n<p><strong>RAY:</strong> Everyone with a grudge and a badge. Starting with him.</p>\n</blockquote>\n<p><em>Gestures at Homes.</em></p>\n<blockquote>\n<p><strong>CURIE:</strong> Then we don't start with feeling. We start with floor patterns and who had vault access.</p>\n</blockquote>\n<p><em>Curie is helpful, and the room will mistake his motive for guilt.</em></p>\n<p><strong>Optional Curie line</strong> (if players rush Sachs):</p>\n<blockquote>\n<p><strong>CURIE:</strong> Street enforcers make noise. This room was silent. Don't waste your first hour on the loudest suspect.</p>\n</blockquote>\n<h2>LIVE INVESTIGATION, PLAYER INTERACTIONS</h2>\n<p><em>Distribute physical clue props when players perform these actions.</em></p>\n<table>\n<thead>\n<tr>\n<th>Player action</th>\n<th>Host response</th>\n<th>Evidence</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td>Examine OR floor near table</td>\n<td>Two distinct blood behaviors visible</td>\n<td><strong>E1-A Blood pattern</strong></td>\n</tr>\n<tr>\n<td>Search anesthesia trash</td>\n<td>Empty vial, compromised seal</td>\n<td><strong>E1-B IV vial</strong></td>\n</tr>\n<tr>\n<td>Search De Worsti's coat (with Ray present)</td>\n<td>Dossier on ex wife reconstruction</td>\n<td><strong>E1-C P.I. file</strong></td>\n</tr>\n<tr>\n<td>Interview Melody at desk</td>\n<td>\"I called the code.\" Saw <strong>Homes</strong> in hall earlier, alibi or misdirect</td>\n<td>Testimony only</td>\n</tr>\n<tr>\n<td>Ask about power failure</td>\n<td>Vance stammers; override \"from admin tier\", vague until Ep 2</td>\n<td>Foreshadow</td>\n</tr>\n<tr>\n<td>Accuse Homes immediately</td>\n<td>Ray: <em>\"Maybe. Show me proof that isn't standing still.\"</em></td>\n<td>No arrest yet</td>\n</tr>\n<tr>\n<td>Demand to search Admin office / Lacey's background</td>\n<td>Ray proceeds; <strong>Curie</strong> adds <em>\"unlikely primary actor, still a lead\"</em>; <strong>Lacey</strong> may invoke Administrative Override once</td>\n<td>Lacey ability foreshadow</td>\n</tr>\n</tbody>\n</table>\n<h3>Pepper's logbook gate</h3>\n<p>Pepper will not open VIP logbook until players trade something scandalous or answer her direct clinical questions. This slows runaway accusations.</p>\n<h3>Homes' subpoena tokens</h3>\n<p>Homes may burn tokens here to force truthful answers, high drama if aimed at Pepper or Jetski.</p>\n<h2>TRANSITION TO EPISODE 2</h2>\n<p>When blood pattern + vial + at least two testimonies are logged (or 30+ minutes elapsed):</p>\n<p><strong>RAY</strong> (closing the scene):</p>\n<blockquote>\n<p>OR's closed. De Worsti goes to the morgue. Everyone's statements are on paper.<br />\nCops aren't here. I am. We get the vault records, who flipped the power, and whatever Vance swears he can't find, before those sirens show up.</p>\n</blockquote>\n<p><strong>CURIE</strong> (to players):</p>\n<blockquote>\n<p>Ten of you were inside when the lights died. One of you is lying well.<br />\nOfficer Ray and I are taking statements in the recovery lounge.<br />\nDon't mistake cooperation for innocence.</p>\n</blockquote>\n<p><em>Narrator:</em></p>\n<blockquote>\n<p>The storm kept hitting the glass. Municipal channels stayed empty. Somewhere two floors up, an administrative terminal held the ghost of a manual override. And somewhere in this wing, someone at the table already knew the wound looked too violent and crazed for a man still holding the blade when the red lights returned.</p>\n</blockquote>\n<p><em>Cut to Episode 2 cutscene, </em><em>05-episode scripts.md</em><em> → \"The Logic of the Needle\"</em></p>\n<h2>HOST NOTES</h2>\n<ul>\n<li><strong>No municipal patrol until Ep 4 coda</strong>, see 09-storm containment logic.md.  </li>\n<li><strong>Ray = killer + compromised authority:</strong> procedural, credible, openly admits debt/motive, runs the board.</li>\n<li><strong>Curie steers participation</strong> as red herring; room chases the charming surgeon.</li>\n<li>Drop storm beats between acts: radio static, flood alerts, flickering generators.  </li>\n<li>Do <strong>not</strong> reveal Lacey/Genevieve until Ep 2 to 4 evidence chain.</li>\n</ul>", "10-the-gathering": "<h1>The Gathering, All Persons of Interest</h1>\n<p><strong>When:</strong> Immediately after Episode 1 OR cutscene (~15 minutes scripted + live questioning)<br />\n<strong>Location:</strong> VIP Recovery Lounge, glass on three sides, storm hammering the city, red backup wash bleeding through the blinds<br />\n<strong>Present:</strong> All eleven players. De Worsti is absent, body in OR, morgue pending.<br />\n<strong>Leads:</strong> Officer Ray, Officer Marlowe \"Marz\" + Dr. Curie<br />\n<strong>Room temperature:</strong> <strong>Dr. Homes is the primary suspect.</strong></p>\n<h2>HOST SETUP</h2>\n<ul>\n<li>Arrange all eleven players in a circle or long table, no one standing apart.  </li>\n<li><strong>Homes</strong> sits or stands under the brightest light if possible.  </li>\n<li><strong>Jetski</strong> may be in a wheelchair or slumped chair, still medicated, hands unsteady.  </li>\n<li><strong>Pepper</strong> should still carry OR terror, bloodless knuckles, voice not fully steady; sage returns slowly.  </li>\n<li><strong>Ray</strong> at the head. <strong>Marz</strong> beside him (junior, notebook, nail polish). <strong>Curie</strong> beside Ray, not across, unified front.  </li>\n<li>Read <strong>NARRATOR</strong> blocks yourself; players deliver their own lines where marked <strong>(PLAYER)</strong>.  </li>\n<li><strong>Persona guide:</strong> <a href=\"14-actor-personas.md\">14-actor-personas.md</a>, encourage big, fun choices; plot beats stay the same.</li>\n<li><strong>Optional Diamond:</strong> If using the twelfth player, <strong>Officer Diamond</strong> arrives at the lounge door after Ray's briefing (see <a href=\"17-officer-diamond.md\">17-officer-diamond.md</a>, dossier <a href=\"player-dossiers/11-officer-diamond.md\">player-dossiers/11-officer-diamond.md</a>).</li>\n</ul>\n<h2>NARRATOR, OPEN</h2>\n<blockquote>\n<p>The VIP Recovery Lounge was built for donors and executives, soft light, skyline views, the illusion that nothing here could go wrong.<br />\nTonight the generators stutter. Rain lashes the glass. Somewhere below, a municipal radio repeats the same sentence: <em>hold position, no ETA.</em><br />\nOfficer Ray has pulled everyone with access to this wing into one room. Officer Marz is with him. Not a request. The wing is locked down.<br />\nThe body of De Worsti is still in the operating theater. The blood on Dr. Homes's gloves has not fully dried.<br />\nAnd eleven people who hated the dead man, or loved him, or owed him, are about to learn they cannot leave until someone answers for what happened in the dark.</p>\n</blockquote>\n<p><em>Door locks. Distant thunder.</em></p>\n<h2>SCENE, THE BRIEFING</h2>\n<p><em>Ray enters last. Curie already inside, arms loose, watching faces. Nobody speaks until Ray closes the door.</em></p>\n<p><strong>RAY</strong> sets his notebook on the table. Looks at each person in turn. When he reaches <strong>Homes</strong>, he doesn't look away.</p>\n<blockquote>\n<p><strong>RAY:</strong> I'm Officer Ray. I run security here. Used to work for the city cops. Right now I'm the senior guard in this building. Officer Marz's with me.</p>\n</blockquote>\n<p><strong>MARZ</strong> (PLAYER: southern belle, pleasant, already painting a nail):</p>\n<blockquote>\n<p>And I'm Officer Marlowe. Marz. Junior guard. I work with Ray, not around him. Y'all can tell us the truth, or you can tell us something so dumb we'll know you're lying. Either way's fine with me.</p>\n<p><strong>RAY:</strong> (beat)<br />\nAt eleven forty-two, De Worsti died in VIP OR Two. Throat opened with a scalpel. Violent. Almost crazed.<br />\nLights were out about a minute. When they came back, Dr. Homes was standing over him with a scalpel in his hand.</p>\n</blockquote>\n<p><strong>HOMES</strong> (PLAYER: defensive, immediate):</p>\n<blockquote>\n<p>That is not... I did not kill him. I lost the blade when the grid dropped. Someone was in that room.</p>\n</blockquote>\n<p><strong>CURIE</strong> (PLAYER: warm, unruffled, room immediately calmer):</p>\n<blockquote>\n<p>Doctor, you'll get your turn. All of you will.</p>\n</blockquote>\n<p><em>He shifts, half a step closer to </em><em>Ray</em><em> than strictly necessary. The room notices.</em></p>\n<blockquote>\n<p><strong>CURIE:</strong> I'm Dr. Curie, Chief of Surgery. Until Municipal Watch gets through the flood, and they are not here yet, I am medical liaison on this death.<br />\nThat means cause, mechanism, and whether anyone in this room had the skill and the access to do what was done.</p>\n</blockquote>\n<p><strong>RAY</strong> (PLAYER: gruff, almost softening):</p>\n<blockquote>\n<p>And I'm the security here. We figure this out together, or we stumble around in the dark.</p>\n</blockquote>\n<p><strong>CURIE</strong> (PLAYER: smile, serious shutdown):</p>\n<blockquote>\n<p>Officer, I'd flirt back, but we have a corpse and a flood. Another time.</p>\n</blockquote>\n<p><em>Light laugh from </em><em>Melody</em><em> or </em><em>Jetski</em><em>. </em><em>RAY</em><em> exhales like he's been disarmed.</em></p>\n<p><strong>PEPPER</strong> (PLAYER: <strong>sharp ahem</strong>; comedic beat):</p>\n<blockquote>\n<p><em>(clears throat)</em><br />\n…Can we stay on the dead man?</p>\n</blockquote>\n<p><strong>HOMES</strong> (PLAYER: bristling):</p>\n<blockquote>\n<p>Christ. Could we investigate the murder instead of...</p>\n</blockquote>\n<p><strong>CURIE</strong> (pleasant, devastating):</p>\n<blockquote>\n<p>Doctor, when you have an alibi, I'll schedule around your preferences.</p>\n</blockquote>\n<p><strong>RAY</strong> (almost amused, to Homes):</p>\n<blockquote>\n<p>Keep talking, Homes.</p>\n</blockquote>\n<p><strong>LACEY</strong> (PLAYER: ice, administrative):</p>\n<blockquote>\n<p>Officer. I have counsel on standby. This hospital will cooperate within regulatory...</p>\n<p><strong>RAY:</strong> (flat) Director Lovely. You locked this wing down twenty minutes ago. That was your call, not mine. Your lawyer can wait until I say otherwise.</p>\n</blockquote>\n<p><em>Lacey holds his gaze. Sits. Says nothing.</em></p>\n<blockquote>\n<p><strong>RAY:</strong> I called the real cops. They logged it. Answer back was wait, roads are flooded. No patrol car. No detective. Nobody's coming up those elevators for hours.<br />\n(beat, harder)<br />\nI know how this looks. De Worsti had dirt on half this city. He had dirt on me too. I'm a suspect same as you. I'm also running this wing until those sirens show up.<br />\nNobody leaves. Nobody. You talk in this room, or I stick you in separate rooms and let the real cops sort it in the morning.</p>\n</blockquote>\n<p><em>Silence. Storm on the glass.</em></p>\n<blockquote>\n<p><strong>CURIE:</strong> (to the room) The officer's right. If we don't build the case tonight, the case will be built for us, by people who weren't in the building when the lights died.</p>\n</blockquote>\n<h2>ROUND ONE, WHO WAS WHERE</h2>\n<p><strong>RAY</strong> opens the notebook.</p>\n<blockquote>\n<p><strong>RAY:</strong> Names. Jobs. Where you were when the red lights came on. One at a time. Jetski, you're first. You're half why this room was knocked out.</p>\n</blockquote>\n<p><strong>JETSKI</strong> (PLAYER, shaking, furious at the framing; occasional surfer slip):</p>\n<blockquote>\n<p>Dr. Jetski. Anesthesiology. Dude, I was at the south wall monitoring IV delivery and I went down before the lights even cut, lag, paralysis, I couldn't move, I couldn't see straight. Ask Pepper. I was on the floor when it happened.</p>\n</blockquote>\n<p><strong>PEPPER</strong> (PLAYER, clinical mask over horror):</p>\n<blockquote>\n<p>He's not lying about the timing. I felt it too, cognitive lag, motor drop. We were incapacitated before the incision.<br />\n(beat, unwilling)<br />\nI was assisting Dr. Homes. De Worsti was on the table when the lights died. When the red lights came back he was on the floor… Homes had the scalpel. De Worsti was gone.</p>\n</blockquote>\n<p><em>Eyes turn to </em><em>Homes</em><em>. The room does the math without help.</em></p>\n<p><strong>HOMES</strong> (PLAYER):</p>\n<blockquote>\n<p>I was primary surgeon. The arterial wall was compromised, we were stabilizing. Jetski reported drift. Then black. I felt the blade pulled from my grip. I shouted for backup power. When the lights returned I was still holding\n(voice cracking)<br />\nI didn't make that cut. I couldn't see. Someone was in there with us.</p>\n</blockquote>\n<p><strong>CURIE</strong> (quiet, surgical):</p>\n<blockquote>\n<p>The wound was not panic. It was passionate, almost crazed. But a scalpel did it, and that could be a surgeon's hand or a man's rage.</p>\n</blockquote>\n<p><em>Not accusation. Worse, assessment. The room hears it as verdict.</em></p>\n<p><strong>RAY</strong> (to Homes):</p>\n<blockquote>\n<p>You're my main guy until I hear better. Sit down.</p>\n</blockquote>\n<p><em>Homes sits. The light doesn't move.</em></p>\n<h2>ROUND TWO, EVERYONE ELSE IN THE WING</h2>\n<p><strong>RAY:</strong></p>\n<blockquote>\n<p>The rest of you. What were you doing in my wing tonight?</p>\n</blockquote>\n<p><strong>MELODY</strong> (PLAYER, valley gossip, ditzy top layer):</p>\n<blockquote>\n<p>Melody! Night reception? Like, I was at the desk, I called the code when the monitor flatlined, oh my god, and I saw <em>everyone</em> coming and going all night. Including</p>\n</blockquote>\n<p><em>Glances at </em><em>Alfie</em><em>. Blinks innocent. Glances at </em><em>Marz</em><em>'s nails.</em></p>\n<blockquote>\n<p><strong>MELODY:</strong> Officer Marz? Where is that blouse from? It is, like, literally gorgeous on you.</p>\n</blockquote>\n<p><strong>MARZ</strong> (PLAYER, kind, without flirting back hard):</p>\n<blockquote>\n<p>Oh, bless you, honey. Thrift store in the Quarter, then I fixed the cuffs myself. You have good eyes.</p>\n<p><strong>MELODY:</strong> Including things that don't match the visitor log. But that's like, a whole thing.</p>\n<p><strong>RAY:</strong> Including what?</p>\n</blockquote>\n<p><strong>MELODY:</strong></p>\n<blockquote>\n<p>Including things that don't match the visitor log. Ask your IT guy about the cameras. Ask about the page missing from the keycard book.</p>\n</blockquote>\n<p><strong>VANCE</strong> (PLAYER, genki speed, then wilt):</p>\n<blockquote>\n<p>Hi! Hi. CD Vance. IT contractor? Server room! Storm failover, corridor three offline, Director Lovely's audit, and also, um. Other requests. I don't do violence, I do logs, I do Python, I do panic</p>\n</blockquote>\n<p><em>Glances at </em><em>Sachs</em><em>. Goes very small.</em></p>\n<blockquote>\n<p><strong>VANCE:</strong> <em>(quieter)</em> …eep.</p>\n<p><strong>RAY:</strong> (flat) Other requests. We'll come back to logs. And to you.</p>\n</blockquote>\n<p><strong>SACHS</strong> (PLAYER, efficiency rage bleeding into menace, German accent; lines as written):</p>\n<blockquote>\n<p>He does what keeps his pones in one piece. Like any contractor who does not want the project cancelled.</p>\n</blockquote>\n<p><strong>ALFIE</strong> (PLAYER, smug, too casual):</p>\n<blockquote>\n<p>Alfie De Worsti. De Worsti's brother. I was a delivery. Medical supplies. That's on the manifest.</p>\n</blockquote>\n<p><strong>SACHS</strong> (PLAYER, hyper-critical chaos gremlin, German accent):</p>\n<blockquote>\n<p>Uvula Sachs. You want the name on my pirth certificate or the one your mother kave you?</p>\n<p><em>(to room, suddenly)</em> Wait. Stop. Who is running this introduction? No one? Ah. That explains the vibe in this room immediately.</p>\n<p><strong>RAY:</strong> (immediate) Where were you at eleven forty-two?</p>\n</blockquote>\n<p><strong>SACHS:</strong></p>\n<blockquote>\n<p>Perimeter. VIP access corridor. Eleven forty-two, <strong>not</strong> \"around\" eleven forty-two. I post where I'm told. De Worsti owed money. I owed answers. I did not owe him a throat cut in the dark.</p>\n</blockquote>\n<p><em>She looks at </em><em>Homes</em><em>.</em></p>\n<blockquote>\n<p>And if you're asking who in this room looks like they just left an OR? You are staring at him, Officer. Motive, opportunity, blood on his hands. Why are we still using vibes?</p>\n</blockquote>\n<p><strong>LACEY</strong> (PLAYER, controlled):</p>\n<blockquote>\n<p>Lacey Lovely. Hospital Director. I was in administration, two floors up, managing grid instability and crisis protocol when the wing failed over. I did not enter the operating theater.</p>\n</blockquote>\n<p><strong>RAY</strong> (if Lacey named or vault raised):</p>\n<blockquote>\n<p>Director Lovely, you're on my list. I want to know everything about you.</p>\n</blockquote>\n<p><strong>CURIE</strong> (PLAYER, does not block):</p>\n<blockquote>\n<p>Good. Pull it. Executive tier on a night like this is a lead.<br />\n(to Ray, professional)<br />\nSurgical read? A director facilitates, she doesn't usually make the incision herself. Unlikely primary cutter. Still a lead. Run it.</p>\n</blockquote>\n<p><em>Lacey doesn't blink. Curie sounds helpful because he is, on the record.</em></p>\n<h2>THE ACCUSATION, HOMES CENTERED</h2>\n<p><strong>RAY</strong> stands. Circles the table. Stops behind Homes' chair.</p>\n<blockquote>\n<p><strong>RAY:</strong> Let's be plain. Everyone hated De Worsti. Loan shark in a hospital gown. Half of you wanted him dead.<br />\nBut only one guy was standing over the body, blood on his hands, scalpel in his grip when the lights came back.<br />\nDr. Homes, you're my main suspect tonight.</p>\n</blockquote>\n<p><strong>HOMES</strong> (PLAYER, standing, rage):</p>\n<blockquote>\n<p>This is insane. Curie, you're Chief of Surgery, you know that cut was</p>\n</blockquote>\n<p><strong>CURIE</strong> (PLAYER, gentle, devastating):</p>\n<blockquote>\n<p>I know what I know. And right now I know you were holding the instrument.</p>\n</blockquote>\n<p><em>Beat. Curie is the red herring the room will chase. Ray is the killer steering the investigation. This line should land.</em></p>\n<p><strong>PEPPER</strong> (PLAYER, torn, quiet):</p>\n<blockquote>\n<p>…I don't think you did it.</p>\n</blockquote>\n<p><em>The room stirs. First crack in the consensus.</em></p>\n<blockquote>\n<p><strong>PEPPER:</strong> I don't know what I think. I was on the floor. I saw you standing there. I saw</p>\n</blockquote>\n<p><em>She can't finish. Grief and guilt.</em></p>\n<p><strong>JETSKI</strong> (PLAYER, small):</p>\n<blockquote>\n<p>Bro, I was paralyzed. He wasn't the only surgeon in this building.</p>\n</blockquote>\n<p><strong>RAY</strong> (to the room):</p>\n<blockquote>\n<p>Then help me prove it. Starting now.</p>\n</blockquote>\n<h2>CURIE, THE ASK (why they investigate)</h2>\n<p><strong>CURIE</strong> steps forward. Addresses everyone, not just Homes.</p>\n<blockquote>\n<p><strong>CURIE:</strong> Officer Ray cannot process a coordinated murder alone. I cannot autopsy a conspiracy from a cot.<br />\nEvery person in this lounge was inside the VIP wing when De Worsti died. That makes you witnesses, suspects, or both.<br />\nThe municipal watch is not walking through that flood tonight. The killer may still be in this wing, I don't say that to panic you. I say it because it's true.<br />\nSo here's what happens next. We split the wing. We log evidence. We cross check access, pharmacy, power, keycards, and testimony. You don't get to go home and invent an alibi in the rain.</p>\n</blockquote>\n<p><strong>RAY:</strong></p>\n<blockquote>\n<p>Find me something that proves Homes didn't do it. Blood on the floor. Pills. Log books. Camera times. Something.<br />\nOr Homes sits alone and I talk to the rest of you one by one in rooms with no windows.</p>\n</blockquote>\n<p><em>He looks at </em><em>Sachs</em><em>. </em><em>Alfie</em><em>. </em><em>Vance</em><em>. </em><em>Melody</em><em>. </em><em>Lacey</em><em>. No one exempt.</em></p>\n<blockquote>\n<p><strong>RAY:</strong> You don't have to like me. You do have to stay.</p>\n</blockquote>\n<h2>JETSKI, THE ROOM GOES QUIET</h2>\n<p><em>Hold one beat after Ray's line. The lounge is full. Eleven people. One dead man upstairs. No sirens yet.</em></p>\n<p><strong>JETSKI</strong> (PLAYER: quiet, not performing, genuinely unsettled; surfer bro mostly gone):</p>\n<blockquote>\n<p>You know what keeps turning in my head?<br />\n(beat)<br />\nWe keep asking who was in the OR. Who had the blade. Who was out in the storm.<br />\nBut whoever killed De Worsti didn't have to be out there.<br />\nThey could be right here. In this lounge. Listening. Helping us decide who to blame.<br />\n(quieter, to Pepper or the room)<br />\nThat's the part that's going to stay with me, man.</p>\n</blockquote>\n<p><em>Silence. </em><em>Curie</em><em> may offer a warm, dismissive line. </em><em>Ray</em><em> may tell him to focus. </em><em>Homes</em><em> may snap. Let it land, then move on.</em></p>\n<blockquote>\n<p><strong>CURIE:</strong> (optional, pleasant) Doctor, you're medicated and you're frightened. That's fair. Let's channel it into evidence.</p>\n<p><strong>RAY:</strong> (optional, gruff) Yeah. Fine. Now we work.</p>\n</blockquote>\n<h2>CHARACTER BEATS, ensure each player heard (host checklist)</h2>\n<table>\n<thead>\n<tr>\n<th>Character</th>\n<th>Must land in this scene</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td><strong>Homes</strong></td>\n<td>Primary suspect; scalpel; \"blade pulled from grip\"</td>\n</tr>\n<tr>\n<td><strong>Pepper</strong></td>\n<td>Witness; incapacitated first; torn about Homes</td>\n</tr>\n<tr>\n<td><strong>Jetski</strong></td>\n<td>Paralyzed pre blackout; not the cutter; surfer bro panic; <strong>killer among us</strong> beat delivered</td>\n</tr>\n<tr>\n<td><strong>Curie</strong></td>\n<td>Charm on; Ray endeared; Pepper ahem; Homes annoyed</td>\n</tr>\n<tr>\n<td><strong>Ray</strong></td>\n<td>Containment; no police; admits own debt</td>\n</tr>\n<tr>\n<td><strong>Marz</strong></td>\n<td>Junior badge; wild theory optional; Melody/Vance triangle beat</td>\n</tr>\n<tr>\n<td><strong>Lacey</strong></td>\n<td>Director distance; crisis lock invoked</td>\n</tr>\n<tr>\n<td><strong>Melody</strong></td>\n<td>Called code; hints missing log / cameras</td>\n</tr>\n<tr>\n<td><strong>Vance</strong></td>\n<td>Server room; logs; <strong>Sachs glance</strong>; wife hunt foreshadow</td>\n</tr>\n<tr>\n<td><strong>Sachs</strong></td>\n<td>German accent; street presence; points at Homes; implies Vance is her coerced asset</td>\n</tr>\n<tr>\n<td><strong>Alfie</strong></td>\n<td>Brother; delivery cover; inflammatory; watches who flinches</td>\n</tr>\n</tbody>\n</table>\n<h2>LIVE QUESTIONING (10 to 20 minutes)</h2>\n<p><em>After scripted scene, open the floor. Ray and Curie take turns.</em></p>\n<p><strong>Ray questions (suggested prompts):</strong>\n- Homes: <em>\"Who else had attending privileges on VIP tonight?\"</em>\n- Sachs / Alfie: <em>\"What were you really here for?\"</em>\n- Vance: <em>\"What's missing from the cameras?\"</em>\n- Melody: <em>\"Who did you see in the hall in the hour before surgery?\"</em>\n- Lacey: <em>\"Whose code opened the pharmacy vault?\"</em> (she deflects; may use Administrative Override later)</p>\n<p><strong>Curie questions (credibility, not obstruction):</strong>\n- <em>\"Let's focus on who had hands on metal in the OR, blade contact first.\"</em>\n- If Ray investigates Lacey: <em>\"Unlikely she'd personally make that cut, but her access tier is still a lead. Run it.\"</em>\n- Never tell Ray <strong>not</strong> to investigate her background.</p>\n<p><strong>Player goal this segment:</strong> defend themselves, trade secrets, notice Ray is compromised, and <strong>everyone but Homes</strong> is leaning Curie's way.</p>\n<p><strong>Host:</strong> Drop one Ray/Curie spark + Pepper throat clear per act max. See <strong>13-curie charm playbook.md</strong>.</p>\n<p><strong>Do not distribute major evidence cards yet</strong>, save E1-A/B/C for OR search in 06-act2-crime scene.md.</p>\n<h2>NARRATOR, TRANSITION OUT</h2>\n<blockquote>\n<p>The lounge emptied in fragments, no one calm, no one innocent in the eyes of the room.<br />\nDr. Homes left under Ray's gaze like a man already in cuffs.<br />\nDr. Curie touched his shoulder in the corridor, a colleague's sympathy that looked perfect on camera that didn't exist.<br />\nThe storm kept screaming. The sirens were still miles away.<br />\nAnd somewhere between the pharmacy vault and the admin terminal, the truth was already written in codes and overrides the room had not opened yet.</p>\n</blockquote>\n<p><em>Cut to live play → </em><em>06-act2-crime scene.md</em><em> (OR forensics + wing search)</em></p>\n<h2>HOST NOTES</h2>\n<ul>\n<li>This scene <strong>centralizes the cast</strong> before anyone scatters, every player has heard the charge and the lockdown rules.  </li>\n<li><strong>Homes must feel the room turn on him</strong>, Sachs, Ray, Curie, and default logic all point his way. Pepper's doubt is the seed for later doubt.  </li>\n<li><strong>Curie's warmth toward Homes in the corridor</strong> (optional stage direction) foreshadows how cleanly Ray framed him.  </li>\n<li>If players try to leave: Ray blocks door, <em>\"Protocol Delta. Sit.\"</em>  </li>\n<li>Lacey invoking counsel then losing to Ray establishes power struggle early.  </li>\n<li>Melody's unfinished <em>\"including, \"</em> plants Alfie without full reveal.</li>\n</ul>", "11-genevieve-backstory": "<h1>Genevieve → Lacey Lovely, Backstory (Facilitator)</h1>\n<p><strong>De Worsti's first wife was Genevieve.</strong> She is now <strong>Lacey Lovely</strong>, hospital director, after total facial reconstruction and legal name change. <strong>Officer Ray is an old friend and protector</strong> who knows who she used to be. Only a handful of people in the building can connect the identities tonight.</p>\n<h2>Who Genevieve was</h2>\n<p>Genevieve grew up in the regional youth sanctuary alongside <strong>Dr. Curie</strong>, arm in arm in the orphanage photo (E2-D). She was bright, guarded, and allergic to authority figures who promised safety and delivered control.</p>\n<p>Before De Worsti, she had already learned not to rely on rescue. Ray became one of the few old connections she trusted, and three years ago he finally understood what De Worsti had turned her life into.</p>\n<p>As a young woman she married <strong>De Worsti</strong> before his empire fully hardened into what Lesbian City underground papers would later call a <strong>loan shark and enforcement network</strong>, protection rackets, predatory lending, debt collectors like <strong>Uvula Sachs</strong>, and violence dressed up as family loyalty.</p>\n<h2>Life under the crime lord</h2>\n<p>De Worsti did not merely cheat or shout. He <strong>ran Genevieve's life as property.</strong></p>\n<table>\n<thead>\n<tr>\n<th>Abuse</th>\n<th>Detail (facilitator truth)</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td><strong>Isolation</strong></td>\n<td>Moved her between apartments; cut her off from sanctuary friends; monitored calls</td>\n</tr>\n<tr>\n<td><strong>Financial erasure</strong></td>\n<td>Every account in his name; she had pocket money, not autonomy</td>\n</tr>\n<tr>\n<td><strong>Physical violence</strong></td>\n<td>Beatings when she questioned deals or flinched from his \"business guests\"; old bruises like the one on De Worsti's wrist in prologue, she wore them first</td>\n</tr>\n<tr>\n<td><strong>Sexual coercion</strong></td>\n<td>Implied in newspaper clipping (redacted); Alfie can testify she \"stopped flinching in public and started flinching alone\"</td>\n</tr>\n<tr>\n<td><strong>Punishment escalations</strong></td>\n<td>After she helped herself to cash from a locked ledger, De Worsti burned <strong>Curie's family home</strong> to teach her what running costs</td>\n</tr>\n<tr>\n<td><strong>Hunt</strong></td>\n<td>When she vanished with stolen millions, De Worsti hired P.I.s, searched facial reconstruction clinics, and used hospital access whenever medicine gave him cover</td>\n</tr>\n</tbody>\n</table>\n<p>Genevieve did not stumble into a new life. She <strong>bought one with blood money and surgery</strong>, new face, new name (<strong>Lacey Lovely</strong>), flagship hospital post in Lesbian City where De Worsti would never think to look.</p>\n<h2>Why Ray acted tonight</h2>\n<p>For years Lacey believed the new face and title kept her safe. <strong>Ray</strong> found her three years ago, took the security chief post, and swore revenge on Alex.</p>\n<p>Then <strong>subtle warnings</strong> turned into a pattern:</p>\n<table>\n<thead>\n<tr>\n<th>Warning sign</th>\n<th>What Lacey / Ray read it as</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td><strong>Uvula Sachs</strong> on VIP perimeter</td>\n<td>Enforcer muscle, De Worsti's network, not random street noise</td>\n</tr>\n<tr>\n<td>Collection faces in parking / loading</td>\n<td>Same Indigo District posture Sachs trained</td>\n</tr>\n<tr>\n<td><strong>Vance</strong> reporting odd database sweeps</td>\n<td>Wife hunt accelerating toward admin tier</td>\n</tr>\n<tr>\n<td>VIP intake with sparse records + bought priority</td>\n<td>De Worsti's signature, even before names matched</td>\n</tr>\n<tr>\n<td>Storm week chaos</td>\n<td>Cover for people who already lived in chaos</td>\n</tr>\n</tbody>\n</table>\n<p><strong>Ray</strong> confirmed the worst when De Worsti's <strong>real surgical booking</strong> landed: VIP arterial repair, compromised vessel, <strong>legitimate medical need</strong>. De Worsti was not faking illness to sneak in. He was dying slowly enough to shop for a stage.</p>\n<p>His play was psychological: book at <strong>her</strong> hospital, let department heads fuss over him, assume she would freeze. <strong>Homes</strong> refused the theater (meritocrat, insulted by wallet ethics). <strong>Curie</strong> refused the theater (sanctuary bond, saw the trap). Ray decided Alex would not walk out.</p>\n<p>Ray did not chase him through the wing. <strong>Sachs</strong> was on perimeter, cameras were still mostly live, and a VIP financier killed anywhere except the table would lead straight to the badge that escorted him in. Alex's real case was the trap Alex built for himself: one window where he'd be sedated, staff could be chemically frozen, lights could die on Ray's schedule, and a violent scalpel wound would read as rage in the theater, not murder by security. Alex wanted to own Lacey's OR; Ray finished him on the table Alex chose, dressed the death as medical chaos, and walked out still running the room.</p>\n<p><strong>Facilitator line:</strong> De Worsti's surgery was real. His arrogance was real. Lacey's fear was real. Ray's cut was still murder.</p>\n<h2>Who knows what (before Alfie's reveal)</h2>\n<table>\n<thead>\n<tr>\n<th>Character</th>\n<th>Knowledge</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td><strong>Lacey</strong></td>\n<td>Full abuse history; knows Ray hates De Worsti and watches out for her; does not know Ray killed tonight</td>\n</tr>\n<tr>\n<td><strong>Ray</strong></td>\n<td>Full truth; killer protecting a friend</td>\n</tr>\n<tr>\n<td><strong>Curie</strong></td>\n<td>Abuse history; wanted De Worsti dead; did not kill</td>\n</tr>\n<tr>\n<td><strong>De Worsti</strong></td>\n<td>Knew she was somewhere in the medical world; died before confirming</td>\n</tr>\n<tr>\n<td><strong>Alfie</strong></td>\n<td><strong>Full family truth</strong>, legal papers, old photos, abuse he witnessed; must reveal in Ep 4</td>\n</tr>\n<tr>\n<td><strong>Melody</strong></td>\n<td>Archival intake photos; recognizes pre surgery face; corroborates after Alfie names Genevieve</td>\n</tr>\n<tr>\n<td><strong>Pepper</strong></td>\n<td>Thought De Worsti was legally married to someone absent; did not know Lacey</td>\n</tr>\n<tr>\n<td><strong>CD Vance</strong></td>\n<td>Sachs forced him to hunt the wife digitally, clinic flags, admin trails; raw logs may show Ray in OR</td>\n</tr>\n<tr>\n<td><strong>Sachs</strong></td>\n<td>Ordered the hunt for money, not mercy; threatened Vance</td>\n</tr>\n<tr>\n<td><strong>Everyone else</strong></td>\n<td>P.I. dossier (E1-C) hints ex wife + reconstruction, no name</td>\n</tr>\n</tbody>\n</table>\n<h2>Alfie's reveal, mandatory beat (Episode 4)</h2>\n<p><strong>Alfie is the only player obligated to put the name Genevieve on the table</strong>, but he speaks with <strong>hedged, uncertain language</strong> (<em>I think, as far as I know, I'm not saying she…</em>) ,  partly camouflage, partly the one subject that punches through his baiter mask. He partially wants <strong>nothing bad to happen to Lacey</strong>; he tells the truth about De Worsti's abuse without fully damning her for tonight.</p>\n<ul>\n<li><strong>When:</strong> Act 4 / Episode 4, before final ballot  </li>\n<li><strong>Script:</strong> see <strong>05-episode scripts.md</strong> → <em>Alfie Reveals Genevieve</em>  </li>\n<li><strong>Lacey responds:</strong> admits she ran and rebuilt her life; <strong>denies murder</strong>, <em>never hated him enough to kill; only wanted distance</em> (<strong>truthful</strong>)  </li>\n<li><strong>Curie:</strong> does <strong>not</strong> oppose Ray's investigation; offers authoritative opinion that he did not make the cut; sanctuary bond makes him look guilty anyway  </li>\n<li><strong>Melody corroborates:</strong> archival face match, firmer than Alfie, after he speaks  </li>\n<li><strong>Moral weight:</strong> Room understands De Worsti was <strong>a bigger monster than his killer</strong>, and the killer is still guilty  </li>\n</ul>\n<h2>Newspaper clippings (player text)</h2>\n<p>Full printable copy: <strong><a href=\"15-evidence-materials.md\">15-evidence-materials.md</a></strong> → <strong>E4-F</strong> (Genevieve missing) and <strong>E4-H</strong> (sanctuary fire, De Worsti not named).</p>\n<p>Players connect <strong>G.A. = Genevieve De Worsti</strong> only after Alfie's reveal.</p>", "12-de-worsti-revelation-arc": "<h1>De Worsti Revelation Arc, Bigger Monster Than His Murderers</h1>\n<p><strong>Design intent:</strong> The room starts thinking <em>someone murdered a VIP patient.</em> By Episode 4 they understand <em>a crime lord was executed</em>, and De Worsti was worse than the person who killed him.</p>\n<p>The killer (Ray) is guilty, calculated, and sympathetic. <strong>De Worsti is not sympathetic.</strong> Each episode adds a layer until the moral ballot is genuinely hard.</p>\n<h2>Episode by episode reveal</h2>\n<table>\n<thead>\n<tr>\n<th>Episode</th>\n<th>What the room learns about De Worsti</th>\n<th>Source</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td><strong>Ep 1</strong></td>\n<td>Controlling, wealthy, treats the hospital as his property; old bruise on wrist (he gives violence, doesn't only receive)</td>\n<td>Prologue, Gathering</td>\n</tr>\n<tr>\n<td><strong>Ep 1</strong></td>\n<td><strong>Real</strong> VIP arterial case, not a fake illness cover; booked at Lacey's hospital as power play; Homes and Curie refuse to orbit him</td>\n<td>Prologue, OR script</td>\n</tr>\n<tr>\n<td><strong>Ep 1</strong></td>\n<td>Half the wing owed him money or feared him; Sachs on perimeter; P.I. hunting vanished ex wife</td>\n<td>E1-C dossier, Ray's debt admission, gathering</td>\n</tr>\n<tr>\n<td><strong>Ep 2</strong></td>\n<td>Someone engineered his death like a procedure, he was hunted, not unlucky</td>\n<td>Toxicology, coordination evidence</td>\n</tr>\n<tr>\n<td><strong>Ep 2</strong></td>\n<td><strong>Vance was forced by Sachs</strong> to dig through systems for De Worsti's wife, clinic lists, reconstruction leads, hospital admin trails</td>\n<td>E2-F Vance search logs</td>\n</tr>\n<tr>\n<td><strong>Ep 3</strong></td>\n<td>Sachs, Alfie, and others came to hurt or kill him tonight; De Worsti collected enemies faster than allies</td>\n<td>Knives, wire cutters, Melody attack context</td>\n</tr>\n<tr>\n<td><strong>Ep 4</strong></td>\n<td><strong>Genevieve's abuse</strong>, isolation, beatings, fire as punishment, repossession mindset</td>\n<td>Alfie reveal, E4-F newspaper</td>\n</tr>\n<tr>\n<td><strong>Ep 4</strong></td>\n<td>De Worsti chose Lacey's hospital for real surgery + hunt; Pepper learns she was sleeping with a man who torched families and hunted ex wives</td>\n<td>Alfie + Pepper reaction beat</td>\n</tr>\n<tr>\n<td><strong>Ep 4 ballot</strong></td>\n<td>Killer broke the law. Victim broke people. Room chooses: punishment, justice, or system exposure</td>\n<td>Ethical verdict</td>\n</tr>\n</tbody>\n</table>\n<h2>The comparison (facilitator framing)</h2>\n<table>\n<thead>\n<tr>\n<th></th>\n<th>Officer Ray</th>\n<th>De Worsti</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td><strong>Violence</strong></td>\n<td>One violent scalpel kill; cover up; attack on Melody to silence</td>\n<td>Years of domestic torture; arson murder; debt slavery across the city</td>\n</tr>\n<tr>\n<td><strong>Target</strong></td>\n<td>De Worsti, hunter who would not stop; protect Lacey</td>\n<td>Genevieve, Curie's family, Ray's mother &amp; sister, countless debtors</td>\n</tr>\n<tr>\n<td><strong>Scale</strong></td>\n<td>One night, one wing</td>\n<td>Empire built on fear</td>\n</tr>\n<tr>\n<td><strong>Room question</strong></td>\n<td><em>Did he murder?</em></td>\n<td><em>Was he the real monster in the building?</em></td>\n</tr>\n</tbody>\n</table>\n<p><strong>Neither answer erases the other.</strong> That's the thriller.</p>\n<h2>CD Vance + Sachs, wife investigation (coerced alliance)</h2>\n<p><strong>Sachs threatened Vance</strong> (elevator shaft, T−2h) to use contractor access and trace <strong>De Worsti's runaway wife</strong>, not for justice for Genevieve, but because Sachs believed the stolen millions were in her hands.</p>\n<table>\n<thead>\n<tr>\n<th>Vance did for Sachs</th>\n<th>Detail</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td>Clinic database sweeps</td>\n<td>Facial reconstruction intake flags in Lesbian City metro</td>\n</tr>\n<tr>\n<td>Hospital cross reference</td>\n<td>Admin access patterns, VIP wing anomalies</td>\n</tr>\n<tr>\n<td>Partial match</td>\n<td>Trails pointing toward St. Saphicca's admin tier, <strong>before</strong> Vance understood Lacey</td>\n</tr>\n</tbody>\n</table>\n<p><strong>Vance is terrified of Sachs</strong> and still feeding him scraps when he can. He is <strong>not</strong> loyal, he is leased.</p>\n<p><strong>Reveal timing:</strong>\n- <strong>Ep 2</strong>, Vance cracks under Ray; admits Sachs made him hunt the wife digitally<br />\n- <strong>Ep 4</strong>, After Alfie names Genevieve, Vance can connect raw mainframe to <strong>Curie's keycard</strong> in OR during blackout ,  Curie was elsewhere; Ray has no OR access</p>\n<p>Lacey's separate pressure (containment, crisis) and Ray's log manipulation make Vance a person crushed between <strong>two</strong> monsters, Sachs and Ray, while De Worsti was the reason any of it started.</p>\n<h2>Suggested player beats</h2>\n<p><strong>Pepper (Ep 4, after Alfie):</strong> Optional host prompt, affair grief collides with abuse testimony; she must sit with loving a man worse than his killer.</p>\n<p><strong>Curie (Ep 4):</strong> <em>\"I wanted him dead. I did not make that cut.\"</em></p>\n<p><strong>Ray (Ep 4, if accused correctly):</strong> <em>\"I've hated men like him my whole career. That doesn't give me a license. It gave my friend a chance.\"</em></p>\n<p><strong>Sachs (Ep 3 to 4):</strong> Not innocent, hunted Genevieve for money, not mercy. Vance's helper, not Vance's friend.</p>\n<p><strong>Jetski (gathering):</strong> Killer in the lounge; De Worsti's shadow was why the table existed.</p>", "13-curie-charm-playbook": "<h1>Curie's Charm, Red Herring Playbook (Facilitator)</h1>\n<p><strong>Dr. Curie is Prince Charming who looks like the killer.</strong> Idealist, kind-hearted social butterfly with <strong>annoying charisma</strong> ,  the wing's angel's advocate, always finding the bright side. Assumes the best in people, including Ray. His niceness is <strong>genuine, not a red-herring performance</strong>; that sincerity reads suspicious in a murder wing anyway. Traumatized (Genevieve, the fire), <strong>never let it show.</strong> Play the lovable leading man: serious when required, shuts down flirt with polished deflection, then back to devastating competence.</p>\n<p><strong>Officer Ray is the real killer.</strong> Curie's charm makes the room chase the wrong surgeon while Ray runs the investigation.</p>\n<h2>Who reacts how</h2>\n<table>\n<thead>\n<tr>\n<th>Character</th>\n<th>Reaction to Curie</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td><strong>Officer Ray</strong></td>\n<td>Likes Curie's competence; banter reads easy and professional; uses Curie as cover</td>\n</tr>\n<tr>\n<td><strong>Nurse Pepper</strong></td>\n<td><strong>Comedic timing</strong>, clears throat when Ray and Curie crowd each other; eye roll the room can see</td>\n</tr>\n<tr>\n<td><strong>Most players</strong></td>\n<td>Admire wit; want him on their side of the investigation</td>\n</tr>\n<tr>\n<td><strong>Dr. Homes</strong></td>\n<td><strong>Professional rival</strong> ,  openly annoyed; hates angel's-advocate speeches; merit vs charm</td>\n</tr>\n</tbody>\n</table>\n<h2>Why Curie looks guilty (host cues)</h2>\n<ol>\n<li><strong>Sanctuary bond</strong> with Genevieve / Lacey (orphanage photo, E2-D)  </li>\n<li><strong>Surgical skill</strong> signature on the wound (E4-E red herring)  </li>\n<li><strong>Motive</strong> everyone can name: fire, failed rescue, De Worsti in his hospital  </li>\n<li><strong>Partnership with Ray</strong> reads like two investigators, not killer + cover  </li>\n<li><strong>Homes's irritation</strong> (rival dynamic) makes Curie look like the room's favorite answer  </li>\n<li><strong>Genuine niceness</strong> ,  not performed innocence; optimism in a corpse wing reads wrong on accident  </li>\n<li><strong>OR keycard in the log</strong> names Curie's badge ,  he has too many corridor friends to say who lifted it; truth lands when evidence surfaces (torn page, mainframe, Melody), not when Curie turns paranoid</li>\n</ol>\n<h2>Curie's toolkit (repeat every episode)</h2>\n<ol>\n<li><strong>Credit Ray publicly</strong>, makes Ray feel partnered, not competed with  </li>\n<li><strong>Praise others' contributions</strong>, then steer (\"Good catch, which means we should look at X, not Y\")  </li>\n<li><strong>Deflect with charm</strong>, <em>\"Officer, save the compliments, we have a corpse.\"</em> Smile. Back to work.  </li>\n<li><strong>Serious when needed</strong>, no jokes during toxicology or Melody attack; charm returns after  </li>\n<li><strong>Never block Ray</strong>, but if Ray's keycard surfaces, Curie may be the first to say <em>run it</em>  </li>\n</ol>\n<h2>Pepper's throat clear (host cue)</h2>\n<p>Use <strong>three times max</strong> per game so it stays funny:</p>\n<table>\n<thead>\n<tr>\n<th>When</th>\n<th>Example</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td>Gathering</td>\n<td>Ray and Curie lean over the same clue at the table</td>\n</tr>\n<tr>\n<td>Episode 2</td>\n<td>Curie straightens a file in Ray's hand after \"run it\"</td>\n</tr>\n<tr>\n<td>Episode 4</td>\n<td>Curie and Ray share a quiet beat after \"don't drop it on my account\"</td>\n</tr>\n</tbody>\n</table>\n<p><strong>PEPPER:</strong> <em>(sharp ahem)</em><br />\nRoom laughs or tenses. Curie doesn't break character. Homes <strong>scowls</strong>.</p>\n<h2>Homes' irritation (sample lines)</h2>\n<blockquote>\n<p><strong>HOMES:</strong> Could we investigate the murder instead of auditioning for a municipal calendar?<br />\n<strong>CURIE:</strong> <em>(pleasant)</em> Doctor, when you have an alibi, I'll schedule around your preferences.<br />\n<strong>HOMES:</strong> He always does this ,  finds the bright side for whoever we're about to cuff.<br />\n<strong>CURIE:</strong> <em>(sincere, not performing)</em> Because sometimes we're wrong, Doctor. That's why we investigate.<br />\n<strong>RAY:</strong> <em>(almost amused)</em> Keep talking, Homes.</p>\n</blockquote>\n<h2>Design intent</h2>\n<ul>\n<li>Ray's cover is <strong>authority</strong>, not stupidity; Curie is the face the room wants to trust  </li>\n<li>Pepper's ahem is pressure valve for player stress  </li>\n<li>Homes' annoyance makes him look guilty when he's actually the <strong>first suspect who must defend himself</strong>  </li>\n<li>Jetski gathering beat lands harder later: <em>they trusted whoever sounded most confident</em> (see 10-the-gathering.md)</li>\n</ul>", "readme": "<h1>The Cure: Live Action Medical Thriller</h1>\n<p><strong>Host reference pack</strong>, facilitator only. Do not distribute to players.</p>\n<table>\n<thead>\n<tr>\n<th>File</th>\n<th>Purpose</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td><a href=\"00-host-blueprint.md\">00-host-blueprint.md</a></td>\n<td>Truth, murder plan, episode flow, endings</td>\n</tr>\n<tr>\n<td><a href=\"01-character-roster.md\">01-character-roster.md</a></td>\n<td>Player booklets summary, abilities, objectives</td>\n</tr>\n<tr>\n<td><a href=\"02-character-timelines.md\">02-character-timelines.md</a></td>\n<td>Minute by minute whereabouts (night of murder)</td>\n</tr>\n<tr>\n<td><a href=\"03-motivations-alliances.md\">03-motivations-alliances.md</a></td>\n<td>Motives, secrets, faction politics</td>\n</tr>\n<tr>\n<td><a href=\"04-evidence-index.md\">04-evidence-index.md</a></td>\n<td>Every clue card, prop, and when it drops</td>\n</tr>\n<tr>\n<td><a href=\"15-evidence-materials.md\">15-evidence-materials.md</a></td>\n<td><strong>Player readable evidence text + props print list</strong></td>\n</tr>\n<tr>\n<td><a href=\"05-episode-scripts.md\">05-episode-scripts.md</a></td>\n<td>Cutscenes, prologue, narrator beats</td>\n</tr>\n<tr>\n<td><a href=\"06-act2-crime-scene.md\">06-act2-crime-scene.md</a></td>\n<td>Live investigation opener, police handoff, crime scene</td>\n</tr>\n<tr>\n<td><a href=\"09-storm-containment-logic.md\">09-storm-containment-logic.md</a></td>\n<td><strong>Why no police / why suspects investigate / Ray's conflict</strong></td>\n</tr>\n<tr>\n<td><a href=\"10-the-gathering.md\">10-the-gathering.md</a></td>\n<td><strong>Central cast briefing, Ray + Marz + Curie, all eleven players, Homes accused</strong></td>\n</tr>\n<tr>\n<td><a href=\"11-genevieve-backstory.md\">11-genevieve-backstory.md</a></td>\n<td><strong>Genevieve / Lacey abuse history; Alfie reveal beat</strong></td>\n</tr>\n<tr>\n<td><a href=\"12-de-worsti-revelation-arc.md\">12-de-worsti-revelation-arc.md</a></td>\n<td><strong>De Worsti worse than killers, episode reveal map; Vance + Sachs</strong></td>\n</tr>\n<tr>\n<td><a href=\"13-curie-charm-playbook.md\">13-curie-charm-playbook.md</a></td>\n<td><strong>Curie red herring; Ray flirt tension; Pepper ahem; Homes annoyed</strong></td>\n</tr>\n<tr>\n<td><a href=\"14-actor-personas.md\">14-actor-personas.md</a></td>\n<td><strong>Exaggerated actor personas, all 11 players</strong></td>\n</tr>\n<tr>\n<td><a href=\"17-officer-diamond.md\">17-officer-diamond.md</a></td>\n<td><strong>Optional 12th player: Officer Diamond beat guide + dossier link</strong></td>\n</tr>\n<tr>\n<td><a href=\"player-dossiers/\">player-dossiers/</a></td>\n<td><strong>Printable player character dossiers (1 per actor)</strong></td>\n</tr>\n<tr>\n<td><a href=\"player-performance-script.md\">player-performance-script.md</a></td>\n<td><strong>Player script only</strong> (no host notes; act by act)</td>\n</tr>\n<tr>\n<td>Game launcher canvas</td>\n<td><strong>Players:</strong> pick character, open dossier and script. <strong>Open live canvas:</strong> Ctrl+Shift+P → <strong>Open Canvas</strong>, or click <a href=\"file:///C:/Users/daisycheung/.cursor/projects/c-projects-the-cure/canvases/the-cure-game-launcher.canvas.tsx\">the-cure-game-launcher.canvas.tsx</a></td>\n</tr>\n<tr>\n<td>Host reference canvas</td>\n<td><strong>Facilitator only:</strong> full spoiler pack. <a href=\"file:///C:/Users/daisycheung/.cursor/projects/c-projects-the-cure/canvases/the-cure-host-reference.canvas.tsx\">the-cure-host-reference.canvas.tsx</a></td>\n</tr>\n<tr>\n<td><a href=\"player-pack/index.html\">Player pack (HTML)</a></td>\n<td><strong>Share to phones/tablets:</strong> zip <code>player-pack/</code> folder, open <code>index.html</code></td>\n</tr>\n</tbody>\n</table>\n<p><strong>Setting:</strong> VIP Wing &amp; Operating Theater, St. Saphicca's Progressive Care, Lesbian City<br />\n<strong>Runtime:</strong> 3 to 4 hours | <strong>Players:</strong> 11<br />\n<strong>Core question:</strong> Was this murder… or justice?</p>\n<h2>Style (for future edits)</h2>\n<ul>\n<li><strong>No em dashes</strong> (<code>,</code>). Use commas, periods, colons, or parentheses instead.</li>\n<li><strong>Interrupted dialogue:</strong> ellipses (<code>...</code>), not em dashes.</li>\n<li><strong>Ranges</strong> (episodes, runtime): en dash (<code>3 to 4 hours</code>) or plain words (<code>Ep 1 to 3</code>) are fine.</li>\n<li><strong>Compound modifiers:</strong> prefer spaces (<code>pre op</code>, <code>night vision</code>) unless the term is a proper name or code.</li>\n<li><strong>Sentence flow:</strong> combine choppy fragments in dossiers and host docs; reserve short beats for scripted dialogue and stage panic.</li>\n</ul>", "17-officer-diamond": "<h1>Officer Diamond, Beat Guide (Host + Player)</h1>\n<p><strong>Player dossier:</strong> <a href=\"player-dossiers/11-officer-diamond.md\">player-dossiers/11-officer-diamond.md</a><br />\n<strong>Persona:</strong> <a href=\"14-actor-personas.md\">14-actor-personas.md</a> → Officer Diamond</p>\n<p>Diamond is a <strong>full player</strong> with dossier and pack access. She supports perimeter and escort while staying in play for the whole night.</p>\n<h2>Role in the fiction</h2>\n<table>\n<thead>\n<tr>\n<th></th>\n<th></th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td><strong>Title</strong></td>\n<td>Auxiliary containment officer, St. Saphicca's Security</td>\n</tr>\n<tr>\n<td><strong>Why she's here</strong></td>\n<td>Storm overflow; main campus security desk routed her to the VIP wing after the code dropped</td>\n</tr>\n<tr>\n<td><strong>Chain of command</strong></td>\n<td>Junior to <strong>Officer Marz</strong>; Ray is chief; Diamond narrates it like a training module anyway</td>\n</tr>\n<tr>\n<td><strong>Night of murder</strong></td>\n<td>Main campus desk, then en route when De Worsti died; <strong>no OR access</strong>, <strong>not a suspect</strong></td>\n</tr>\n</tbody>\n</table>\n<h2>What she does on stage</h2>\n<table>\n<thead>\n<tr>\n<th>Do</th>\n<th>Don't</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td>Gamify corridor patrol, door checks, phases</td>\n<td>Steal Ray or Marz's authority</td>\n</tr>\n<tr>\n<td>Drop one sharp observation per act, report to Ray</td>\n<td>Hand out clues or read evidence cards</td>\n</tr>\n<tr>\n<td>Escort players to assigned rooms (Act 2)</td>\n<td>Run accusations or a vote</td>\n</tr>\n<tr>\n<td>React to storm beats with fake cheer</td>\n<td>Confess to murder you did not commit</td>\n</tr>\n<tr>\n<td>Use optional script lines when facilitator calls her in</td>\n<td>Hand out evidence</td>\n</tr>\n</tbody>\n</table>\n<h2>When to enter</h2>\n<ol>\n<li><strong>End of Act 1</strong> (after The Gathering): Ray radios overflow; Diamond arrives at the lounge door. See <a href=\"player-performance-script.md\">player-performance-script.md</a>.</li>\n<li><strong>Act 2 evidence search:</strong> Escort pairs; assign \"Phase Three: Controlled Chaos.\"</li>\n<li><strong>Between acts:</strong> Radio check with Marz; credibility points joke; exit.</li>\n</ol>\n<h2>Host reminders</h2>\n<ul>\n<li>Ray and Marz remain the investigation leads; see <a href=\"09-storm-containment-logic.md\">09-storm-containment-logic.md</a>.</li>\n<li>If players ask why they have not seen her before: overflow call, storm night, main campus until the code.</li>\n<li>Diamond notices odd behavior and <strong>reports to Ray</strong>; Ray decides what the room hears.</li>\n<li>No ballot, no killer reveal. Optional character if uncast, but if cast she gets the full player pack like everyone else.</li>\n</ul>", "dossiers-readme": "<h1>Player Dossiers, The Cure</h1>\n<p>Print <strong>one dossier per player</strong>. Dossiers are <strong>private</strong>, do not show other players.<br />\nFormat: <strong>labeled sections</strong> (Look, Vibe, Where, Goal, etc.) with content on the next line. <strong>Likes</strong>, <strong>Dislikes</strong>, <strong>History</strong>, and <strong>Plan</strong> use bullet lists (blank line after the label, then <code>-</code> items). <strong>Rules</strong> and <strong>Night Truth</strong> keep bullets where needed. No inline bold on names or keywords in body text.</p>\n<p><strong>Punctuation:</strong> No em dashes; use commas, colons, or ellipses for cuts in speech.</p>\n<p><strong>Prose:</strong> Prefer flowing sentences over staccato fragments. Combine related ideas with commas, <em>so</em>, <em>because</em>, or <em>and</em> instead of stacking three-line punches.</p>\n<p>Also print <strong><a href=\"../player-performance-script.md\">player-performance-script.md</a></strong> (one copy for the table, or one per player). Players only read the act they are in.</p>\n<table>\n<thead>\n<tr>\n<th>File</th>\n<th>Character</th>\n<th>Role</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td><a href=\"00-alex-austin.md\">00-alex-austin.md</a></td>\n<td>Alex Austin <em>(De Worsti)</em></td>\n<td>Victim / prologue only (not one of the eleven)</td>\n</tr>\n<tr>\n<td><a href=\"01-dr-curie.md\">01-dr-curie.md</a></td>\n<td>Dr. Curie</td>\n<td>Obvious red herring</td>\n</tr>\n<tr>\n<td><a href=\"02-officer-ray.md\">02-officer-ray.md</a></td>\n<td>Officer Ray</td>\n<td>Killer / security chief</td>\n</tr>\n<tr>\n<td><a href=\"03-nurse-pepper.md\">03-nurse-pepper.md</a></td>\n<td>Nurse Pepper</td>\n<td>Witness + logbook gatekeeper</td>\n</tr>\n<tr>\n<td><a href=\"04-dr-homes.md\">04-dr-homes.md</a></td>\n<td>Dr. Homes</td>\n<td>Framed surgeon / first suspect</td>\n</tr>\n<tr>\n<td><a href=\"05-lacey-lovely.md\">05-lacey-lovely.md</a></td>\n<td>Lacey Lovely</td>\n<td>Ray's friend; hunted by De Worsti</td>\n</tr>\n<tr>\n<td><a href=\"06-dr-jetski.md\">06-dr-jetski.md</a></td>\n<td>Dr. Jetski</td>\n<td>Anesthesiologist</td>\n</tr>\n<tr>\n<td><a href=\"07-uvula-sachs.md\">07-uvula-sachs.md</a></td>\n<td>Uvula Sachs</td>\n<td>Enforcer (red herring)</td>\n</tr>\n<tr>\n<td><a href=\"08-alfie-de-worsti.md\">08-alfie-de-worsti.md</a></td>\n<td>Alfie De Worsti</td>\n<td>De Worsti's brother</td>\n</tr>\n<tr>\n<td><a href=\"09-melody.md\">09-melody.md</a></td>\n<td>Melody</td>\n<td>Night receptionist</td>\n</tr>\n<tr>\n<td><a href=\"10-cd-vance.md\">10-cd-vance.md</a></td>\n<td>CD Vance</td>\n<td>IT contractor</td>\n</tr>\n<tr>\n<td><a href=\"11-officer-diamond.md\">11-officer-diamond.md</a></td>\n<td>Officer Diamond</td>\n<td>Auxiliary containment / overflow</td>\n</tr>\n<tr>\n<td><a href=\"12-officer-marz.md\">12-officer-marz.md</a></td>\n<td>Officer Marlowe \"Marz\"</td>\n<td>Junior security / investigator</td>\n</tr>\n</tbody>\n</table>\n<p><strong>Ray</strong> dossier includes a sealed <strong>NIGHT TRUTH</strong> section at the bottom, fold or staple closed before handing out.</p>"}};
